def _mask_secret(value):
    text = str(value or '').strip()
    if not text:
        return 'not configured'
    return '********'


def _telegram_identity_scan_snapshot():
    project_root = Path(__file__).resolve().parent
    patterns = {
        'old_username': re.compile(r'wildberries_andrey_ai_bot', re.IGNORECASE),
        'old_brand': re.compile(r'Wildberries AI Agent|WB AI Agent', re.IGNORECASE),
        'old_atlas': re.compile(r'ATLAS'),
    }
    active_refs = []
    ignored_refs = []
    for path in project_root.rglob('*'):
        if not path.is_file():
            continue
        relative = path.relative_to(project_root)
        suffix = ''.join(path.suffixes).lower()
        if suffix in ('.pyc', '.png', '.jpg', '.jpeg', '.gif', '.zip', '.xlsx'):
            continue
        relative_text = str(relative).replace('\\', '/')
        try:
            text = path.read_text(encoding='utf-8')
        except Exception:
            continue
        lines = text.splitlines()
        lowered_relative = relative_text.lower()
        is_archive = any(token in lowered_relative for token in ('/archive/', '/tmp/', '.bak', 'backup', 'recovered'))
        is_test_guard = lowered_relative.startswith('tests/')
        for idx, line in enumerate(lines, start=1):
            for label, pattern in patterns.items():
                if not pattern.search(line):
                    continue
                if 're.compile(' in line:
                    continue
                if label == 'old_atlas' and ('_ATLAS_' in line or '_atlas_' in line):
                    continue
                item = {
                    'file': relative_text,
                    'line': idx,
                    'type': label,
                    'text': line.strip(),
                }
                if is_archive or is_test_guard:
                    ignored_refs.append(item)
                else:
                    active_refs.append(item)
    return {
        'active_references': active_refs,
        'ignored_archive_references': ignored_refs,
        'old_bot_references_found': bool(active_refs),
        'status': 'WARNING' if active_refs else 'OK',
    }


def _telegram_config_identity_snapshot():
    configured_token = str(BOT_TOKEN or '').strip()
    configured_username = str(BOT_USERNAME or '').strip()
    token_present = bool(configured_token)
    token_source = 'environment variable BOT_TOKEN' if token_present else 'not configured'
    username_is_set = bool(configured_username and configured_username.lower() != 'unknown')
    username_source = 'environment variable BOT_USERNAME' if username_is_set else 'environment variable not set'
    source_scan = _telegram_identity_scan_snapshot()
    return {
        'brand': 'VOOGLII',
        'config_source': token_source,
        'token_present': token_present,
        'token_masked': _mask_secret(configured_token),
        'bot_username': configured_username if username_is_set else 'unknown',
        'bot_username_source': username_source,
        'old_bot_references_found': bool(source_scan.get('old_bot_references_found')),
        'active_references': list(source_scan.get('active_references') or []),
        'ignored_archive_references': list(source_scan.get('ignored_archive_references') or []),
        'runtime_status': 'OK' if token_present else 'WARNING',
        'status': 'WARNING' if (not token_present or source_scan.get('old_bot_references_found')) else 'OK',
    }


