def _period_input(args, default='all', start_index=0):
    values=[str(x).strip() for x in (args or [])[start_index:] if str(x).strip()]
    if not values:
        return default
    if len(values) >= 2:
        return values[:2]
    return values[0]
def period(args, default='all', start_index=0): return normalize_period(_period_input(args, default, start_index))
