def _executive_period(args, default='month', start_index=0):
    try:
        return period(args, default, start_index)
    except ValueError:
        values = [str(x).strip() for x in (args or [])[start_index:] if str(x).strip()]
        if len(values) != 1:
            raise
        preset = str(values[0]).strip().lower()
        if preset not in PERIOD_ENGINE_ALLOWED_PRESETS:
            raise
        period_snapshot = build_period_snapshot(preset=preset)
        if preset == 'all':
            return 'all', None
        return preset, (period_snapshot.get('start_date'), period_snapshot.get('end_date'))


def _snapshot_context(context=None):
    context = context if isinstance(context, dict) else {}
    context.setdefault('snapshots', {})
    context.setdefault('timings', {})
    context.setdefault('warnings', [])
    context.setdefault('build_counts', {})
    context.setdefault('layer_timings', {})
    context.setdefault('db_opens_by_layer', {})
    context.setdefault('db_queries_by_layer', {})
    context.setdefault('api_call_count', {
        'finance_api_calls': 0,
        'ads_api_calls': 0,
        'sales_api_calls': 0,
    })
    context.setdefault('api_calls_by_layer', {})
    context.setdefault('profile_mode', 'full')
    context.setdefault('light_path_used', False)
    context.setdefault('full_fallback_fields', [])
    context.setdefault('saved_db_opens_estimate', 0)
    context.setdefault('saved_queries_estimate', 0)
    context['timings']['layer_timings'] = context['layer_timings']
    return context


def _context_key(name, *parts):
    normalized = [str(name or '').strip()]
    normalized.extend(str(part or '').strip() for part in parts)
    return tuple(normalized)


def _snapshot_layer_name(name):
    mapping = {
        'period_snapshot': 'period_parse_ms',
        'financial_engine_snapshot': 'financial_engine_ms',
        'business_metrics_snapshot': 'business_metrics_ms',
        'unified_data_snapshot': 'udl_ms',
        'kpi_snapshot': 'kpi_ms',
        'cfo_insights_snapshot': 'cfo_insights_ms',
        'decision_snapshot': 'decision_ms',
        'advisor_v2_snapshot': 'advisor_v2_ms',
        'director_snapshot': 'director_snapshot_ms',
        'payment_reconciliation_snapshot': 'payment_reconciliation_snapshot',
        'sku_registry_snapshot': 'sku_registry_snapshot',
        'ads_snapshot': 'ads_snapshot',
        'data_quality_snapshot': 'data_quality_snapshot',
        'advertising_health_snapshot': 'advertising_health_snapshot',
        'finance_difference_snapshot': 'finance_difference_snapshot',
        'profit_audit_snapshot': 'profit_audit_snapshot',
        'report_mgmt_snapshot': 'report_mgmt_snapshot',
    }
    return mapping.get(str(name or '').strip(), str(name or '').strip())


def _layer_entry(context, layer_name):
    context = _snapshot_context(context)
    layer_name = str(layer_name or 'unknown')
    layer_timings = context['layer_timings']
    entry = dict(layer_timings.get(layer_name) or {})
    entry.setdefault('ms', 0.0)
    entry.setdefault('status', 'built')
    entry.setdefault('reused', 'no')
    layer_timings[layer_name] = entry
    return entry


def _context_snapshot_get(context, key):
    snapshots = _snapshot_context(context).get('snapshots') or {}
    if key not in snapshots:
        return None
    value = snapshots.get(key)
    if isinstance(key, tuple) and key:
        layer_name = _snapshot_layer_name(key[0])
        entry = _layer_entry(context, layer_name)
        if float(entry.get('ms') or 0.0) > 0.0:
            entry['status'] = 'built'
        else:
            entry['status'] = 'cached'
        entry['reused'] = 'yes'
        _snapshot_context(context)['layer_timings'][layer_name] = entry
    return dict(value) if isinstance(value, dict) else value


def _context_snapshot_put(context, key, value):
    context = _snapshot_context(context)
    context['snapshots'][key] = dict(value) if isinstance(value, dict) else value
    return dict(value) if isinstance(value, dict) else value


def _context_count(context, name):
    context = _snapshot_context(context)
    build_counts = context['build_counts']
    build_counts[name] = int(build_counts.get(name) or 0) + 1
    layer_name = _snapshot_layer_name(name)
    entry = _layer_entry(context, layer_name)
    entry['status'] = 'built'
    entry['reused'] = 'no'
    context['layer_timings'][layer_name] = entry


def _context_warning(context, text):
    text = str(text or '').strip()
    if not text:
        return
    context = _snapshot_context(context)
    warnings = context['warnings']
    lowered = text.lower()
    if all(str(item or '').strip().lower() != lowered for item in warnings):
        warnings.append(text)


def _context_copy_build_counts(context):
    return dict((_snapshot_context(context).get('build_counts') or {}))


def dedupe_warnings(warnings):
    unique_items = []
    seen = set()
    for item in list(warnings or []):
        text = str(item or '').strip()
        if not text:
            continue
        if text in seen:
            continue
        seen.add(text)
        unique_items.append(text)
    return unique_items


def _context_api_call(context, api_type, caller=None):
    context = _snapshot_context(context)
    api_type = str(api_type or '').strip()
    if api_type not in ('finance_api_calls', 'ads_api_calls', 'sales_api_calls'):
        return
    counter = context['api_call_count']
    counter[api_type] = int(counter.get(api_type) or 0) + 1
    layer_source = context.get('timings') if isinstance(context.get('timings'), dict) else context
    layer_name = str(layer_source.get('_active_layer') or context.get('_active_layer') or 'unattributed')
    api_calls_by_layer = context['api_calls_by_layer']
    bucket = dict(api_calls_by_layer.get(layer_name) or {})
    bucket[api_type] = int(bucket.get(api_type) or 0) + 1
    if caller:
        bucket.setdefault('callers', [])
        if str(caller) not in bucket['callers']:
            bucket['callers'].append(str(caller))
    api_calls_by_layer[layer_name] = bucket


def _period_snapshot_for_range(start_date, end_date, context=None):
    start_date = str(start_date)
    end_date = str(end_date)
    cache_key = _context_key('period_snapshot', start_date, end_date)
    cached = _context_snapshot_get(context, cache_key)
    if cached is not None:
        return cached
    with perf_timer(_snapshot_context(context)['timings'], 'period_parse_ms'):
        snapshot = build_period_snapshot(start_date=start_date, end_date=end_date)
    _context_count(context, 'period_snapshot')
    return _context_snapshot_put(context, cache_key, snapshot)


def _try_center_period(args, default='current_month', executive=False):
    values = [str(x).strip() for x in (args or []) if str(x).strip()]
    try:
        if not values:
            if executive:
                return _executive_period([default], default)
            return _try_date_range_period([default], default)
        if executive:
            return _executive_period(args, default)
        return period(args, default, 0)
    except Exception:
        return None


def _try_date_range_period(args, default='current_month', start_index=0):
    values = [str(x).strip() for x in (args or [])[start_index:] if str(x).strip()]
    try:
        if len(values) >= 2:
            snapshot = build_period_snapshot(start_date=values[0], end_date=values[1])
            return snapshot.get('display_name') or f'{values[0]}..{values[1]}', (
                snapshot.get('start_date'),
                snapshot.get('end_date'),
            )
        preset = str(values[0] if values else default).strip().lower()
        preset_aliases = {
            'week': 'last_7_days',
            'month': 'last_30_days',
        }
        preset = preset_aliases.get(preset, preset)
        snapshot = build_period_snapshot(preset=preset)
        if preset == 'all':
            return 'all', None
        return snapshot.get('display_name') or preset, (
            snapshot.get('start_date'),
            snapshot.get('end_date'),
        )
    except Exception:
        return None


