def _performance_target(args):
    values = [str(x).strip().lower() for x in (args or []) if str(x).strip()]
    aliases = {
        'director': 'director',
        'home': 'home',
        'advisor_v2': 'advisor_v2',
        'advisor': 'advisor_v2',
        'decision': 'decision',
        'cfo_insights': 'cfo_insights',
        'cfo': 'cfo_insights',
        'kpi': 'kpi',
        'dashboard': 'dashboard',
        'report_ceo': 'report_ceo',
        'ceo': 'report_ceo',
        'system_audit': 'system_audit',
        'system': 'system_audit',
    }
    if values and values[0] in aliases:
        return aliases[values[0]], values[1:]
    return 'director', values

