def _atlas_month_label(days):
    start_date, end_date = _period_dates(days)
    try:
        dt = datetime.strptime(str(start_date), '%Y-%m-%d')
        month_names = {
            1: 'Январь', 2: 'Февраль', 3: 'Март', 4: 'Апрель',
            5: 'Май', 6: 'Июнь', 7: 'Июль', 8: 'Август',
            9: 'Сентябрь', 10: 'Октябрь', 11: 'Ноябрь', 12: 'Декабрь',
        }
        if str(start_date or '')[:7] == str(end_date or '')[:7] and str(start_date or '').endswith('-01'):
            return f'{month_names.get(dt.month, dt.strftime("%B"))} {dt.year}'
    except Exception:
        pass
    return f'{start_date} - {end_date}'


