def _gold_standard_normalize_key(value):
    text = unicodedata.normalize('NFKC', str(value or '').strip().lower())
    text = text.replace('ё', 'е')
    return re.sub(r'[^0-9a-zа-я]+', '', text)


def _gold_standard_to_float(value):
    if value in (None, ''):
        return 0.0
    if isinstance(value, (int, float)):
        return round(float(value), 2)
    text = str(value).strip()
    if not text:
        return 0.0
    text = text.replace('\xa0', '').replace(' ', '')
    if ',' in text and '.' in text:
        if text.rfind(',') > text.rfind('.'):
            text = text.replace('.', '').replace(',', '.')
        else:
            text = text.replace(',', '')
    else:
        text = text.replace(',', '.')
    try:
        return round(float(text), 2)
    except Exception:
        return 0.0


def _gold_standard_date_text(value):
    if value in (None, ''):
        return None
    if isinstance(value, datetime):
        return value.strftime('%Y-%m-%d')
    text = str(value).strip()
    if not text:
        return None
    text = text[:10]
    for fmt in ('%Y-%m-%d', '%d.%m.%Y', '%d-%m-%Y', '%Y/%m/%d', '%d/%m/%Y'):
        try:
            return datetime.strptime(text, fmt).strftime('%Y-%m-%d')
        except Exception:
            pass
    return text if re.fullmatch(r'\d{4}-\d{2}-\d{2}', text) else None


def _gold_standard_extract_report_id(*values):
    for value in values:
        if value in (None, ''):
            continue
        match = re.search(r'(\d{6,})', str(value))
        if match:
            return match.group(1)
    return None


def _gold_standard_detect_header(rows, limit=20):
    best_index = None
    best_score = -1
    for index, row in enumerate(rows[:limit]):
        score = 0
        for cell in row:
            key = _gold_standard_normalize_key(cell)
            if not key:
                continue
            if any(key in aliases for aliases in _GOLD_STANDARD_COLUMN_ALIASES.values()):
                score += 3
            elif len(key) >= 3:
                score += 1
        if score > best_score:
            best_score = score
            best_index = index
    return best_index if best_score >= 3 else None


def _gold_standard_rows_from_csv_bytes(raw_bytes):
    text = None
    for encoding in ('utf-8-sig', 'cp1251', 'utf-8', 'latin-1'):
        try:
            text = raw_bytes.decode(encoding)
            break
        except Exception:
            continue
    if text is None:
        return []
    lines = text.splitlines()
    if not lines:
        return []
    sample = '\n'.join(lines[:5])
    delimiter = ';'
    try:
        delimiter = csv.Sniffer().sniff(sample, delimiters=';,|\t').delimiter
    except Exception:
        pass
    return list(csv.reader(io.StringIO(text), delimiter=delimiter))


def _gold_standard_sheet_rows_from_xlsx(raw_bytes):
    workbook = load_workbook(io.BytesIO(raw_bytes), read_only=True, data_only=True)
    best_rows = []
    best_score = -1
    for sheet in workbook.worksheets:
        rows = [list(row) for row in sheet.iter_rows(values_only=True)]
        if not rows:
            continue
        header_index = _gold_standard_detect_header(rows)
        score = len(rows) + (100 if header_index is not None else 0)
        if score > best_score:
            best_score = score
            best_rows = rows
    workbook.close()
    return best_rows


def _gold_standard_make_row_dict(header, row, report_id=None, source_file=None, source_member=None):
    data = {}
    for index, name in enumerate(header):
        normalized = _gold_standard_normalize_key(name)
        if not normalized:
            normalized = f'column_{index + 1}'
        data[normalized] = row[index] if index < len(row) else None
    data['source_report_id'] = report_id
    data['source_file'] = source_file
    data['source_member'] = source_member
    return data


def _gold_standard_read_tabular_bytes(raw_bytes, file_name, report_id=None, source_file=None, source_member=None):
    suffix = Path(file_name).suffix.lower()
    if suffix == '.csv':
        rows = _gold_standard_rows_from_csv_bytes(raw_bytes)
    elif suffix in ('.xlsx', '.xlsm'):
        rows = _gold_standard_sheet_rows_from_xlsx(raw_bytes)
    else:
        return []
    if not rows:
        return []
    header_index = _gold_standard_detect_header(rows)
    if header_index is None:
        return []
    header = rows[header_index]
    parsed = []
    for row in rows[header_index + 1:]:
        if not any(cell not in (None, '') for cell in row):
            continue
        parsed.append(_gold_standard_make_row_dict(header, row, report_id=report_id, source_file=source_file, source_member=source_member))
    return parsed


def _gold_standard_reference_search_roots():
    roots = []
    cwd = Path.cwd()
    roots.extend([
        cwd,
        cwd / 'uploads',
        cwd / 'upload',
        cwd / 'references',
        cwd / 'reference',
        cwd / 'загрузки',
        cwd / 'Загрузки',
        cwd / 'exports',
    ])
    parent = cwd.parent
    if parent != cwd:
        roots.extend([
            parent / 'Downloads',
            parent / 'Загрузки',
        ])
    unique = []
    seen = set()
    for path in roots:
        key = str(path).lower()
        if key not in seen and path.exists():
            seen.add(key)
            unique.append(path)
    return unique


def _discover_gold_standard_reference_files(reference_files=None):
    if reference_files:
        if isinstance(reference_files, (str, os.PathLike)):
            raw_items = [reference_files]
        else:
            raw_items = list(reference_files)
        resolved = []
        for item in raw_items:
            path = Path(item)
            if path.is_dir():
                for pattern in _GOLD_STANDARD_REFERENCE_GLOB_PATTERNS:
                    resolved.extend(sorted(path.glob(pattern)))
            elif path.exists():
                resolved.append(path)
        return [path for path in resolved if path.is_file()]

    discovered = []
    for root in _gold_standard_reference_search_roots():
        for pattern in _GOLD_STANDARD_REFERENCE_GLOB_PATTERNS:
            for path in sorted(root.glob(pattern)):
                name = path.name.lower()
                report_id = _gold_standard_extract_report_id(path.name)
                if report_id in _GOLD_STANDARD_REFERENCE_IDS or 'детализ' in name or 'detailed' in name:
                    discovered.append(path)
    unique = []
    seen = set()
    for path in discovered:
        key = str(path.resolve()).lower()
        if key not in seen:
            seen.add(key)
            unique.append(path)
    return unique


def _gold_standard_reference_files_available(reference_files=None):
    return len(_discover_gold_standard_reference_files(reference_files)) > 0


def _parse_wb_detailed_reports_reference(folder_or_files=None):
    files = _discover_gold_standard_reference_files(folder_or_files)
    rows = []
    for path in files:
        report_id = _gold_standard_extract_report_id(path.name)
        suffix = path.suffix.lower()
        try:
            if suffix == '.zip':
                with zipfile.ZipFile(path, 'r') as archive:
                    for member in archive.namelist():
                        member_suffix = Path(member).suffix.lower()
                        if member_suffix not in ('.xlsx', '.xlsm', '.csv'):
                            continue
                        raw_bytes = archive.read(member)
                        rows.extend(
                            _gold_standard_read_tabular_bytes(
                                raw_bytes,
                                member,
                                report_id=report_id or _gold_standard_extract_report_id(member),
                                source_file=str(path),
                                source_member=member,
                            )
                        )
            elif suffix in ('.xlsx', '.xlsm', '.csv'):
                rows.extend(
                    _gold_standard_read_tabular_bytes(
                        path.read_bytes(),
                        path.name,
                        report_id=report_id,
                        source_file=str(path),
                        source_member=path.name,
                    )
                )
        except Exception as exc:
            logger.warning('gold standard reference parse failed for %s: %s', path, exc)
    return rows


def _gold_standard_pick(row, field_name):
    aliases = _GOLD_STANDARD_COLUMN_ALIASES.get(field_name) or ()
    for alias in aliases:
        if alias in row and row.get(alias) not in (None, ''):
            return row.get(alias)
    return None


def _normalize_wb_detail_row(row):
    raw_row = {
        _gold_standard_normalize_key(key): value
        for key, value in dict(row or {}).items()
    }
    report_id = (
        _gold_standard_extract_report_id(
            _gold_standard_pick(raw_row, 'report_id'),
            raw_row.get('source_report_id'),
            raw_row.get('source_member'),
            raw_row.get('source_file'),
        ) or ''
    )
    date_from = _gold_standard_date_text(_gold_standard_pick(raw_row, 'date_from'))
    date_to = _gold_standard_date_text(_gold_standard_pick(raw_row, 'date_to'))
    report_period = str(_gold_standard_pick(raw_row, 'report_period') or '').strip() or None
    if not report_period and date_from and date_to:
        report_period = f'{date_from}..{date_to}'
    supplier_article = str(_gold_standard_pick(raw_row, 'supplier_article') or '').strip()
    sa_name = str(_gold_standard_pick(raw_row, 'sa_name') or '').strip()
    operation_type = str(_gold_standard_pick(raw_row, 'operation_type') or '').strip()
    return {
        'report_id': report_id or None,
        'date_from': date_from,
        'date_to': date_to,
        'report_period': report_period,
        'sale_date': _gold_standard_date_text(_gold_standard_pick(raw_row, 'sale_date')),
        'order_date': _gold_standard_date_text(_gold_standard_pick(raw_row, 'order_date')),
        'supplier_article': supplier_article or sa_name or None,
        'sa_name': sa_name or supplier_article or None,
        'nm_id': str(_gold_standard_pick(raw_row, 'nm_id') or '').strip() or None,
        'subject_name': str(_gold_standard_pick(raw_row, 'subject_name') or '').strip() or None,
        'brand_name': str(_gold_standard_pick(raw_row, 'brand_name') or '').strip() or None,
        'quantity': _gold_standard_to_float(_gold_standard_pick(raw_row, 'quantity')),
        'retail_amount': _gold_standard_to_float(_gold_standard_pick(raw_row, 'retail_amount')),
        'for_pay': _gold_standard_to_float(_gold_standard_pick(raw_row, 'for_pay')),
        'wb_reward_before_agent': _gold_standard_to_float(_gold_standard_pick(raw_row, 'wb_reward_before_agent')),
        'wb_commission': abs(_gold_standard_to_float(_gold_standard_pick(raw_row, 'wb_commission'))),
        'acquiring': abs(_gold_standard_to_float(_gold_standard_pick(raw_row, 'acquiring'))),
        'delivery': abs(_gold_standard_to_float(_gold_standard_pick(raw_row, 'delivery'))),
        'storage': abs(_gold_standard_to_float(_gold_standard_pick(raw_row, 'storage'))),
        'acceptance': abs(_gold_standard_to_float(_gold_standard_pick(raw_row, 'acceptance'))),
        'deductions': abs(_gold_standard_to_float(_gold_standard_pick(raw_row, 'deductions'))),
        'penalty': abs(_gold_standard_to_float(_gold_standard_pick(raw_row, 'penalty'))),
        'additional_payment': _gold_standard_to_float(_gold_standard_pick(raw_row, 'additional_payment')),
        'one_time_payment_change': _gold_standard_to_float(_gold_standard_pick(raw_row, 'one_time_payment_change')),
        'payment_total': _gold_standard_to_float(_gold_standard_pick(raw_row, 'payment_total')),
        'operation_type': operation_type or None,
        'source_file': raw_row.get('source_file'),
        'source_member': raw_row.get('source_member'),
        'raw_row': raw_row,
    }


def _gold_standard_row_in_period(row, start_date, end_date):
    sale_date = row.get('sale_date')
    order_date = row.get('order_date')
    if sale_date and start_date <= sale_date <= end_date:
        return True
    if order_date and start_date <= order_date <= end_date:
        return True
    date_from = row.get('date_from')
    date_to = row.get('date_to')
    if date_from and date_to:
        overlap = _reference_period_overlap(date_from, date_to, start_date, end_date)
        if overlap:
            return True
    return False


def _gold_standard_group_entry(label):
    entry = {'key': label, 'rows_count': 0}
    for metric in _GOLD_STANDARD_GROUP_METRICS:
        entry[metric] = 0.0
    return entry


def _gold_standard_finalize_groups(groups):
    items = []
    for key, payload in groups.items():
        row = dict(payload)
        row['key'] = key
        items.append(row)
    items.sort(key=lambda item: (-float(item.get('sales') or 0), str(item.get('key') or '')))
    return items


def _gold_standard_match_status(gold_value, agent_value):
    if gold_value is None:
        return 'MISSING'
    if agent_value is None:
        return 'UNKNOWN'
    delta = round(float(agent_value or 0) - float(gold_value or 0), 2)
    abs_delta = abs(delta)
    if abs_delta <= 1.0:
        return 'MATCH'
    close_tolerance = max(100.0, abs(float(gold_value or 0)) * 0.05)
    if abs_delta <= close_tolerance:
        return 'CLOSE'
    return 'DIFF'


def _is_gold_standard_may_period(start_date, end_date):
    return str(start_date) == _GOLD_STANDARD_MAY_RANGE[0] and str(end_date) == _GOLD_STANDARD_MAY_RANGE[1]


def _gold_standard_may_expected_fixture():
    return dict(_OFFICIAL_FINANCIAL_GOLD_STANDARD_MAY)


def _legacy_gold_validation_default():
    return {
        'legacy_gold_validation_status': 'NOT_APPLICABLE',
        'legacy_gold_delta': {
            'payment_delta': None,
            'cost_delta': None,
            'tax_delta': None,
            'net_profit_delta': None,
        },
    }


def _validate_legacy_fallback_against_gold_standard(snapshot):
    snapshot = dict(snapshot or {})
    if not (
        str(snapshot.get('period_start') or '') == '2026-05-01'
        and str(snapshot.get('period_end') or '') == '2026-05-31'
        and str(snapshot.get('source') or '') == 'legacy_finance_api'
        and str(snapshot.get('status') or '') == 'LEGACY_FALLBACK'
        and int(snapshot.get('detail_rows_count') or 0) > 0
    ):
        return _legacy_gold_validation_default()

    expected = _gold_standard_may_expected_fixture()
    rub_tolerance = 1.0
    percent_tolerance = 0.5

    def _delta(actual, expected_value):
        if actual is None or expected_value is None:
            return None
        return round(float(actual) - float(expected_value), 2)

    def _matches(actual, expected_value):
        if actual is None or expected_value in (None, 0, 0.0):
            return False
        delta_abs = abs(float(actual) - float(expected_value))
        percent_delta = (delta_abs / abs(float(expected_value))) * 100.0 if float(expected_value) else 0.0
        return delta_abs <= rub_tolerance or percent_delta <= percent_tolerance

    deltas = {
        'payment_delta': _delta(snapshot.get('wb_payment_total'), expected.get('wb_payment_total')),
        'cost_delta': _delta(snapshot.get('cost_total'), expected.get('cost_total')),
        'tax_delta': _delta(snapshot.get('tax_amount'), expected.get('tax_amount')),
        'net_profit_delta': _delta(snapshot.get('legacy_financial_profit_estimate'), expected.get('official_net_profit')),
    }
    checks = (
        _matches(snapshot.get('wb_payment_total'), expected.get('wb_payment_total')),
        _matches(snapshot.get('cost_total'), expected.get('cost_total')),
        _matches(snapshot.get('tax_amount'), expected.get('tax_amount')),
        _matches(snapshot.get('legacy_financial_profit_estimate'), expected.get('official_net_profit')),
    )
    matched_count = sum(1 for item in checks if item)
    if matched_count == len(checks):
        status = 'MATCHED_LEGACY'
    elif matched_count > 0:
        status = 'PARTIAL_LEGACY'
    else:
        status = 'NEEDS_REVIEW'
    return {
        'legacy_gold_validation_status': status,
        'legacy_gold_delta': deltas,
    }


