def _finance_api_origin(payload=None, text='', headers=None):
    payload = payload if isinstance(payload, dict) else {}
    headers = headers if isinstance(headers, dict) else {}
    for key in ('origin', 'Origin'):
        value = payload.get(key)
        if value not in (None, ''):
            return str(value)
    for key in ('x-origin', 'X-Origin', 'x-upstream-origin', 'X-Upstream-Origin'):
        value = headers.get(key)
        if value not in (None, ''):
            return str(value)
    match = re.search(r'"origin"\s*:\s*"([^"]+)"', str(text or ''), re.IGNORECASE)
    if match:
        return str(match.group(1))
    match = re.search(r'origin\s*:\s*([^\s,]+)', str(text or ''), re.IGNORECASE)
    if match:
        return str(match.group(1))
    return ''


def _finance_api_detected_issue(http_status, payload=None, text='', origin=''):
    if http_status == 200:
        return 'OK'
    if http_status == 429:
        return 'RATE_LIMIT'
    if http_status in (401, 403):
        return 'TOKEN_CATEGORY_REQUIRED'
    serialized = ''
    if isinstance(payload, dict):
        try:
            serialized = json.dumps(payload, ensure_ascii=False)
        except Exception:
            serialized = str(payload)
    elif isinstance(payload, list):
        serialized = str(payload[:3])
    raw_text = f'{serialized}\n{text or ""}'.lower()
    origin_text = str(origin or '').lower()
    if http_status == 404 and 'path not found' in raw_text and 'stat' in origin_text:
        return 'WRONG_HOST_OR_METHOD'
    return 'UNKNOWN'


def _finance_api_probe(url, token, body=None, timeout=30, method='POST'):
    request_method = str(method or 'POST').upper()
    body = dict(body or {})
    request_headers = {'Authorization': token}
    try:
        response = httpx.request(request_method, url, headers=request_headers, json=body, timeout=timeout)
    except httpx.TimeoutException:
        return {
            'http_status': 'TIMEOUT',
            'raw_status': 'TIMEOUT',
            'headers': {},
            'retry_after': None,
            'error_text': 'timeout',
            'json': None,
            'text': '',
            'final_url': url,
            'sent_body': body,
            'method': request_method,
            'endpoint': str(httpx.URL(url).path),
            'host': str(httpx.URL(url).host or ''),
            'origin': '',
            'detected_issue': 'UNKNOWN',
        }
    except Exception as exc:
        return {
            'http_status': None,
            'raw_status': 'ERROR',
            'headers': {},
            'retry_after': None,
            'error_text': f'{type(exc).__name__}: {exc}',
            'json': None,
            'text': '',
            'final_url': url,
            'sent_body': body,
            'method': request_method,
            'endpoint': str(httpx.URL(url).path),
            'host': str(httpx.URL(url).host or ''),
            'origin': '',
            'detected_issue': 'UNKNOWN',
        }
    try:
        payload = response.json()
    except Exception:
        payload = None
    retry_after = (
        response.headers.get('Retry-After')
        or response.headers.get('retry-after')
        or response.headers.get('X-Ratelimit-Retry')
        or response.headers.get('x-ratelimit-retry')
    )
    error_text = ''
    if response.status_code != 200:
        error_text = (response.text or '')[:1000]
    origin = _finance_api_origin(payload=payload, text=response.text or '', headers=dict(response.headers))
    return {
        'http_status': int(response.status_code),
        'raw_status': _sales_probe_status_name(response.status_code, error_text, retry_after),
        'headers': dict(response.headers),
        'retry_after': retry_after,
        'error_text': error_text,
        'json': payload,
        'text': response.text or '',
        'final_url': str(response.request.url) if getattr(response, 'request', None) else url,
        'sent_body': body,
        'method': request_method,
        'endpoint': str(httpx.URL(url).path),
        'host': str(httpx.URL(url).host or ''),
        'origin': origin,
        'detected_issue': _finance_api_detected_issue(response.status_code, payload=payload, text=response.text or '', origin=origin),
    }


def _finance_api_post(url, token, body=None, timeout=30, caller='unknown'):
    probe = _finance_api_probe(url, token, body=body, timeout=timeout, method='POST')
    http_status = probe.get('http_status')
    if http_status == 200:
        return probe.get('json'), 'SUCCESS', probe
    if http_status == 429:
        retry_after = probe.get('retry_after')
        status = f'RATE_LIMIT:{retry_after}' if retry_after not in (None, '') else 'RATE_LIMIT'
        return None, status, probe
    if probe.get('detected_issue') == 'WRONG_HOST_OR_METHOD':
        return None, 'API_ENDPOINT_ERROR', probe
    if http_status == 'TIMEOUT':
        return None, 'TIMEOUT', probe
    if http_status in (None, ''):
        return None, 'CONNECTION_ERROR', probe
    if probe.get('json') is None and str(probe.get('text') or '').strip() == '' and int(http_status or 0) in (200, 201, 204):
        return [], 'SUCCESS', probe
    return None, f'ERROR_{http_status}', probe


