def fetch_wb_finance_report_detail(report_id, token=None, report_period=None):
    token = str(token or '').strip()
    report_id = str(report_id or '').strip()
    if not token:
        return {'status': 'NO_WB_TOKEN', 'rows': [], 'message': 'WB token is missing.'}
    if not report_id:
        return {'status': 'EMPTY', 'rows': [], 'message': 'WB report_id is missing.'}

    report_period = dict(report_period or {})
    period_body = {}
    if report_period.get('dateFrom') and report_period.get('dateTo'):
        period_body = {
            'dateFrom': str(report_period.get('dateFrom')),
            'dateTo': str(report_period.get('dateTo')),
        }
    endpoints = [
        (
            FINANCE_REPORTS_DETAILED_BY_ID_ENDPOINT.format(report_id=report_id),
            {},
            'fetch_wb_finance_report_detail->sales-reports/detailed/{reportId}',
        ),
        (
            FINANCE_REPORTS_DETAILED_PERIOD_ENDPOINT,
            period_body,
            'fetch_wb_finance_report_detail->sales-reports/detailed',
        ),
    ]
    last_status = 'EMPTY'
    last_message = 'No finance report details returned'
    last_diagnostics = {}
    for url, body, caller in endpoints:
        payload, status, diagnostics = _finance_api_post(url, token, body=body, timeout=25, caller=caller)
        last_diagnostics = {
            'finance_api_host': diagnostics.get('host'),
            'finance_api_method': diagnostics.get('method'),
            'finance_api_endpoint': diagnostics.get('endpoint'),
            'origin': diagnostics.get('origin') or None,
            'detected_issue': diagnostics.get('detected_issue') or 'UNKNOWN',
        }
        if status != 'SUCCESS':
            last_status = status
            last_message = {
                'ERROR_401': 'Finance detail API token lacks permissions',
                'ERROR_403': 'Finance detail API token lacks permissions',
                'RATE_LIMIT': 'Finance detail API rate limited',
                'TIMEOUT': 'Finance detail API unavailable',
                'CONNECTION_ERROR': 'Finance detail API unavailable',
                'INVALID_JSON': 'Finance detail API unavailable',
                'API_ENDPOINT_ERROR': 'Finance API endpoint/method mismatch',
            }.get(str(status).split(':', 1)[0], 'Finance detail API unavailable')
            if str(status).startswith('RATE_LIMIT:'):
                last_message = 'Finance detail API rate limited'
            continue
        rows = _finance_detail_extract_rows(payload)
        if rows:
            return {'status': 'SUCCESS', 'rows': rows, 'message': 'ok', **last_diagnostics}
        last_status = 'EMPTY'
        last_message = 'No finance report details returned'
    return {'status': last_status, 'rows': [], 'message': last_message, **last_diagnostics}


def _financial_detail_cost_snapshot(detail_rows, user, start_date, end_date):
    cost_reference = _sku_cost_reference_data()
    nm_map = _sku_ads_nm_article_map(user, start_date, end_date)
    normalized_rows = []
    missing_cost_skus = []
    matched_cost_rows = 0
    cost_eligible_rows = 0
    cost_total = 0.0
    for row in (detail_rows or []):
        item = dict(row or {})
        sku = str(item.get('sku') or '').strip()
        nm_id = str(item.get('nm_id') or '').strip()
        if not sku and nm_id:
            sku = str(nm_map.get(nm_id) or '').strip()
        item['resolved_sku'] = sku or None
        quantity = int(item.get('quantity') or 0)
        unit_cost = cost_reference.get(sku) if sku else None
        item['unit_cost'] = None if unit_cost is None else round(float(unit_cost), 2)
        if quantity > 0:
            cost_eligible_rows += 1
            if unit_cost is None:
                label = sku or (f'nmID:{nm_id}' if nm_id else 'unknown')
                if label not in missing_cost_skus:
                    missing_cost_skus.append(label)
                item['cost_total'] = None
                item['cost_status'] = 'MISSING'
            else:
                matched_cost_rows += 1
                item['cost_total'] = round(quantity * float(unit_cost), 2)
                item['cost_status'] = 'OK'
                cost_total = round(cost_total + float(item['cost_total'] or 0), 2)
        else:
            item['cost_total'] = 0.0
            item['cost_status'] = 'NOT_APPLICABLE'
        normalized_rows.append(item)
    coverage_percent = 100.0 if cost_eligible_rows == 0 else round((matched_cost_rows / cost_eligible_rows) * 100.0, 1)
    return {
        'rows': normalized_rows,
        'cost_total': round(cost_total, 2),
        'cost_eligible_rows': int(cost_eligible_rows),
        'matched_cost_rows': int(matched_cost_rows),
        'cost_coverage_percent': coverage_percent,
        'missing_cost_skus': missing_cost_skus,
        'cost_status': 'OK' if not missing_cost_skus else 'PARTIAL_COST_MISSING',
    }


def _legacy_finance_row_rrd_id(row):
    row = dict(row or {})
    for key in ('rrd_id', 'rrdId', 'rrdid'):
        value = row.get(key)
        if value in (None, ''):
            continue
        try:
            return int(value)
        except Exception:
            continue
    return None


def _normalize_legacy_financial_detail_row(row, start_date, end_date):
    row = dict(row or {})
    mapped = dict(row)
    alias_map = {
        'retail_amount': 'retailAmount',
        'retail_price_withdisc_rub': 'priceWithDisc',
        'ppvz_for_pay': 'ppvzForPay',
        'ppvz_sales_commission': 'commission',
        'delivery_rub': 'deliveryRub',
        'storage_fee': 'storageFee',
        'acquiring_fee': 'acquiringFee',
        'supplier_article': 'supplierArticle',
        'sa_name': 'saName',
        'nm_id': 'nmId',
    }
    for source_key, target_key in alias_map.items():
        if target_key not in mapped and row.get(source_key) not in (None, ''):
            mapped[target_key] = row.get(source_key)
    if mapped.get('supplierArticle') in (None, '') and row.get('sa_name') not in (None, ''):
        mapped['supplierArticle'] = row.get('sa_name')
    for key in ('quantity', 'quantity_full', 'saleQty', 'sa_quantity'):
        if mapped.get('quantity') not in (None, ''):
            break
        if row.get(key) not in (None, ''):
            mapped['quantity'] = row.get(key)
            break
    report_row = {
        'report_id': f'legacy:{start_date}..{end_date}',
        'period_start': str(start_date),
        'period_end': str(end_date),
    }
    return normalize_financial_detail_row(mapped, report_row=report_row)


def _fetch_wb_legacy_report_detail_by_period(user, start_date, end_date, force=False):
    user = int(user or 0)
    token = str(get_user_token(user) or '').strip()
    if not token:
        return {'status': 'NO_WB_TOKEN', 'rows': [], 'message': 'WB token is missing.'}
    if not force:
        blocked, cooldown_row = _finance_is_blocked(user)
        if blocked:
            cooldown = _finance_cooldown_state(cooldown_row)
            return {
                'status': 'RATE_LIMIT',
                'rows': [],
                'message': 'Finance API cooldown active',
                'cooldown_until': cooldown.get('cooldown_until'),
                'cooldown_source': cooldown.get('cooldown_source') or 'manual',
            }

    url = f'{STAT_API}/api/v5/supplier/reportDetailByPeriod'
    limit = 100000
    max_pages = 10
    page = 0
    rrdid = 0
    rows = []
    last_probe = {}
    while page < max_pages:
        probe = _finance_api_get_probe(
            url,
            token,
            params={
                'dateFrom': str(start_date),
                'dateTo': str(end_date),
                'limit': limit,
                'rrdid': rrdid,
            },
            timeout=20,
        )
        last_probe = dict(probe or {})
        http_status = probe.get('http_status')
        if http_status == 200:
            payload = probe.get('json')
            if not isinstance(payload, list):
                return {
                    'status': 'INVALID_RESPONSE',
                    'rows': [],
                    'message': 'Legacy finance API returned non-list payload.',
                    'http_status': http_status,
                    'origin': probe.get('origin'),
                    'detected_issue': probe.get('detected_issue'),
                }
            batch = [item for item in payload if isinstance(item, dict)]
            rows.extend(batch)
            page += 1
            if len(batch) < limit:
                break
            next_rrd_id = _legacy_finance_row_rrd_id(batch[-1] if batch else {})
            if next_rrd_id in (None, rrdid):
                break
            rrdid = next_rrd_id
            continue
        if http_status == 429:
            retry_after = (
                (probe.get('headers') or {}).get('Retry-After')
                or (probe.get('headers') or {}).get('retry-after')
                or probe.get('retry_after')
            )
            return {
                'status': 'RATE_LIMIT',
                'rows': [],
                'message': 'legacy API rate limited',
                'http_status': http_status,
                'origin': probe.get('origin'),
                'detected_issue': probe.get('detected_issue'),
                'retry_after': retry_after,
            }
        if http_status in (401, 403):
            return {
                'status': 'FORBIDDEN',
                'rows': [],
                'message': 'legacy finance API denied',
                'http_status': http_status,
                'origin': probe.get('origin'),
                'detected_issue': probe.get('detected_issue'),
            }
        if probe.get('detected_issue') == 'WRONG_HOST_OR_METHOD':
            return {
                'status': 'API_ENDPOINT_ERROR',
                'rows': [],
                'message': 'legacy finance API endpoint/method mismatch',
                'http_status': http_status,
                'origin': probe.get('origin'),
                'detected_issue': probe.get('detected_issue'),
            }
        if http_status == 'TIMEOUT':
            return {'status': 'TIMEOUT', 'rows': [], 'message': 'legacy finance API timeout'}
        if http_status in (None, ''):
            return {'status': 'CONNECTION_ERROR', 'rows': [], 'message': 'legacy finance API unavailable'}
        return {
            'status': f'ERROR_{http_status}',
            'rows': [],
            'message': 'legacy finance API unavailable',
            'http_status': http_status,
            'origin': probe.get('origin'),
            'detected_issue': probe.get('detected_issue'),
        }

    normalized_rows = [
        _normalize_legacy_financial_detail_row(row, start_date, end_date)
        for row in rows
        if isinstance(row, dict)
    ]
    if not normalized_rows:
        return {
            'status': 'EMPTY',
            'rows': [],
            'message': 'No legacy finance rows returned',
            'http_status': last_probe.get('http_status'),
            'origin': last_probe.get('origin'),
            'detected_issue': last_probe.get('detected_issue'),
        }
    return {
        'status': 'SUCCESS',
        'rows': normalized_rows,
        'message': 'ok',
        'http_status': last_probe.get('http_status'),
        'origin': last_probe.get('origin'),
        'detected_issue': last_probe.get('detected_issue'),
        'pages': page,
    }


def _financial_engine_snapshot(start_date, end_date, user=658486226, context=None):
    start_date = str(start_date)
    end_date = str(end_date)
    context = _snapshot_context(context)
    cache_key = _context_key('financial_engine_snapshot', user, start_date, end_date)
    cached = _context_snapshot_get(context, cache_key)
    if cached is not None:
        return cached

    def _finalize(snapshot):
        _context_count(context, 'financial_engine_snapshot')
        return _context_snapshot_put(context, cache_key, snapshot)

    with perf_timer(context['timings'], 'financial_engine_ms'):
        with perf_timer(context['timings'], 'finance_status_ms'):
            finance_api_status = _finance_api_status_snapshot(user)
            finance_runtime_status = str((finance_api_status or {}).get('status') or '')
        if finance_runtime_status == 'UNAUTHORIZED':
            return _finalize(_financial_engine_access_denied_snapshot(
                start_date,
                end_date,
                'UNAUTHORIZED',
                [
                    'Finance API unauthorized.',
                    'Проверьте корректность и актуальность WB API token.',
                ],
            ))
        blocked, cooldown_row = _finance_is_blocked(user)
        if blocked and finance_runtime_status != 'FORBIDDEN':
            cooldown = _finance_cooldown_state(cooldown_row)
            snapshot = {
                'source': 'cooldown',
                'status': 'RATE_LIMIT',
                'period': f'{start_date}..{end_date}',
                'period_start': start_date,
                'period_end': end_date,
                'reports_count': 0,
                'detail_rows_count': 0,
                'wb_sales_total': None,
                'wb_payment_total': None,
                'wb_commission_total': None,
                'payment_services_commission_total': None,
                'logistics_total': None,
                'storage_total': None,
                'acceptance_total': None,
                'deductions_total': None,
                'penalties_total': None,
                'additional_payments_total': None,
                'ads_included_in_wb_deductions': None,
                'ads_handling': 'UNKNOWN',
                'cost_total': None,
                'cost_status': 'CANNOT_COMPUTE_COST_WITHOUT_DETAIL',
                'cost_coverage_percent': 0.0,
                'missing_cost_skus': [],
                'tax_base': None,
                'tax_rate': 0.06,
                'tax_amount': None,
                'profit_before_tax': None,
                'official_net_profit': None,
                'validation_status': 'NOT_VALIDATED',
                'warnings': [
                    'Finance API cooldown active',
                    'До указанного времени API не запрашивался',
                    _finance_rate_limited_message(cooldown_row),
                ],
                'cooldown_active': True,
                'cooldown_until': cooldown.get('cooldown_until'),
                'cooldown_source': cooldown.get('cooldown_source') or 'manual',
            }
            snapshot.update(_legacy_gold_validation_default())
            return _finalize(snapshot)

        token = str(get_user_token(user) or '').strip()
        if not token:
            snapshot = {
                'source': 'unavailable',
                'status': 'UNAVAILABLE',
                'period': f'{start_date}..{end_date}',
                'period_start': start_date,
                'period_end': end_date,
                'reports_count': 0,
                'detail_rows_count': 0,
                'wb_sales_total': None,
                'wb_payment_total': None,
                'wb_commission_total': None,
                'payment_services_commission_total': None,
                'logistics_total': None,
                'storage_total': None,
                'acceptance_total': None,
                'deductions_total': None,
                'penalties_total': None,
                'additional_payments_total': None,
                'ads_included_in_wb_deductions': None,
                'ads_handling': 'UNKNOWN',
                'cost_total': None,
                'cost_status': 'CANNOT_COMPUTE_COST_WITHOUT_DETAIL',
                'cost_coverage_percent': 0.0,
                'missing_cost_skus': [],
                'tax_base': None,
                'tax_rate': 0.06,
                'tax_amount': None,
                'profit_before_tax': None,
                'official_net_profit': None,
                'validation_status': 'NOT_VALIDATED',
                'warnings': ['WB Finance API token is unavailable for the selected period.'],
                'cooldown_active': False,
                'cooldown_until': None,
                'cooldown_source': 'manual',
            }
            snapshot.update(_legacy_gold_validation_default())
            return _finalize(snapshot)

        if finance_runtime_status == 'FORBIDDEN':
            legacy_result = _fetch_wb_legacy_report_detail_by_period(user, start_date, end_date, force=True)
            legacy_status = str(legacy_result.get('status') or 'UNKNOWN')
            if legacy_status == 'SUCCESS':
                detail_rows = list(legacy_result.get('rows') or [])
                cost_snapshot = _financial_detail_cost_snapshot(detail_rows, user, start_date, end_date)
                detail_rows = cost_snapshot.get('rows') or []
                payment_snapshot = _payment_reconciliation_snapshot(user, start_date, end_date, context=context)
                wb_sales_total = round(sum(float(row.get('sales_total') or 0) for row in detail_rows), 2)
                wb_payment_total = round(sum(float(row.get('for_pay_total') or 0) for row in detail_rows), 2)
                wb_commission_total = round(sum(float(row.get('wb_commission_total') or 0) for row in detail_rows), 2)
                payment_services_commission_total = round(sum(float(row.get('payment_services_commission_total') or 0) for row in detail_rows), 2)
                logistics_total = round(sum(float(row.get('logistics_total') or 0) for row in detail_rows), 2)
                storage_total = round(sum(float(row.get('storage_total') or 0) for row in detail_rows), 2)
                acceptance_total = round(sum(float(row.get('acceptance_total') or 0) for row in detail_rows), 2)
                deductions_total = round(sum(float(row.get('deductions_total') or 0) for row in detail_rows), 2)
                penalties_total = round(sum(float(row.get('penalty_total') or 0) for row in detail_rows), 2)
                additional_payments_total = round(sum(float(row.get('additional_payment_total') or 0) for row in detail_rows), 2)
                tax_base = round(float(payment_snapshot.get('sales_revenue_total') or 0), 2) if payment_snapshot.get('sales_revenue_total') is not None else None
                tax_amount = round(tax_base * 0.06, 2) if tax_base is not None else None
                cost_total = cost_snapshot.get('cost_total')
                legacy_profit_before_tax = None
                legacy_financial_profit_estimate = None
                if str(cost_snapshot.get('cost_status') or '') == 'OK':
                    legacy_profit_before_tax = round(float(wb_payment_total or 0) - float(cost_total or 0), 2)
                    legacy_financial_profit_estimate = round(legacy_profit_before_tax - float(tax_amount or 0), 2) if tax_amount is not None else None
                validation_status = 'LEGACY_NOT_OFFICIAL_NEW_API'
                snapshot = {
                    'source': 'legacy_finance_api',
                    'status': 'LEGACY_FALLBACK',
                    'period': f'{start_date}..{end_date}',
                    'period_start': start_date,
                    'period_end': end_date,
                    'reports_count': 1,
                    'detail_rows_count': len(detail_rows),
                    'wb_sales_total': wb_sales_total,
                    'wb_payment_total': wb_payment_total,
                    'wb_commission_total': wb_commission_total,
                    'payment_services_commission_total': payment_services_commission_total,
                    'logistics_total': logistics_total,
                    'storage_total': storage_total,
                    'acceptance_total': acceptance_total,
                    'deductions_total': deductions_total,
                    'penalties_total': penalties_total,
                    'additional_payments_total': additional_payments_total,
                    'ads_included_in_wb_deductions': True,
                    'ads_handling': 'INCLUDED_IN_WB_DEDUCTIONS',
                    'cost_total': cost_total if detail_rows else None,
                    'cost_status': cost_snapshot.get('cost_status') if detail_rows else 'CANNOT_COMPUTE_COST_WITHOUT_DETAIL',
                    'cost_coverage_percent': float(cost_snapshot.get('cost_coverage_percent') or 0),
                    'missing_cost_skus': list(cost_snapshot.get('missing_cost_skus') or []),
                    'tax_base': tax_base,
                    'tax_rate': 0.06,
                    'tax_amount': tax_amount,
                    'profit_before_tax': None,
                    'official_net_profit': None,
                    'legacy_profit_before_tax': legacy_profit_before_tax,
                    'legacy_financial_profit_estimate': legacy_financial_profit_estimate,
                    'official_new_finance_available': False,
                    'legacy_estimate_available': bool(detail_rows),
                    'validation_status': validation_status,
                    'warnings': [
                        'Токен работает для старого reports/stat API, но не принят новым Finance API.',
                        'Legacy fallback mode active: source=legacy_finance_api.',
                        'Это временный fallback, потому что новый Finance API не принимает текущий токен.',
                        'Расчёт можно использовать для сверки, но для final official mode нужен новый Finance API.',
                    ],
                    'rows': [],
                    'financial_detail_rows': detail_rows,
                    'cooldown_active': False,
                    'cooldown_until': None,
                    'cooldown_source': 'manual',
                }
                snapshot.update(_validate_legacy_fallback_against_gold_standard(snapshot))
                return _finalize(snapshot)
            if legacy_status == 'RATE_LIMIT':
                return _finalize(_legacy_financial_engine_status_snapshot(
                    start_date,
                    end_date,
                    'RATE_LIMIT',
                    ['legacy API rate limited'],
                ))
            if legacy_status == 'FORBIDDEN':
                return _finalize(_legacy_financial_engine_status_snapshot(
                    start_date,
                    end_date,
                    'FORBIDDEN',
                    [
                        'both new and legacy finance APIs denied',
                        'Finance API token lacks permissions.',
                        'Проверьте, что WB API token имеет категорию Finance.',
                    ],
                ))
            return _finalize(_financial_engine_access_denied_snapshot(
                start_date,
                end_date,
                'FORBIDDEN',
                [
                    'Finance API token lacks permissions.',
                    'Проверьте, что WB API token имеет категорию Finance.',
                ],
            ))

        api_result = fetch_wb_finance_reports_list(start_date, end_date, token=token)
        raw_status = str(api_result.get('status') or 'UNKNOWN')
        if raw_status != 'SUCCESS':
            status = 'ERROR'
            if raw_status.startswith('RATE_LIMIT'):
                status = 'RATE_LIMIT'
            elif raw_status == 'API_ENDPOINT_ERROR':
                status = 'API_ENDPOINT_ERROR'
            elif raw_status in ('NO_WB_TOKEN', 'EMPTY'):
                status = 'UNAVAILABLE'
            elif raw_status in ('ERROR_401', 'ERROR_403', 'TIMEOUT', 'CONNECTION_ERROR', 'INVALID_JSON'):
                status = 'UNAVAILABLE'
            warning_message = str(api_result.get('message') or 'WB Finance API unavailable.')
            if status == 'API_ENDPOINT_ERROR':
                warning_message = 'Finance API endpoint/method mismatch'
            snapshot = {
                'source': 'unavailable',
                'status': status,
                'period': f'{start_date}..{end_date}',
                'period_start': start_date,
                'period_end': end_date,
                'reports_count': 0,
                'detail_rows_count': 0,
                'wb_sales_total': None,
                'wb_payment_total': None,
                'wb_commission_total': None,
                'payment_services_commission_total': None,
                'logistics_total': None,
                'storage_total': None,
                'acceptance_total': None,
                'deductions_total': None,
                'penalties_total': None,
                'additional_payments_total': None,
                'ads_included_in_wb_deductions': None,
                'ads_handling': 'UNKNOWN',
                'cost_total': None,
                'cost_status': 'CANNOT_COMPUTE_COST_WITHOUT_DETAIL',
                'cost_coverage_percent': 0.0,
                'missing_cost_skus': [],
                'tax_base': None,
                'tax_rate': 0.06,
                'tax_amount': None,
                'profit_before_tax': None,
                'official_net_profit': None,
                'validation_status': 'NOT_VALIDATED',
                'warnings': [warning_message],
                'cooldown_active': False,
                'cooldown_until': None,
                'cooldown_source': 'manual',
            }
            snapshot.update(_legacy_gold_validation_default())
            return _finalize(snapshot)

        rows = [_normalize_financial_engine_report(row) for row in (api_result.get('rows') or []) if isinstance(row, dict)]
        payment_snapshot = _payment_reconciliation_snapshot(user, start_date, end_date, context=context)
        list_level_payment_total = round(sum(float(row.get('payment_total') or 0) for row in rows), 2)
        list_level_logistics_total = round(sum(float(row.get('delivery_service_sum') or 0) for row in rows), 2)
        list_level_storage_total = round(sum(float(row.get('storage_sum') or 0) for row in rows), 2)
        list_level_deductions_total = round(sum(float(row.get('deduction_sum') or 0) for row in rows), 2)
        list_level_penalties_total = round(sum(float(row.get('penalty_sum') or 0) for row in rows), 2)
        list_level_additional_payments_total = round(sum(float(row.get('additional_payment_sum') or 0) for row in rows), 2)

        detail_rows = []
        detail_fetch_warnings = []
        for report_row in rows:
            report_id = str(report_row.get('report_id') or '').strip()
            if not report_id:
                continue
            detail_result = fetch_wb_finance_report_detail(
                report_id,
                token=token,
                report_period={
                    'dateFrom': report_row.get('period_start'),
                    'dateTo': report_row.get('period_end'),
                },
            )
            detail_status = str(detail_result.get('status') or 'UNKNOWN')
            if detail_status != 'SUCCESS':
                if detail_status not in ('EMPTY',):
                    detail_fetch_warnings.append(
                        f'report {report_id}: {str(detail_result.get("message") or detail_status)}'
                    )
                continue
            for raw_detail_row in (detail_result.get('rows') or []):
                if isinstance(raw_detail_row, dict):
                    detail_rows.append(_normalize_financial_detail_row(raw_detail_row, report_row=report_row))

        cost_snapshot = _financial_detail_cost_snapshot(detail_rows, user, start_date, end_date)
        detail_rows = cost_snapshot.get('rows') or []
        detail_wb_sales_total = round(sum(float(row.get('sales_total') or 0) for row in detail_rows), 2)
        detail_wb_payment_total = round(sum(float(row.get('for_pay_total') or 0) for row in detail_rows), 2)
        detail_wb_commission_total = round(sum(float(row.get('wb_commission_total') or 0) for row in detail_rows), 2)
        detail_payment_services_commission_total = round(sum(float(row.get('payment_services_commission_total') or 0) for row in detail_rows), 2)
        detail_logistics_total = round(sum(float(row.get('logistics_total') or 0) for row in detail_rows), 2)
        detail_storage_total = round(sum(float(row.get('storage_total') or 0) for row in detail_rows), 2)
        detail_acceptance_total = round(sum(float(row.get('acceptance_total') or 0) for row in detail_rows), 2)
        detail_deductions_total = round(sum(float(row.get('deductions_total') or 0) for row in detail_rows), 2)
        detail_penalties_total = round(sum(float(row.get('penalty_total') or 0) for row in detail_rows), 2)
        detail_additional_payments_total = round(sum(float(row.get('additional_payment_total') or 0) for row in detail_rows), 2)

        wb_sales_total = detail_wb_sales_total if detail_rows else None
        wb_payment_total = detail_wb_payment_total if detail_rows else (list_level_payment_total if rows else None)
        logistics_total = detail_logistics_total if detail_rows else (list_level_logistics_total if rows else None)
        storage_total = detail_storage_total if detail_rows else (list_level_storage_total if rows else None)
        deductions_total = detail_deductions_total if detail_rows else (list_level_deductions_total if rows else None)
        penalties_total = detail_penalties_total if detail_rows else (list_level_penalties_total if rows else None)
        additional_payments_total = detail_additional_payments_total if detail_rows else (list_level_additional_payments_total if rows else None)
        wb_commission_total = detail_wb_commission_total if detail_rows else None
        payment_services_commission_total = detail_payment_services_commission_total if detail_rows else None
        acceptance_total = detail_acceptance_total if detail_rows else None
        tax_base = round(float(payment_snapshot.get('sales_revenue_total') or 0), 2) if payment_snapshot.get('sales_revenue_total') is not None else None
        tax_amount = round(tax_base * 0.06, 2) if tax_base is not None else None
        warnings = []
        if wb_payment_total <= 0.01:
            warnings.append('WB Finance Reports API returned no positive bank payment total for the selected period.')
        warnings.extend(detail_fetch_warnings)
        cost_total = cost_snapshot.get('cost_total')
        profit_before_tax = None
        official_net_profit = None
        status = 'UNAVAILABLE'
        detail_endpoint_error_seen = any(
            'endpoint/method mismatch' in str(item).lower() for item in detail_fetch_warnings
        )
        if detail_endpoint_error_seen:
            warnings.append('Finance API endpoint/method mismatch')
            status = 'API_ENDPOINT_ERROR'
        elif rows and not detail_rows:
            warnings.append('Detailed finance rows are required to compute cost_total and official_net_profit safely.')
            status = 'DETAIL_REQUIRED'
        elif detail_rows:
            if str(cost_snapshot.get('cost_status') or '') == 'OK':
                profit_before_tax = round(float(wb_payment_total or 0) - float(cost_total or 0), 2)
                official_net_profit = round(profit_before_tax - float(tax_amount or 0), 2) if tax_amount is not None else None
                status = 'PARTIAL'
            else:
                status = 'PARTIAL_COST_MISSING'
        validation_status = 'NOT_VALIDATED'
        if _is_gold_standard_may_period(start_date, end_date):
            expected = _gold_standard_may_expected_fixture()
            payment_match = abs(float(wb_payment_total or 0) - float(expected.get('wb_payment_total') or 0)) <= 1.0
            cost_match = abs(float(cost_total or 0) - float(expected.get('cost_total') or 0)) <= 1.0 if cost_total is not None else False
            profit_match = abs(float(official_net_profit or 0) - float(expected.get('official_net_profit') or 0)) <= 1.0 if official_net_profit is not None else False
            if payment_match and (official_net_profit is None or (cost_match and profit_match)):
                validation_status = 'MATCHED'
                if official_net_profit is not None:
                    status = 'MATCHED'
            elif float(wb_payment_total or 0) > 0.01:
                validation_status = 'PARTIAL'
            else:
                validation_status = 'NOT_VALIDATED'
        snapshot = {
            'source': 'wb_finance_api',
            'status': status,
            'period': f'{start_date}..{end_date}',
            'period_start': start_date,
            'period_end': end_date,
            'reports_count': len(rows),
            'detail_rows_count': len(detail_rows),
            'wb_sales_total': wb_sales_total,
            'wb_payment_total': wb_payment_total if rows else None,
            'wb_commission_total': wb_commission_total,
            'payment_services_commission_total': payment_services_commission_total,
            'logistics_total': logistics_total if rows else None,
            'storage_total': storage_total if rows else None,
            'acceptance_total': acceptance_total,
            'deductions_total': deductions_total if rows else None,
            'penalties_total': penalties_total if rows else None,
            'additional_payments_total': additional_payments_total if rows else None,
            'ads_included_in_wb_deductions': True if rows else None,
            'ads_handling': 'INCLUDED_IN_WB_DEDUCTIONS' if rows else 'UNKNOWN',
            'cost_total': cost_total if detail_rows else None,
            'cost_status': cost_snapshot.get('cost_status') if detail_rows else 'CANNOT_COMPUTE_COST_WITHOUT_DETAIL',
            'cost_coverage_percent': float(cost_snapshot.get('cost_coverage_percent') or 0),
            'missing_cost_skus': list(cost_snapshot.get('missing_cost_skus') or []),
            'tax_base': tax_base,
            'tax_rate': 0.06,
            'tax_amount': tax_amount,
            'profit_before_tax': profit_before_tax,
            'official_net_profit': official_net_profit,
            'legacy_profit_before_tax': None,
            'legacy_financial_profit_estimate': None,
            'official_new_finance_available': True if detail_rows else False,
            'legacy_estimate_available': False,
            'validation_status': validation_status,
            'warnings': warnings,
            'rows': rows,
            'financial_detail_rows': detail_rows,
            'cooldown_active': False,
            'cooldown_until': None,
            'cooldown_source': 'manual',
        }
        snapshot.update(_legacy_gold_validation_default())
        return _finalize(snapshot)


def _official_financial_profit_snapshot(start_date, end_date, user=658486226):
    engine = _financial_engine_snapshot(start_date, end_date, user=user)
    if str(engine.get('status') or '') not in ('MATCHED', 'PARTIAL'):
        return {
            'period_start': str(start_date),
            'period_end': str(end_date),
            'status': 'UNAVAILABLE',
            'source': str(engine.get('source') or 'unavailable'),
            'source_label': 'Official financial profit is unavailable without a complete financial engine snapshot.',
            'operational_profit_model_kept': True,
        }
    return {
        'period_start': str(start_date),
        'period_end': str(end_date),
        'status': 'AVAILABLE',
        'source': str(engine.get('source') or 'wb_finance_api'),
        'source_label': 'WB Financial Engine',
        'wb_payment_total': engine.get('wb_payment_total'),
        'cost_total': engine.get('cost_total'),
        'tax_base_sales': engine.get('tax_base'),
        'tax_rate': engine.get('tax_rate'),
        'tax_amount': engine.get('tax_amount'),
        'official_profit_before_tax': engine.get('profit_before_tax'),
        'official_net_profit': engine.get('official_net_profit'),
        'ads_included_in_wb_deductions': engine.get('ads_included_in_wb_deductions'),
        'ads_double_subtraction_prevented': str(engine.get('ads_handling') or '') == 'INCLUDED_IN_WB_DEDUCTIONS',
        'operational_profit_model_kept': True,
    }


