def _business_metrics_snapshot_mode(user, start_date, end_date, context=None, mode='full'):
    period = (str(start_date), str(end_date))
    context = _snapshot_context(context)
    mode = str(mode or 'full').strip().lower()
    cache_key = _context_key('business_metrics_snapshot', mode, user, period[0], period[1])
    cached = _context_snapshot_get(context, cache_key)
    if cached is not None:
        return cached
    with perf_timer(context['timings'], 'business_metrics_ms'):
        data_quality_snapshot = _data_quality_snapshot(user, period, context=context)
        financial_engine_snapshot = _financial_engine_snapshot(start_date, end_date, user=user, context=context)
        ads_health_snapshot = _advertising_health_snapshot(user, period, context=context)
        if mode == 'director_light':
            snapshot = build_business_metrics_light_snapshot(
                start_date,
                end_date,
                financial_engine_snapshot=financial_engine_snapshot,
                data_quality_snapshot=data_quality_snapshot,
                ads_health_snapshot=ads_health_snapshot,
                operational_estimate_available=False,
            )
        else:
            mgmt = _report_mgmt_snapshot(user, period, context=context)
            finance_health = get_finance_difference_snapshot(user, str(start_date), str(end_date), context=context)
            operational_profit_snapshot = _profit_display_snapshot(user, period, mgmt=mgmt, finance_health=finance_health)
            profit_audit_snapshot = _profit_audit_snapshot(user, period, context=context)
            data_quality_enriched = dict(data_quality_snapshot or {})
            data_quality_enriched['trust_score'] = profit_audit_snapshot.get('trust_score')
            snapshot = build_business_metrics_snapshot(
                start_date,
                end_date,
                financial_engine_snapshot=financial_engine_snapshot,
                operational_profit_snapshot=operational_profit_snapshot,
                data_quality_snapshot=data_quality_enriched,
                ads_health_snapshot=ads_health_snapshot,
            )
    _context_count(context, 'business_metrics_snapshot')
    return _context_snapshot_put(context, cache_key, snapshot)


