def _gold_standard_comparison_item(name, gold_value, agent_value):
    if gold_value is None:
        status = 'MISSING'
        delta = None
    elif agent_value is None:
        status = 'UNKNOWN'
        delta = None
    else:
        delta = round(float(agent_value or 0) - float(gold_value or 0), 2)
        status = _gold_standard_match_status(gold_value, agent_value)
    return {
        'name': name,
        'gold_value': None if gold_value is None else round(float(gold_value or 0), 2),
        'agent_value': None if agent_value is None else round(float(agent_value or 0), 2),
        'delta': delta,
        'status': status,
    }


def _gold_standard_primary_status(snapshot, comparisons):
    reports_count = int(snapshot.get('reports_count') or 0)
    rows_count = int(snapshot.get('rows_count') or 0)
    if int(snapshot.get('reference_files_count') or 0) <= 0:
        return 'UNKNOWN'
    if reports_count <= 0 or rows_count <= 0:
        return 'FAILED'
    if float(snapshot.get('wb_commission_total') or 0) <= 0.01:
        return 'NEEDS_REVIEW'
    key_items = [
        item for item in (comparisons or [])
        if item.get('name') in ('sales_total', 'for_pay_total', 'payment_total', 'wb_commission_total')
        and item.get('status') not in ('UNKNOWN', 'MISSING')
    ]
    if key_items and all(str(item.get('status') or '') == 'MATCH' for item in key_items):
        return 'MATCHED'
    if any(str(item.get('status') or '') in ('MATCH', 'CLOSE') for item in key_items):
        return 'PARTIAL'
    if key_items:
        return 'NEEDS_REVIEW'
    return 'UNKNOWN'


def _gold_standard_financial_snapshot(start_date, end_date, reference_files=None, user=658486226):
    start_date = str(start_date)
    end_date = str(end_date)
    reference_paths = _discover_gold_standard_reference_files(reference_files)
    parsed_rows = _parse_wb_detailed_reports_reference(reference_paths)
    normalized_rows = [_normalize_wb_detail_row(row) for row in parsed_rows]
    period_rows = [row for row in normalized_rows if _gold_standard_row_in_period(row, start_date, end_date)]
    if not period_rows:
        period_rows = normalized_rows

    totals = {
        'sales_total': 0.0,
        'for_pay_total': 0.0,
        'wb_commission_total': 0.0,
        'acquiring_total': 0.0,
        'logistics_total': 0.0,
        'storage_total': 0.0,
        'acceptance_total': 0.0,
        'deductions_total': 0.0,
        'penalty_total': 0.0,
        'additional_payment_total': 0.0,
        'one_time_payment_change_total': 0.0,
        'payment_total': 0.0,
    }
    group_maps = {
        'by_report_id': {},
        'by_sku': {},
        'by_nm_id': {},
        'by_subject': {},
        'by_operation_type': {},
    }

    for row in period_rows:
        totals['sales_total'] = round(totals['sales_total'] + float(row.get('retail_amount') or 0), 2)
        totals['for_pay_total'] = round(totals['for_pay_total'] + float(row.get('for_pay') or 0), 2)
        totals['wb_commission_total'] = round(totals['wb_commission_total'] + float(row.get('wb_commission') or 0), 2)
        totals['acquiring_total'] = round(totals['acquiring_total'] + float(row.get('acquiring') or 0), 2)
        totals['logistics_total'] = round(totals['logistics_total'] + float(row.get('delivery') or 0), 2)
        totals['storage_total'] = round(totals['storage_total'] + float(row.get('storage') or 0), 2)
        totals['acceptance_total'] = round(totals['acceptance_total'] + float(row.get('acceptance') or 0), 2)
        totals['deductions_total'] = round(totals['deductions_total'] + float(row.get('deductions') or 0), 2)
        totals['penalty_total'] = round(totals['penalty_total'] + float(row.get('penalty') or 0), 2)
        totals['additional_payment_total'] = round(totals['additional_payment_total'] + float(row.get('additional_payment') or 0), 2)
        totals['one_time_payment_change_total'] = round(totals['one_time_payment_change_total'] + float(row.get('one_time_payment_change') or 0), 2)
        totals['payment_total'] = round(totals['payment_total'] + float(row.get('payment_total') or 0), 2)

        group_values = {
            'sales': float(row.get('retail_amount') or 0),
            'for_pay': float(row.get('for_pay') or 0),
            'wb_commission': float(row.get('wb_commission') or 0),
            'logistics': float(row.get('delivery') or 0),
            'storage': float(row.get('storage') or 0),
            'acquiring': float(row.get('acquiring') or 0),
            'deductions': round(
                float(row.get('deductions') or 0)
                + float(row.get('acceptance') or 0)
                + float(row.get('penalty') or 0),
                2,
            ),
            'payment_total': float(row.get('payment_total') or 0),
        }
        group_keys = {
            'by_report_id': row.get('report_id') or 'unknown',
            'by_sku': row.get('supplier_article') or row.get('sa_name') or 'unknown',
            'by_nm_id': row.get('nm_id') or 'unknown',
            'by_subject': row.get('subject_name') or 'unknown',
            'by_operation_type': row.get('operation_type') or 'unknown',
        }
        for group_name, key in group_keys.items():
            entry = group_maps[group_name].setdefault(key, _gold_standard_group_entry(key))
            entry['rows_count'] += 1
            for metric_name, metric_value in group_values.items():
                entry[metric_name] = round(float(entry.get(metric_name) or 0) + float(metric_value or 0), 2)

    bridge_base = round(
        totals['sales_total']
        - totals['wb_commission_total']
        - totals['acquiring_total']
        - totals['logistics_total']
        - totals['storage_total']
        - totals['acceptance_total']
        - totals['deductions_total']
        - totals['penalty_total']
        + totals['additional_payment_total']
        + totals['one_time_payment_change_total'],
        2,
    )
    bridge_to_for_pay = bridge_base
    bridge_to_payment_total = bridge_base
    bridge_delta_for_pay = round(bridge_base - totals['for_pay_total'], 2)
    bridge_delta_payment = round(bridge_base - totals['payment_total'], 2)
    wb_deductions_total = round(
        totals['wb_commission_total']
        + totals['acquiring_total']
        + totals['logistics_total']
        + totals['storage_total']
        + totals['acceptance_total']
        + totals['deductions_total']
        + totals['penalty_total']
        - totals['additional_payment_total']
        - totals['one_time_payment_change_total'],
        2,
    )

    comparison_snapshot = _agent_vs_gold_standard_snapshot(start_date, end_date, gold_snapshot={
        **totals,
        'sales_total': totals['sales_total'],
        'for_pay_total': totals['for_pay_total'],
        'payment_total': totals['payment_total'],
        'wb_commission_total': totals['wb_commission_total'],
        'logistics_total': totals['logistics_total'],
        'storage_total': totals['storage_total'],
    }, user=user)
    status = _gold_standard_primary_status({'reports_count': len({row.get('report_id') for row in period_rows if row.get('report_id')}), 'rows_count': len(period_rows), 'reference_files_count': len(reference_paths), 'wb_commission_total': totals['wb_commission_total']}, comparison_snapshot.get('comparisons') or [])

    return {
        'period_start': start_date,
        'period_end': end_date,
        'reference_files_count': len(reference_paths),
        'reference_files': [str(path) for path in reference_paths],
        'reports_count': len({row.get('report_id') for row in period_rows if row.get('report_id')}),
        'rows_count': len(period_rows),
        'parsed_rows_count': len(normalized_rows),
        'sales_total': round(totals['sales_total'], 2),
        'for_pay_total': round(totals['for_pay_total'], 2),
        'wb_commission_total': round(totals['wb_commission_total'], 2),
        'acquiring_total': round(totals['acquiring_total'], 2),
        'logistics_total': round(totals['logistics_total'], 2),
        'storage_total': round(totals['storage_total'], 2),
        'acceptance_total': round(totals['acceptance_total'], 2),
        'deductions_total': round(totals['deductions_total'], 2),
        'penalty_total': round(totals['penalty_total'], 2),
        'additional_payment_total': round(totals['additional_payment_total'], 2),
        'one_time_payment_change_total': round(totals['one_time_payment_change_total'], 2),
        'payment_total': round(totals['payment_total'], 2),
        'wb_deductions_total': round(wb_deductions_total, 2),
        'bridge_to_forPay': round(bridge_to_for_pay, 2),
        'bridge_to_payment_total': round(bridge_to_payment_total, 2),
        'bridge_delta_forPay': round(bridge_delta_for_pay, 2),
        'bridge_delta_payment': round(bridge_delta_payment, 2),
        'calculated_bridge_delta': round(bridge_delta_payment if abs(bridge_delta_payment) <= abs(bridge_delta_for_pay) else bridge_delta_for_pay, 2),
        'by_report_id': _gold_standard_finalize_groups(group_maps['by_report_id']),
        'by_sku': _gold_standard_finalize_groups(group_maps['by_sku']),
        'by_nm_id': _gold_standard_finalize_groups(group_maps['by_nm_id']),
        'by_subject': _gold_standard_finalize_groups(group_maps['by_subject']),
        'by_operation_type': _gold_standard_finalize_groups(group_maps['by_operation_type']),
        'comparisons': comparison_snapshot.get('comparisons') or [],
        'agent_snapshot': comparison_snapshot,
        'status': status,
        'status_reason': comparison_snapshot.get('status_reason') or '',
    }


