def _agent_vs_gold_standard_snapshot(start_date, end_date, gold_snapshot=None, user=658486226):
    start_date = str(start_date)
    end_date = str(end_date)
    if gold_snapshot is None:
        gold_snapshot = _gold_standard_financial_snapshot(start_date, end_date, user=user)
    payment_snapshot = _payment_reconciliation_snapshot(user, start_date, end_date)
    finance_health = get_finance_difference_snapshot(user, start_date, end_date)
    commission_snapshot = _wb_commission_breakdown_snapshot(user, start_date, end_date)
    ads_stats = get_advertising_stats((start_date, end_date), user)
    advertising_agent = None
    if isinstance(ads_stats, (list, tuple)) and len(ads_stats) > 4:
        try:
            advertising_agent = round(float(ads_stats[4] or 0), 2)
        except Exception:
            advertising_agent = None

    comparisons = [
        _gold_standard_comparison_item('sales_total', gold_snapshot.get('sales_total'), payment_snapshot.get('sales_revenue_total')),
        _gold_standard_comparison_item('for_pay_total', gold_snapshot.get('for_pay_total'), payment_snapshot.get('sales_for_pay_total')),
        _gold_standard_comparison_item('logistics_total', gold_snapshot.get('logistics_total'), finance_health.get('logistics')),
        _gold_standard_comparison_item('storage_total', gold_snapshot.get('storage_total'), finance_health.get('storage')),
        _gold_standard_comparison_item('advertising_total', None, advertising_agent),
        _gold_standard_comparison_item('payment_total', gold_snapshot.get('payment_total'), payment_snapshot.get('weekly_payout_total_all')),
        _gold_standard_comparison_item('wb_commission_total', gold_snapshot.get('wb_commission_total'), commission_snapshot.get('realization_commission_total')),
    ]
    return {
        'period_start': start_date,
        'period_end': end_date,
        'comparisons': comparisons,
        'status_reason': 'Advertising gold reference is unavailable locally, so that comparison stays UNKNOWN/MISSING.',
    }


def _gold_standard_financial_text(start_date, end_date, user=658486226):
    snapshot = _gold_standard_financial_snapshot(start_date, end_date, user=user)
    top_sku = snapshot.get('by_sku') or []
    top_deductions = sorted(
        snapshot.get('by_operation_type') or [],
        key=lambda item: -float(item.get('deductions') or 0),
    )
    lines = [
        'GOLD STANDARD FINANCIAL VALIDATION',
        '',
        'Источник:',
        'WB detailed weekly reports',
        f'reports: {int(snapshot.get("reports_count") or 0)}',
        f'rows: {int(snapshot.get("rows_count") or 0)}',
        f'reference files: {int(snapshot.get("reference_files_count") or 0)}',
        '',
        'Итоги по документам WB:',
        f'Продажи: {money(snapshot.get("sales_total") or 0)}',
        f'Комиссия WB за реализацию: {money(snapshot.get("wb_commission_total") or 0)}',
        f'Комиссия платёжных сервисов / эквайринг: {money(snapshot.get("acquiring_total") or 0)}',
        f'Логистика: {money(snapshot.get("logistics_total") or 0)}',
        f'Хранение: {money(snapshot.get("storage_total") or 0)}',
        f'Приёмка: {money(snapshot.get("acceptance_total") or 0)}',
        f'Удержания: {money(snapshot.get("deductions_total") or 0)}',
        f'Штрафы: {money(snapshot.get("penalty_total") or 0)}',
        f'Доплаты: {money(snapshot.get("additional_payment_total") or 0)}',
        f'Разовое изменение срока перечисления: {money(snapshot.get("one_time_payment_change_total") or 0)}',
        f'К перечислению продавцу: {money(snapshot.get("for_pay_total") or 0)}',
        f'Итого к оплате: {money(snapshot.get("payment_total") or 0)}',
        '',
        'Bridge checks:',
        f'sales → forPay: {money(snapshot.get("bridge_to_forPay") or 0)}',
        f'sales → payment_total: {money(snapshot.get("bridge_to_payment_total") or 0)}',
        f'delta: {money(snapshot.get("calculated_bridge_delta") or 0)}',
        '',
        'Agent vs Gold Standard:',
    ]
    for item in snapshot.get('comparisons') or []:
        lines.append(
            f'{item["name"]}: gold {money(item.get("gold_value") or 0) if item.get("gold_value") is not None else "-"} | '
            f'agent {money(item.get("agent_value") or 0) if item.get("agent_value") is not None else "-"} | '
            f'delta {money(item.get("delta") or 0) if item.get("delta") is not None else "-"} | '
            f'status {item.get("status") or "UNKNOWN"}'
        )
    lines.extend(['', 'TOP SKU:'])
    if top_sku:
        for item in top_sku[:5]:
            lines.append(
                f'{item.get("key")}: sales {money(item.get("sales") or 0)} | for_pay {money(item.get("for_pay") or 0)} | '
                f'wb_commission {money(item.get("wb_commission") or 0)}'
            )
    else:
        lines.append('Нет доступных SKU в reference-отчётах.')
    lines.extend(['', 'TOP удержания:'])
    if top_deductions:
        for item in top_deductions[:5]:
            lines.append(
                f'{item.get("key")}: deductions {money(item.get("deductions") or 0)} | payment_total {money(item.get("payment_total") or 0)}'
            )
    else:
        lines.append('Нет доступных строк по операциям.')
    lines.extend([
        '',
        'GOLD STANDARD STATUS:',
        snapshot.get('status') or 'UNKNOWN',
    ])
    if snapshot.get('status_reason'):
        lines.extend(['', snapshot.get('status_reason')])
    lines.extend([
        '',
        'Это отдельный read-only validation tool. Формулы прибыли, VERIFIED payout model, report.py, Dashboard/CEO/Advisor и DB write-path не изменяются.',
    ])
    return '\n'.join(lines)
def _period_dates(period_spec):
    if isinstance(period_spec, tuple) and len(period_spec) == 2:
        return str(period_spec[0]), str(period_spec[1])
    days = period_spec
    if days == 1:
        today = datetime.now().strftime('%Y-%m-%d')
        return today, today
    if days is None:
        return None, None
    return (datetime.now() - timedelta(days=int(days) - 1)).strftime('%Y-%m-%d'), datetime.now().strftime('%Y-%m-%d')


def _period_engine_parse_args(args):
    values = [str(x).strip() for x in (args or []) if str(x).strip()]
    if not values:
        return {"start_date": None, "end_date": None, "preset": None}
    if len(values) == 1:
        token = str(values[0]).strip().lower()
        if token in PERIOD_ENGINE_ALLOWED_PRESETS:
            return {"start_date": None, "end_date": None, "preset": token}
        datetime.strptime(token, '%Y-%m-%d')
        return {"start_date": token, "end_date": token, "preset": None}
    if len(values) == 2:
        start_date = str(values[0]).strip()
        end_date = str(values[1]).strip()
        datetime.strptime(start_date, '%Y-%m-%d')
        datetime.strptime(end_date, '%Y-%m-%d')
        return {"start_date": start_date, "end_date": end_date, "preset": None}
    raise ValueError('INVALID_PERIOD_ENGINE_ARGS')


def _period_engine_snapshot(args=None, today=None):
    parsed = _period_engine_parse_args(args or [])
    return build_period_snapshot(
        start_date=parsed.get('start_date'),
        end_date=parsed.get('end_date'),
        preset=parsed.get('preset'),
        today=today,
    )


def _period_engine_text(args=None, today=None):
    return period_engine_text(_period_engine_snapshot(args=args, today=today))


def _raw_command_name(update):
    text = ''
    if getattr(update, 'message', None):
        text = str(getattr(update.message, 'text', '') or '').strip()
    if not text.startswith('/'):
        return ''
    head = text.split(None, 1)[0][1:]
    if '@' in head:
        head = head.split('@', 1)[0]
    return str(head or '').strip().lower()


