def _command_source_audit_text():
    snapshot = _command_source_audit_snapshot()
    lines = [
        'COMMAND SOURCE AUDIT',
        '',
        f'commands count: {int(snapshot.get("commands_count") or 0)}',
    ]
    for item in snapshot.get('commands') or []:
        lines.extend([
            '',
            str(item.get('command') or '-'),
            f'status: {item.get("status") or "UNKNOWN"}',
            f'level: {item.get("level") or "UNKNOWN"}',
            f'source: {item.get("source") or "-"}',
            f'helper functions: {", ".join(item.get("helper_functions") or []) or "-"}',
            f'data sources: {", ".join(item.get("data_sources") or []) or "-"}',
            f'direct SQL: {item.get("direct_sql") or "unknown"}',
            f'API call: {item.get("api_call") or "unknown"}',
            f'write risk: {item.get("write_risk") or "unknown"}',
            f'uses snapshots: {item.get("uses_snapshots") or "unknown"}',
            f'legacy compatibility: {item.get("legacy_compatibility") or "unknown"}',
            f'uses official profit: {item.get("uses_official_financial_profit") or "unknown"}',
            f'uses operational profit: {item.get("uses_operational_profit") or "unknown"}',
            f'migration target: {item.get("migration_target") or "-"}',
            f'risk: {item.get("risk") or "unknown"}',
            f'migration readiness: {int(item.get("migration_readiness_percent") or 0)}%',
            f'migration readiness status: {item.get("migration_readiness_status") or "UNKNOWN"}',
            f'dependencies: {", ".join(item.get("dependencies") or []) or "-"}',
            f'blockers: {"; ".join(item.get("blockers") or []) or "-"}',
            f'legacy_fallback: {", ".join(item.get("legacy_fallback_fields") or []) or "-"}',
            f'migration risk: {item.get("migration_risk") or "UNKNOWN"}',
            f'suggested phase: {item.get("suggested_phase") or "-"}',
        ])
    if snapshot.get('warnings'):
        lines.extend(['', 'Warnings:'])
        lines.extend(str(item) for item in snapshot.get('warnings') or [])
    return '\n'.join(lines)


def _migration_readiness_snapshot():
    audit = _command_source_audit_snapshot()
    commands = list(audit.get('commands') or [])
    summary = {key: 0 for key in MIGRATION_READINESS_ALLOWED_STATUSES}
    suggested_order = {key: [] for key in MIGRATION_READINESS_ALLOWED_PHASES}
    for item in commands:
        status = str(item.get('migration_readiness_status') or 'UNKNOWN')
        if status not in summary:
            summary['UNKNOWN'] += 1
        else:
            summary[status] += 1
        phase = str(item.get('suggested_phase') or '')
        if phase in suggested_order:
            suggested_order[phase].append(str(item.get('command') or '-'))
    return {
        'status': 'OK',
        'commands_count': len(commands),
        'commands': commands,
        'summary': summary,
        'recommended_order': suggested_order,
        'product_ux': {
            '/home': 'READY',
            '/business': 'READY',
            '/finance': 'READY',
            '/products': 'READY',
            '/analytics': 'READY',
            '/system': 'READY',
        },
        'legacy_policy': [
            'keep supported',
            'hidden from main help',
            'available in developer help',
        ],
        'wait_finance_api_items': [
            'Financial Engine live validation',
            'Detailed rows validation',
        ],
    }


