def parse_update_status(raw):
    text = str(raw or '')
    parts = text.split('|') if text else []
    overall = parts[0] if parts else 'UNKNOWN'
    blocks = {}
    for part in parts[1:]:
        items = part.split(':')
        if len(items) >= 3:
            blocks[items[0]] = {'status': ':'.join(items[1:-1]), 'loaded': items[-1]}
    return overall, blocks


def last_block_issue(raw, block):
    _, blocks = parse_update_status(raw)
    data = blocks.get(block) or {}
    return str(data.get('status', ''))


def human_block_status(status):
    s = str(status or 'UNKNOWN')
    if s == 'SUCCESS':
        return 'актуально'
    if s.startswith('RATE_LIMIT') or s.startswith('SKIPPED_COOLDOWN') or s.startswith('ADS_COOLDOWN') or s.startswith('ADS_STEP_COOLDOWN') or s.startswith('FULLSTATS_429') or s.startswith('ADS_BACKGROUND_THROTTLED'):
        return f'лимит WB, следующая попытка через {rate_text(s)}'
    if s.startswith('ADVERTISING_UNSUPPORTED'):
        return 'не загружена'
    if s.startswith('ERROR_') or s.startswith('EXCEPTION:') or s in ('INVALID_RESPONSE', 'CONNECTION_ERROR', 'INVALID_JSON'):
        return 'ошибка обновления'
    if s == 'SKIPPED':
        return 'пропущено'
    if s == 'PENDING':
        return 'ожидает обновления'
    return s.lower() if s.isalpha() else 'требует проверки'


def parse_dt(value):
    if not value:
        return None
    for fmt in ('%Y-%m-%d %H:%M:%S', '%Y-%m-%d'):
        try:
            return datetime.strptime(str(value), fmt)
        except Exception:
            pass
    return None


def _log_ads_cooldown_debug(status, retry_after=None, saved_until=None, now=None, remaining=None):
    logger.info('ADS COOLDOWN DEBUG')
    logger.info('status=%s', status)
    logger.info('retry_after=%s', retry_after)
    logger.info('saved_until=%s', saved_until)
    logger.info('now=%s', now)
    logger.info('remaining=%s', remaining)


def _token_kind(token):
    text = str(token or '').strip()
    if not text:
        return 'empty'
    parts = text.split('.')
    if len(parts) == 3:
        return 'jwt'
    return f'non-jwt:{len(parts)}-segments'


def _log_ads_token_debug(token, source='unknown'):
    text = str(token or '').strip()
    logger.info('ADS TOKEN DEBUG source=%s length=%s type=%s', sanitize_log_value(source), len(text), _token_kind(token))


def _ads_cooldown_debug_values(row):
    retry_after_raw = (row or {}).get('retry_after')
    retry_after = parse_dt(retry_after_raw)
    now_dt = datetime.now()
    remaining = None
    if retry_after:
        remaining = max(0, int((retry_after - now_dt).total_seconds()))
    return {
        'saved_until': retry_after_raw or '-',
        'current_time': now_dt.strftime('%Y-%m-%d %H:%M:%S'),
        'remaining_seconds': remaining if remaining is not None else '-',
    }


def _ads_remaining_seconds(row):
    retry_after = parse_dt((row or {}).get('retry_after'))
    if not retry_after:
        return None
    return int((retry_after - datetime.now()).total_seconds())


def _ads_cooldown_is_active(row):
    remaining = _ads_remaining_seconds(row)
    return remaining is not None and remaining > 0


def _ads_ready_text():
    return 'готова к обновлению'


def _ads_retry_text(status, row=None):
    remaining = _ads_remaining_seconds(row) if row is not None else None
    if remaining is not None and remaining > 0:
        return rate_text(f'ADS_STEP_COOLDOWN:{remaining}')
    return rate_text(status)


def _ads_status_display_text(status, row=None):
    s = str(status or '')
    if s.startswith(('FULLSTATS_429_SAFE_COOLDOWN:', 'ADS_COOLDOWN:', 'ADS_STEP_COOLDOWN:', 'FULLSTATS_429:', 'RATE_LIMIT:')):
        if row is not None and not _ads_cooldown_is_active(row):
            return _ads_ready_text()
    if s.startswith('FULLSTATS_429_SAFE_COOLDOWN:') or s.startswith('ADS_COOLDOWN:') or s.startswith('ADS_STEP_COOLDOWN:'):
        return f'лимит WB\nСледующая безопасная попытка через {_ads_retry_text(s, row)}'
    if s.startswith('FULLSTATS_429:') or s.startswith('RATE_LIMIT:'):
        return f'лимит WB\nСледующая попытка через {_ads_retry_text(s, row)}'
    return None


