def rate_text(status):
    raw = str(status or '')
    value = raw.split(':', 1)[1] if ':' in raw else raw
    if raw.startswith('ADS_COOLDOWN') or raw.startswith('ADS_STEP_COOLDOWN') or raw.startswith('FULLSTATS_429_SAFE_COOLDOWN'):
        try:
            remaining = int(float(value))
        except Exception:
            remaining = None
        _log_ads_cooldown_debug(
            status=raw,
            retry_after=None,
            saved_until=None,
            now=datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            remaining=remaining,
        )
    return format_seconds(value)


def age_text(value):
    dt = parse_dt(value)
    if not dt:
        return 'нет данных'
    return f'{format_seconds((datetime.now() - dt).total_seconds())} назад'


