def cooldown_text(row):
    retry_after = parse_dt((row or {}).get('retry_after'))
    if not retry_after or retry_after <= datetime.now():
        _log_ads_cooldown_debug(
            status=(row or {}).get('last_status'),
            retry_after=(row or {}).get('retry_after'),
            saved_until=(row or {}).get('retry_after'),
            now=datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            remaining=0 if retry_after else None,
        )
        return None
    remaining = int((retry_after - datetime.now()).total_seconds())
    _log_ads_cooldown_debug(
        status=(row or {}).get('last_status'),
        retry_after=(row or {}).get('retry_after'),
        saved_until=(row or {}).get('retry_after'),
        now=datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        remaining=remaining,
    )
    return format_seconds(remaining)


def _cooldown_minutes_text(row):
    retry_after = parse_dt((row or {}).get('retry_after'))
    if not retry_after or retry_after <= datetime.now():
        _log_ads_cooldown_debug(
            status=(row or {}).get('last_status'),
            retry_after=(row or {}).get('retry_after'),
            saved_until=(row or {}).get('retry_after'),
            now=datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            remaining=0 if retry_after else None,
        )
        return '1'
    seconds = int((retry_after - datetime.now()).total_seconds())
    _log_ads_cooldown_debug(
        status=(row or {}).get('last_status'),
        retry_after=(row or {}).get('retry_after'),
        saved_until=(row or {}).get('retry_after'),
        now=datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        remaining=seconds,
    )
    minutes = max(1, seconds // 60 if seconds % 60 == 0 else seconds // 60 + 1)
    return str(minutes)


def _finance_rate_limited_message(row):
    cooldown = _finance_cooldown_state(row)
    cooldown_until = cooldown.get('cooldown_until') or 'неизвестно'
    cooldown_source = cooldown.get('cooldown_source') or 'manual'
    minutes = _cooldown_minutes_text(row)
    return (
        "Finance API находится в cooldown.\n"
        f"Повторная попытка безопасна после: {cooldown_until}\n"
        f"cooldown_source: {cooldown_source}\n"
        f"Ориентировочное ожидание: {minutes} мин.\n"
        "Данные из WB не запрашивались."
    )


def _sales_help_text():
    return (
        '/sales audit YYYY-MM-DD YYYY-MM-DD [target_orders_count=N] [target_orders_sum=X] '
        '[target_sales_count=N] [target_sales_sum=X]\n'
        '/sales backfill YYYY-MM-DD YYYY-MM-DD\n'
        '/sales historical YYYY-MM-DD YYYY-MM-DD\n'
        '/sales applyhistorical YYYY-MM-DD YYYY-MM-DD\n'
        '/sales investigate YYYY-MM-DD YYYY-MM-DD'
    )


def _sales_parse_target_args(args, start_index=3):
    targets = {}
    allowed = {
        'target_orders_count',
        'target_orders_sum',
        'target_sales_count',
        'target_sales_sum',
    }
    for raw in (args or [])[start_index:]:
        text = str(raw or '').strip()
        if '=' not in text:
            continue
        key, value = text.split('=', 1)
        key = key.strip().lower()
        value = value.strip()
        if key not in allowed or not value:
            continue
        if key.endswith('_count'):
            try:
                targets[key] = int(float(value))
            except Exception:
                continue
        else:
            try:
                targets[key] = round(float(str(value).replace(',', '.')), 2)
            except Exception:
                continue
    return targets


def _sales_local_source_snapshot(user, start_date, end_date, table_name, id_column, date_column):
    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    columns = _finance_table_columns(cur, table_name)
    amount_column = 'price_with_disc' if 'price_with_disc' in columns else 'for_pay'
    cur.execute(
        f"SELECT COUNT(*), COUNT(DISTINCT {id_column}), COALESCE(SUM({amount_column}),0), "
        f"MIN(substr({date_column},1,10)), MAX(substr({date_column},1,10)) "
        f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ?",
        (user, str(start_date), str(end_date)),
    )
    head = cur.fetchone() or (0, 0, 0, None, None)

    last_change_stats = {'column_present': False, 'min': None, 'max': None}
    for candidate in ('lastChangeDate', 'last_change_date', 'lastChangeDateTime'):
        if candidate in columns:
            cur.execute(
                f"SELECT MIN(substr({candidate},1,10)), MAX(substr({candidate},1,10)) "
                f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ?",
                (user, str(start_date), str(end_date)),
            )
            lc = cur.fetchone() or (None, None)
            last_change_stats = {'column_present': True, 'min': lc[0], 'max': lc[1], 'column': candidate}
            break

    srid_count = None
    if 'srid' in columns:
        cur.execute(
            f"SELECT COUNT(DISTINCT NULLIF(TRIM(COALESCE(srid,'')), '')) "
            f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ?",
            (user, str(start_date), str(end_date)),
        )
        srid_count = int((cur.fetchone() or [0])[0] or 0)

    article_column = 'supplier_article' if 'supplier_article' in columns else 'supplierArticle'
    cur.execute(
        f"SELECT substr({date_column},1,10), COUNT(*), COALESCE(SUM({amount_column}),0) "
        f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ? "
        f"GROUP BY substr({date_column},1,10) ORDER BY 1",
        (user, str(start_date), str(end_date)),
    )
    day_groups = [
        {'date': str(row[0]), 'count': int(row[1] or 0), 'sum': round(float(row[2] or 0), 2)}
        for row in cur.fetchall()
    ]
    cur.execute(
        f"SELECT COALESCE(NULLIF(TRIM(COALESCE({article_column},'')), ''), '-'), COUNT(*), COALESCE(SUM({amount_column}),0) "
        f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ? "
        f"GROUP BY COALESCE(NULLIF(TRIM(COALESCE({article_column},'')), ''), '-') "
        f"ORDER BY COUNT(*) DESC, COALESCE(SUM({amount_column}),0) DESC, 1 ASC LIMIT 30",
        (user, str(start_date), str(end_date)),
    )
    article_groups = [
        {'supplier_article': str(row[0]), 'count': int(row[1] or 0), 'sum': round(float(row[2] or 0), 2)}
        for row in cur.fetchall()
    ]
    conn.close()
    return {
        'rows': int(head[0] or 0),
        'unique_ids': int(head[1] or 0),
        'sum': round(float(head[2] or 0), 2),
        'min_date': head[3],
        'max_date': head[4],
        'last_change': last_change_stats,
        'unique_srid': srid_count,
        'day_groups': day_groups,
        'article_groups': article_groups,
    }


def _sales_verdict_lines(audit_result, targets):
    lines = []
    sales_api = audit_result.get('sales_api') or {}
    orders_api = audit_result.get('orders_api') or {}
    sales_local = audit_result.get('sales_local') or {}
    orders_local = audit_result.get('orders_local') or {}

    if int(sales_local.get('rows') or 0) == 0 and int(orders_local.get('rows') or 0) == 0:
        lines.append('period не загружался ранее')
    if int(sales_api.get('rows_in_range') or 0) > int(sales_local.get('rows') or 0):
        lines.append('rolling window')
    if not sales_api.get('pagination_used') or not orders_api.get('pagination_used'):
        lines.append('отсутствует pagination')
    if not sales_api.get('rows_with_last_change_date'):
        lines.append('отсутствует lastChangeDate')
    if int(sales_api.get('rows_in_range') or 0) > int(sales_local.get('rows') or 0) or int(orders_api.get('rows_in_range') or 0) > int(orders_local.get('rows') or 0):
        lines.append('отсутствует historical backfill')
    if targets:
        if 'target_sales_count' in targets and int(sales_local.get('rows') or 0) != int(targets['target_sales_count']):
            lines.append('local sales count не совпадает с manual target')
        if 'target_orders_count' in targets and int(orders_local.get('rows') or 0) != int(targets['target_orders_count']):
            lines.append('local orders count не совпадает с manual target')
    return lines or ['явная причина не определена; нужен дополнительный historical backfill/audit']


def _sales_investigate_date_only(value):
    text = str(value or '').strip()
    return text[:10] if text else ''


def _sales_investigate_in_range(date_text, start_date, end_date):
    day = _sales_investigate_date_only(date_text)
    if not day:
        return False
    return str(start_date) <= day <= str(end_date)


def _sales_token_mask(token):
    text = str(token or '').strip()
    if not text:
        return {'present': 'no', 'length': 0, 'prefix4': '', 'suffix4': '', 'kind': _token_kind(token)}
    return {
        'present': 'yes',
        'length': len(text),
        'prefix4': text[:4],
        'suffix4': text[-4:],
        'kind': _token_kind(token),
    }


def _sales_probe_status_name(http_status, error_text='', retry_after=None):
    if http_status == 200:
        return 'SUCCESS'
    if http_status == 429:
        return 'RATE_LIMIT'
    if http_status == 401:
        return 'UNAUTHORIZED'
    if http_status == 403:
        return 'FORBIDDEN'
    if http_status == 400:
        return 'BAD_REQUEST'
    if http_status == 'TIMEOUT':
        return 'TIMEOUT'
    if http_status in (None, ''):
        return 'ERROR'
    return 'ERROR'


def _sales_http_probe(url, token, params=None, timeout=30):
    try:
        response = httpx.get(url, headers={'Authorization': token}, params=params, timeout=timeout)
    except httpx.TimeoutException:
        return {
            'http_status': 'TIMEOUT',
            'raw_status': 'TIMEOUT',
            'headers': {},
            'retry_after': None,
            'error_text': 'timeout',
            'json': None,
            'text': '',
            'final_url': url,
            'sent_params': dict(params or {}),
        }
    except Exception as exc:
        return {
            'http_status': None,
            'raw_status': 'ERROR',
            'headers': {},
            'retry_after': None,
            'error_text': f'{type(exc).__name__}: {exc}',
            'json': None,
            'text': '',
            'final_url': url,
            'sent_params': dict(params or {}),
        }
    try:
        payload = response.json()
    except Exception:
        payload = None
    retry_after = response.headers.get('Retry-After') or response.headers.get('retry-after') or response.headers.get('X-Ratelimit-Retry') or response.headers.get('x-ratelimit-retry')
    error_text = ''
    if response.status_code != 200:
        error_text = (response.text or '')[:500]
    return {
        'http_status': int(response.status_code),
        'raw_status': _sales_probe_status_name(response.status_code, error_text, retry_after),
        'headers': dict(response.headers),
        'retry_after': retry_after,
        'error_text': error_text,
        'json': payload,
        'text': response.text or '',
        'final_url': str(response.request.url) if getattr(response, 'request', None) else url,
        'sent_params': dict(params or {}),
    }


def _sales_rows_summary(rows, start_date=None, end_date=None, kind='sales', telegram_id=0):
    amount_field = 'priceWithDisc'
    raw_rows = [row for row in (rows or []) if isinstance(row, dict)]
    id_field = 'saleID' if kind == 'sales' else 'odid'
    alt_id_field = 'srid'
    alt2_id_field = 'gNumber'
    filtered_by_date = []
    filtered_by_last_change = []
    min_date = None
    max_date = None
    min_last_change = None
    max_last_change = None
    sum_price = 0.0
    first_ids = []
    saleid_duplicates = 0
    rawkey_duplicates = 0
    srid_duplicates = 0
    saleid_seen = set()
    rawkey_seen = set()
    srid_seen = set()
    last_change_present = 0
    for row in raw_rows:
        row_date = _sales_investigate_date_only(row.get('date'))
        if row_date:
            min_date = row_date if min_date is None or row_date < min_date else min_date
            max_date = row_date if max_date is None or row_date > max_date else max_date
        lc = _sales_investigate_date_only(row.get('lastChangeDate') or row.get('last_change_date') or row.get('lastChangeDateTime'))
        if lc:
            last_change_present += 1
            min_last_change = lc if min_last_change is None or lc < min_last_change else min_last_change
            max_last_change = lc if max_last_change is None or lc > max_last_change else max_last_change
        sum_price += float(row.get(amount_field) or 0)
        if start_date and end_date and _sales_investigate_in_range(row.get('date'), start_date, end_date):
            filtered_by_date.append(row)
        if start_date and end_date and lc and _sales_investigate_in_range(lc, start_date, end_date):
            filtered_by_last_change.append(row)
        if kind == 'sales':
            raw_identity = row.get('saleID') or row.get('srid') or f"{row.get('date')}:{row.get('supplierArticle')}:{row.get('nmId')}:{row.get('forPay')}"
        else:
            raw_identity = row.get('odid') or row.get('srid') or f"{row.get('date')}:{row.get('supplierArticle')}:{row.get('nmId')}:{row.get('totalPrice')}"
        identity = f"{telegram_id}:{raw_identity}"
        raw_key = identity.split(':', 1)[1] if ':' in identity else identity
        if raw_key in rawkey_seen:
            rawkey_duplicates += 1
        else:
            rawkey_seen.add(raw_key)
        direct_id = row.get(id_field)
        if direct_id not in (None, ''):
            direct_id = str(direct_id)
            if direct_id in saleid_seen:
                saleid_duplicates += 1
            else:
                saleid_seen.add(direct_id)
            if len(first_ids) < 2:
                first_ids.append(direct_id)
        srid = row.get(alt_id_field)
        if srid not in (None, ''):
            srid = str(srid)
            if srid in srid_seen:
                srid_duplicates += 1
            else:
                srid_seen.add(srid)
            if len(first_ids) < 2 and srid not in first_ids:
                first_ids.append(srid)
        alt2 = row.get(alt2_id_field)
        if len(first_ids) < 2 and alt2 not in (None, ''):
            first_ids.append(str(alt2))
    return {
        'rows_before_filter': len(raw_rows),
        'rows_after_date_filter': len(filtered_by_date) if start_date and end_date else len(raw_rows),
        'rows_after_last_change_filter': len(filtered_by_last_change) if start_date and end_date else last_change_present,
        'min_date': min_date,
        'max_date': max_date,
        'min_last_change': min_last_change,
        'max_last_change': max_last_change,
        'sum_price': round(sum_price, 2),
        'first_ids': first_ids[:2],
        'has_primary_id': any(row.get(id_field) not in (None, '') for row in raw_rows),
        'has_srid': any(row.get('srid') not in (None, '') for row in raw_rows),
        'saleid_duplicates': saleid_duplicates,
        'srid_duplicates': srid_duplicates,
        'rawkey_duplicates': rawkey_duplicates,
        'last_change_present': last_change_present,
    }


def _sales_probe_variants(start_date, end_date):
    start_dt = datetime.strptime(str(start_date), '%Y-%m-%d')
    end_dt = datetime.strptime(str(end_date), '%Y-%m-%d')
    return [
        ('start_date', start_dt.strftime('%Y-%m-%d')),
        ('start_date_plus_1', (start_dt + timedelta(days=1)).strftime('%Y-%m-%d')),
        ('fixed_2026_05_11', '2026-05-11'),
        ('end_date', end_dt.strftime('%Y-%m-%d')),
        ('today_minus_30', (datetime.now() - timedelta(days=30)).strftime('%Y-%m-%d')),
    ]


def _sales_investigate_snapshot(user, token, start_date, end_date):
    token_info = _sales_token_mask(token)
    sales_endpoint = 'https://statistics-api.wildberries.ru/api/v1/supplier/sales'
    orders_endpoint = 'https://statistics-api.wildberries.ru/api/v1/supplier/orders'
    request_formats = [
        ('date', str(start_date)),
        ('datetime', f'{start_date}T00:00:00'),
        ('datetime_tz', f'{start_date}T00:00:00+03:00'),
    ]
    parameter_probes = []
    for label, date_from_value in request_formats:
        params = {'dateFrom': date_from_value}
        sales_probe = _sales_http_probe(sales_endpoint, token, params=params, timeout=20)
        orders_probe = _sales_http_probe(orders_endpoint, token, params=params, timeout=20)
        parameter_probes.append({
            'label': label,
            'dateFrom': date_from_value,
            'sales': sales_probe,
            'orders': orders_probe,
            'timezone_used': '+03:00' in date_from_value,
            'format_sent': date_from_value,
        })

    sales_test = _sales_http_probe(sales_endpoint, token, params={'dateFrom': str(start_date)}, timeout=20)
    orders_test = _sales_http_probe(orders_endpoint, token, params={'dateFrom': str(start_date)}, timeout=20)

    sales_variants = []
    for label, value in _sales_probe_variants(start_date, end_date):
        probe = _sales_http_probe(sales_endpoint, token, params={'dateFrom': value}, timeout=20)
        summary = _sales_rows_summary(probe.get('json') if isinstance(probe.get('json'), list) else [], start_date, end_date, kind='sales', telegram_id=user)
        sales_variants.append({'label': label, 'dateFrom': value, 'probe': probe, 'summary': summary})

    orders_variants = []
    for label, value in _sales_probe_variants(start_date, end_date):
        probe = _sales_http_probe(orders_endpoint, token, params={'dateFrom': value}, timeout=20)
        summary = _sales_rows_summary(probe.get('json') if isinstance(probe.get('json'), list) else [], start_date, end_date, kind='orders', telegram_id=user)
        orders_variants.append({'label': label, 'dateFrom': value, 'probe': probe, 'summary': summary})

    sales_local = _sales_local_source_snapshot(user, start_date, end_date, 'sales', 'sale_id', 'sale_date')
    orders_local = _sales_local_source_snapshot(user, start_date, end_date, 'orders', 'order_id', 'order_date')
    sales_inspect = inspect_sales_api(token, start_date, end_date, user)
    orders_inspect = inspect_orders_api(token, start_date, end_date, user)
    sales_summary = _sales_rows_summary(sales_test.get('json') if isinstance(sales_test.get('json'), list) else [], start_date, end_date, kind='sales', telegram_id=user)
    orders_summary = _sales_rows_summary(orders_test.get('json') if isinstance(orders_test.get('json'), list) else [], start_date, end_date, kind='orders', telegram_id=user)
    return {
        'token_info': token_info,
        'sales_endpoint': sales_endpoint,
        'orders_endpoint': orders_endpoint,
        'parameter_probes': parameter_probes,
        'sales_test': sales_test,
        'orders_test': orders_test,
        'sales_variants': sales_variants,
        'orders_variants': orders_variants,
        'sales_local': sales_local,
        'orders_local': orders_local,
        'sales_inspect': sales_inspect,
        'orders_inspect': orders_inspect,
        'sales_summary': sales_summary,
        'orders_summary': orders_summary,
    }


def _sales_investigate_verdict(snapshot):
    sales_test = snapshot['sales_test']
    orders_test = snapshot['orders_test']
    sales_summary = snapshot['sales_summary']
    orders_summary = snapshot['orders_summary']
    sales_local = snapshot['sales_local']
    sales_inspect = snapshot['sales_inspect']

    rate_limit_high = any(str(item['probe'].get('raw_status')) == 'RATE_LIMIT' for item in snapshot['sales_variants'] + snapshot['orders_variants'])
    unauthorized = any(str(item.get('raw_status')) in ('UNAUTHORIZED', 'FORBIDDEN') for item in (sales_test, orders_test))
    historical_gap = int(sales_local.get('rows') or 0) < int(sales_inspect.get('rows_in_range') or 0) and int(sales_inspect.get('rows_in_range') or 0) > 0
    historical_zero = int(sales_summary.get('rows_before_filter') or 0) == 0 and int(orders_summary.get('rows_before_filter') or 0) == 0
    missing_last_change = int(sales_summary.get('last_change_present') or 0) == 0
    no_pagination = str(sales_inspect.get('pagination_used')) == 'False' and str(orders_inspect.get('pagination_used')) == 'False'
    filter_problem = int(sales_summary.get('rows_before_filter') or 0) > 0 and int(sales_summary.get('rows_after_date_filter') or 0) == 0
    key_problem = int(sales_summary.get('saleid_duplicates') or 0) > 0 or int(sales_summary.get('rawkey_duplicates') or 0) > 0

    verdict = {
        'RATE_LIMIT мешает загрузке': 'HIGH' if rate_limit_high else 'LOW',
        'WB statistics API не отдаёт исторические данные старше 30 дней': 'HIGH' if historical_zero else ('MEDIUM' if historical_gap else 'LOW'),
        'используется неверный токен': 'HIGH' if unauthorized else 'LOW',
        'неверный формат dateFrom': 'MEDIUM' if historical_zero and not unauthorized else 'LOW',
        'отсутствует lastChangeDate стратегия': 'HIGH' if missing_last_change else 'LOW',
        'отсутствует пагинация': 'HIGH' if no_pagination else 'LOW',
        'ошибка фильтрации периода': 'HIGH' if filter_problem else 'LOW',
        'ошибка safe upsert / ключей': 'MEDIUM' if key_problem else 'LOW',
    }
    root_cause = 'RATE_LIMIT и/или WB statistics API не отдаёт исторические данные по sales для заданного dateFrom'
    if unauthorized:
        root_cause = 'неверный или неподходящий token для statistics API'
    elif filter_problem:
        root_cause = 'строки приходят из API, но отбрасываются локальной фильтрацией периода'
    elif key_problem:
        root_cause = 'риск коллизии/дедупликации по ключам safe upsert'
    return verdict, root_cause


