async def buttons(update, context):
    text = update.message.text
    period_buttons = {
        '📅 Сегодня': 'today',
        '📆 Неделя': 'week',
        '🗓 Месяц': 'month',
        '♾ Всё время': 'all',
    }
    if text in period_buttons:
        if period_buttons[text] == 'all':
            context.args = list(_customer_all_time_range(uid(update)))
        else:
            context.args = [period_buttons[text]]
        await business_command(update, context)
        return
    mapping = {
        '📊 Отчёт': (report_command, ['current_month']),
        '👑 CEO': (ceo_command, ['current_month']),
        '📦 Остатки': (stocks_command, []),
        '💰 P&L': (pnl_command, ['current_month']),
        '📢 Реклама': (advert_command, ['current_month']),
        '🤖 AI-советы': (advisor_command, []),
        '⚠ Проблемы': (business_command, ['current_month']),
        '👤 Кабинет': (profile_command, []),
        '🔄 Обновить': (update_command, []),
        '⚙ Меню': (menu_command, []),
    }.get(text)
    if mapping:
        context.args = list(mapping[1])
        await mapping[0](update, context)
        return


def _ad_warning_text(user_id, period_days=None):
    sync_map = get_sync_status_map(user_id)
    row = sync_map.get('advertising') or {}
    status = row.get('last_status') or ''
    last_success = row.get('last_success')
    if not status or status in ('SUCCESS', 'PENDING'):
        return None
    if not last_success:
        return (
            "⚠ Внимание:\n"
            "Реклама WB не обновлена.\n"
            "Причина: лимит WB API или ошибка рекламного API.\n"
            "Чистая прибыль может быть завышена."
        )
    if _status_kind(status) == 'cooldown':
        return f"⚠ Реклама устарела:\nпоследнее успешное обновление было {age_text(last_success)}."
    if _status_kind(status) == 'error':
        return (
            "⚠ Внимание:\n"
            "Реклама WB не обновлена.\n"
            "Причина: лимит WB API или ошибка рекламного API.\n"
            "Чистая прибыль может быть завышена."
        )
    return None


def _stale_sync_warnings(user_id):
    sync_map = get_sync_status_map(user_id)
    limits = {'sales': 12 * 3600, 'stocks': 24 * 3600, 'advertising': 24 * 3600, 'finance': 24 * 3600}
    warnings = []
    now = datetime.now()
    for block, limit_seconds in limits.items():
        row = sync_map.get(block) or {}
        last_success = parse_dt(row.get('last_success'))
        if not last_success:
            continue
        if int((now - last_success).total_seconds()) > limit_seconds:
            warnings.append(f'{block_label(block)}: последнее успешное обновление было {age_text(row.get("last_success"))}.')
    return warnings


def _stock_snapshot_date(user_id):
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    cur.execute('SELECT MAX(stock_date) FROM stocks WHERE telegram_id=?', (user_id,))
    row = cur.fetchone()
    conn.close()
    return row[0] if row and row[0] else None


async def update_command(update, context):
    from vooglii_telegram.handlers.update import update_command as _impl
    return await _impl(update, context)


async def _update_command_entry(update, context):
    if not await access(update, 'update'):
        return
    token = get_user_token(uid(update))
    if not token:
        await update.message.reply_text(update_no_cabinet_text())
        return
    await update.message.reply_text(update_started_text())
    saved, status = load_sales_for_user(uid(update), token, 30, False, True)
    if not isinstance(status, dict):
        if str(status).startswith('RATE_LIMIT'):
            await update.message.reply_text(f'⏳ Лимит WB API. Повтор через {rate_text(status)}.')
        elif str(status).startswith('SUCCESS'):
            await update.message.reply_text(f'✅ Обновление завершено.\nНовых продаж: {saved}')
        else:
            await update.message.reply_text(f'⚠ Ошибка обновления: {status}')
        return

    blocks = status.get('blocks', {})
    all_limited = True
    any_success = False
    lines = []
    for name in ['sales', 'orders', 'stocks', 'finance', 'advertising']:
        block = blocks.get(name) or {}
        block_status = str(block.get('status') or 'PENDING')
        kind = _status_kind(block_status)
        if kind != 'cooldown':
            all_limited = False
        if kind == 'success':
            any_success = True
            lines.append(f'✅ {block_label(name)} обновлены')
        elif kind == 'cooldown':
            lines.append(f'⏳ {block_label(name)}: повтор через {rate_text(block_status)}')
        else:
            lines.append(f'⚠ {block_label(name)}: {_user_reason_text(block_status)}')

    if all_limited:
        await update.message.reply_text(
            '⏳ Обновление сейчас недоступно из-за лимитов WB API\n\n'
            'Повторить можно:\n' + '\n'.join(lines) +
            '\n\nСтарые данные сохранены.\nОтчёты продолжают работать на последних успешных данных.'
        )
        return

    if any_success and any(_status_kind((blocks.get(n) or {}).get('status')) != 'success' for n in blocks):
        await update.message.reply_text('⚠ Данные обновлены частично\n\n' + '\n'.join(lines))
        return

    await update.message.reply_text('✅ Данные обновлены\n\n' + '\n'.join(lines))


