async def _syncstatus_command_entry(update, context):
    user = uid(update)
    ensure_sync_status_rows(user)
    sync_rows = get_sync_status(user)
    api_rows = {row['api_block']: row for row in get_api_status(user)}
    sync_map = {row['sync_block']: row for row in sync_rows}
    snapshot = _stock_snapshot_date(user)
    lines = ['📡 Синхронизация данных', '']
    for block in ['sales', 'orders', 'stocks', 'finance', 'advertising']:
        row = sync_map.get(block) or {}
        api_row = api_rows.get(block) or {}
        extra = [f'Дата snapshot: {snapshot}'] if block == 'stocks' and snapshot else None
        lines.append(format_sync_block_for_user(block, row, api_row, extra))
        if _is_engineering_role(user):
            lines.append(format_sync_block_for_admin(block, row, api_row))
        lines.append('')
    await send_long(update, '\n'.join(lines).strip())


