async def _connect_command_entry(update, context):
    if not context.args:
        await update.message.reply_text(connect_intro_text())
        return
    user_id = uid(update)
    try:
        validate_wb_token(context.args[0].strip())
        save_user(user_id, uname(update), context.args[0].strip())
    except Exception as exc:
        await update.message.reply_text(
            "⚠ Не удалось подключить кабинет WB.\n\n"
            "Проверьте, что API-ключ скопирован полностью, и повторите команду /connect."
        )
        return
    ensure_sync_status_rows(user_id)
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    cur.execute('''
    INSERT OR IGNORE INTO notifications(
        telegram_id,daily_enabled,daily_hour,weekly_enabled,low_stock_threshold,negative_profit_alert,drr_alert_threshold,sales_drop_threshold
    ) VALUES(?,?,?,?,?,?,?,?)
    ''', (user_id, 1, 9, 1, 5, 1, 30, 40))
