def _roi_text_and_cost_warnings(days, user_id):
    roi = get_roi(days, user_id)
    cost_stats = get_cost_fill_stats(days, user_id)
    roi_text = f'{roi:.1f}%' if roi is not None else 'не рассчитан'
    lines = []
    if cost_stats['total_rows'] > 0 and cost_stats['all_missing']:
        lines.append('⚠ Себестоимость не заполнена.')
        lines.append('Причина: не заполнена себестоимость товаров.')
        lines.append('Чистая прибыль, маржа и ROI могут быть неточными.')
    elif cost_stats['total_rows'] > 0 and (cost_stats['partial_missing'] or cost_stats['missing_articles'] > 0):
        lines.append('⚠ Себестоимость заполнена не у всех товаров. Прибыль и ROI могут быть неточными.')
    return roi_text, '\n'.join(lines) if lines else None



def _ads_status_user_text(status):
    s = str(status or '')
    if s.startswith('ADS_PARTIAL_PROGRESS'):
        return 'частично загружена\nЗагрузка продолжается поэтапно'
    normalized_status = normalize_advertising_status(s)
    if normalized_status == 'ADS_PARTIAL':
        return '⚠ Рекламные данные обновлены частично.\nЧасть кампаний пока не удалось связать с товарами WB.'
    if normalized_status == 'ADS_NO_CAMPAIGNS':
        return 'активные рекламные кампании не найдены'
    if s.startswith('ADS_BATCH_TOO_LARGE'):
        return 'список campaign_id слишком большой для одного fullstats-запроса'
    if s.startswith('ADS_PERIOD_BATCH_FAILED'):
        return 'period batch fullstats не принят рекламным API'
    if s.startswith('ADS_BACKGROUND_THROTTLED'):
        return f'фоновая загрузка отложена\nСледующая попытка через {rate_text(s)}'
    display = _ads_status_display_text(status)
    if display is not None:
        return display
    if s.startswith('FULLSTATS_INVALID_BEGIN'):
        return 'ошибка формата даты fullstats. Можно диагностировать через /ads probe'
    if s.startswith('FULLSTATS_400'):
        return 'ошибка формата запроса fullstats'
    if s.startswith('FULLSTATS_404'):
        return 'endpoint fullstats не найден'
    if s.startswith('DISCOVERY_404'):
        return 'endpoint списка рекламных кампаний не найден'
    if s.startswith('ERROR_401') or s.startswith('ERROR_403') or s == 'TOKEN_ERROR':
        return 'проблема с токеном'
    if s.startswith('ERROR_'):
        return f'ошибка WB API {s}'
    if s.startswith('ADVERTISING_UNSUPPORTED'):
        return 'рекламный API недоступен для этого кабинета'
    if s == 'SUCCESS':
        return 'актуально'
    if s == 'UNKNOWN':
        return 'данные обновляются'
    if s == 'NOT_ACTIVE':
        return 'нет активных рекламных кампаний'
    return s or '-'


def _finance_breakdown_text(status, st_other):
    s = str(status or '')
    if s.startswith('RATE_LIMIT:'):
        return (
            "Финансы WB временно на лимите.\n"
            f"Следующая попытка после: через {rate_text(s)}\n"
            "Старые данные в отчёте сохранены."
        )
    if s == 'SUCCESS':
        return None
    return f'Не удалось получить детализацию из WB API: {s}\nПо текущим данным в отчёте: {money(st_other)}'


def _legacy_user_reason_text_v1(status):
    s = str(status or '')
    if s.startswith('ADS_PARTIAL_MISSING_IDS'):
        return 'WB fullstats вернул не все advertId; пришедшие данные сохранены, missing ids не затёрты'
    if s.startswith('ADS_COOLDOWN') or s.startswith('FULLSTATS_429:') or s.startswith('RATE_LIMIT:') or s.startswith('ADS_BACKGROUND_THROTTLED'):
        return f'лимит WB API, повтор через {rate_text(s)}'
    if s.startswith('ADS_BATCH_TOO_LARGE'):
        return 'список campaign_id слишком большой для одного fullstats-запроса'
    if s.startswith('ADS_PERIOD_BATCH_FAILED'):
        return 'period batch fullstats не принят рекламным API'
    if s.startswith('FULLSTATS_400'):
        return 'ошибка формата запроса fullstats'
    if s.startswith('FULLSTATS_404'):
        return 'endpoint fullstats не найден'
    if s.startswith('DISCOVERY_404'):
        return 'endpoint списка рекламных кампаний не найден'
    if s.startswith('ADVERTISING_UNSUPPORTED'):
        return 'рекламный API недоступен для этого кабинета'
    if s.startswith('ERROR_401') or s.startswith('ERROR_403') or s == 'TOKEN_ERROR':
        return 'проблема с токеном'
    if s.startswith('ERROR_'):
        return f'ошибка WB API {s}'
    if s.startswith('EXCEPTION:'):
        return 'внутренняя ошибка обновления'
    if s in ('CONNECTION_ERROR', 'INVALID_RESPONSE', 'INVALID_JSON'):
        return f'ошибка загрузки {s}'
    return s or '-'



