def _finance_all_positive_warning(positive_count, negative_count):
    if positive_count > 0 and negative_count == 0:
        return 'Все deduction за период положительные. Нужно проверить по типам операций, являются ли они удержанием или начислением WB.'
    return None


async def finance_deduction_command(update, context, period_name, days, user):
    if not await access(update, 'report'):
        return
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    period_sql, params = _finance_period_clause(days)
    base_params = [user] + params

    cur.execute(
        "SELECT COUNT(*) FROM finance_raw_audit WHERE telegram_id=?" + period_sql,
        base_params
    )
    raw_count = int(cur.fetchone()[0] or 0)
    if raw_count == 0:
        conn.close()
        await update.message.reply_text(_finance_empty_raw_audit_text())
        return

    cur.execute(
        "SELECT report_date, rrd_id, deduction, supplier_article, nm_id, srid, "
        "doc_type_name, operation_type, payment_type, bonus_type_name, subject_name, brand_name "
        "FROM finance_raw_audit WHERE telegram_id=? AND COALESCE(deduction,0)!=0" + period_sql + " "
        "ORDER BY ABS(deduction) DESC, report_date DESC, id DESC LIMIT 20",
        base_params
    )
    rows = cur.fetchall()
    cur.execute(
        "SELECT "
        "SUM(CASE WHEN deduction > 0 THEN 1 ELSE 0 END), "
        "SUM(CASE WHEN deduction < 0 THEN 1 ELSE 0 END) "
        "FROM finance_raw_audit WHERE telegram_id=? AND COALESCE(deduction,0)!=0" + period_sql,
        base_params
    )
    counts = cur.fetchone() or (0, 0)
    conn.close()

    lines = [f'FINANCE DEDUCTION ({period_name})', '']
    lines.extend(_finance_deduction_disclaimer_lines())
    warning = _finance_all_positive_warning(int(counts[0] or 0), int(counts[1] or 0))
    if warning:
        lines.extend(['', warning])
    lines.append('')
    if not rows:
        lines.append('В raw audit есть данные за период, но строк с deduction != 0 не найдено.')
        await send_long(update, '\n'.join(lines))
        return

    for idx, row in enumerate(rows, 1):
        (
            report_date, rrd_id, deduction, supplier_article, nm_id, srid,
            doc_type_name, operation_type, payment_type, bonus_type_name,
            subject_name, brand_name
        ) = row
        lines.extend([
            f'{idx}. {report_date} | rrd_id {rrd_id} | deduction raw {money(deduction)}',
            f'supplier_article: {_finance_text_value(supplier_article)}',
            f'nm_id: {_finance_text_value(nm_id)}',
            f'srid: {_finance_text_value(srid)}',
            f'doc_type_name: {_finance_text_value(doc_type_name)}',
            f'operation_type: {_finance_text_value(operation_type)}',
            f'payment_type: {_finance_text_value(payment_type)}',
            f'bonus_type_name: {_finance_text_value(bonus_type_name)}',
            f'subject_name: {_finance_text_value(subject_name)}',
            f'brand_name: {_finance_text_value(brand_name)}',
            '',
        ])
    await send_long(update, '\n'.join(lines).strip())


