async def finance_deductionstats_command(update, context, period_name, days, user):
    if not await access(update, 'report'):
        return
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    period_sql, params = _finance_period_clause(days)
    base_params = [user] + params

    cur.execute(
        "SELECT COUNT(*) FROM finance_raw_audit WHERE telegram_id=?" + period_sql,
        base_params
    )
    raw_count = int(cur.fetchone()[0] or 0)
    if raw_count == 0:
        conn.close()
        await update.message.reply_text(_finance_empty_raw_audit_text())
        return

    cur.execute(
        "SELECT "
        "SUM(CASE WHEN deduction > 0 THEN 1 ELSE 0 END), "
        "SUM(CASE WHEN deduction < 0 THEN 1 ELSE 0 END) "
        "FROM finance_raw_audit WHERE telegram_id=? AND COALESCE(deduction,0)!=0" + period_sql,
        base_params
    )
    counts = cur.fetchone() or (0, 0)

    group_fields = [
        ('operation_type', 'operation_type'),
        ('payment_type', 'payment_type'),
        ('doc_type_name', 'doc_type_name'),
        ('bonus_type_name', 'bonus_type_name'),
        ('supplier_article', 'supplier_article'),
    ]
    lines = [f'FINANCE DEDUCTIONSTATS ({period_name})', '']
    lines.extend(_finance_deduction_disclaimer_lines())
    warning = _finance_all_positive_warning(int(counts[0] or 0), int(counts[1] or 0))
    if warning:
        lines.extend(['', warning])

    for field_name, label in group_fields:
        cur.execute(
            "SELECT COALESCE(NULLIF(TRIM(" + field_name + "), ''), '-'), "
            "COALESCE(SUM(deduction),0), COALESCE(SUM(ABS(deduction)),0), COUNT(*) "
            "FROM finance_raw_audit WHERE telegram_id=? AND COALESCE(deduction,0)!=0" + period_sql + " "
            "GROUP BY COALESCE(NULLIF(TRIM(" + field_name + "), ''), '-') "
            "ORDER BY COALESCE(SUM(ABS(deduction)),0) DESC, 1 ASC LIMIT 10",
            base_params
        )
        rows = cur.fetchall()
        lines.extend(['', f'By {label}:'])
        if not rows:
            lines.append('Нет строк с deduction != 0.')
            continue
        for value, raw_sum, abs_sum, row_count in rows:
            lines.append(
                f'{value} | raw_sum {money(raw_sum)} | abs_sum {money(abs_sum)} | rows {row_count}'
            )

    conn.close()
    await send_long(update, '\n'.join(lines).strip())


