async def finance_biggestdeductions_command(update, context, period_name, days, user):
    if not await access(update, 'report'):
        return
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    period_sql, params = _finance_period_clause(days)
    base_params = [user] + params

    cur.execute(
        "SELECT COUNT(*) FROM finance_raw_audit WHERE telegram_id=?" + period_sql,
        base_params
    )
    raw_count = int(cur.fetchone()[0] or 0)
    if raw_count == 0:
        conn.close()
        await update.message.reply_text(_finance_empty_audit_text())
        return

    cur.execute(
        "SELECT report_date, rrd_id, deduction, operation_type, payment_type, supplier_article, nm_id "
        "FROM finance_raw_audit WHERE telegram_id=? AND COALESCE(deduction,0)!=0" + period_sql + " "
        "ORDER BY ABS(deduction) DESC, report_date DESC, id DESC LIMIT 20",
        base_params
    )
    rows = cur.fetchall()
    conn.close()

    lines = [f'FINANCE BIGGEST DEDUCTIONS ({period_name})', '']
    if not rows:
        lines.append('В raw audit есть данные за период, но строк с deduction != 0 не найдено.')
        await send_long(update, '\n'.join(lines))
        return

    for idx, row in enumerate(rows, 1):
        report_date, rrd_id, deduction, operation_type, payment_type, supplier_article, nm_id = row
        lines.extend([
            f'{idx}. {report_date} | RRD_ID {rrd_id} | Deduction {money(deduction)}',
            f'operation_type: {_finance_text_value(operation_type)}',
            f'payment_type: {_finance_text_value(payment_type)}',
            f'supplier_article: {_finance_text_value(supplier_article)}',
            f'nm_id: {_finance_text_value(nm_id)}',
            '',
        ])
    await send_long(update, '\n'.join(lines).strip())


async def finance_promotionaudit_command(update, context, period_name, days, user):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    period_sql, params = _finance_period_clause(days)
    base_params = [user] + params

    cur.execute(
        "SELECT report_date, rrd_id, deduction, doc_type_name, operation_type, payment_type, "
        "bonus_type_name, subject_name, brand_name "
        "FROM finance_raw_audit WHERE telegram_id=? AND COALESCE(deduction,0)!=0" + period_sql + " "
        "ORDER BY report_date DESC, id DESC",
        base_params
    )
    raw_rows = [dict(row) for row in cur.fetchall()]

    matched_groups = {}
    matched_sum_abs = 0.0
    matched_raw_sum = 0.0
    remaining_deduction_abs = 0.0
    for row in raw_rows:
        amount = float(row.get('deduction') or 0)
        if _finance_is_promotion_row(row):
            descriptor_parts = _finance_promotion_descriptor_parts(row)
            descriptor = ' | '.join(f'{name}: {value}' for name, value in descriptor_parts) or '-'
            doc_value = _finance_text_value(row.get('doc_type_name'))
            key = (str(row.get('report_date') or '')[:10], doc_value, descriptor, '+' if amount > 0 else '-' if amount < 0 else '0')
            bucket = matched_groups.setdefault(key, {'sum_abs': 0.0, 'rows': 0})
            bucket['sum_abs'] += abs(amount)
            bucket['rows'] += 1
            matched_sum_abs += abs(amount)
            matched_raw_sum += amount
        else:
            remaining_deduction_abs += abs(amount)

    daily_promo = {}
    for (report_date, _doc, _descriptor, _sign), bucket in matched_groups.items():
        daily_promo[report_date] = round(daily_promo.get(report_date, 0.0) + float(bucket['sum_abs'] or 0), 2)

    cur.execute(
        "SELECT advert_date, COALESCE(SUM(spend),0) "
        "FROM advertising WHERE telegram_id=?" + _finance_period_clause(days, 'advert_date')[0] + " "
        "GROUP BY advert_date ORDER BY advert_date",
        [user] + _finance_period_clause(days, 'advert_date')[1]
    )
    ad_daily_rows = cur.fetchall()
    conn.close()

    advertising_sum = round(sum(float(row[1] or 0) for row in ad_daily_rows), 2)
    ad_daily = {str(row[0] or '')[:10]: round(float(row[1] or 0), 2) for row in ad_daily_rows}
    overlap_rows = []
    for report_date, promo_sum in sorted(daily_promo.items()):
        ad_sum = ad_daily.get(report_date)
        if ad_sum is None:
            continue
        if abs(float(ad_sum) - float(promo_sum)) <= 1:
            overlap_rows.append((report_date, promo_sum, ad_sum))

    sorted_groups = sorted(
        matched_groups.items(),
        key=lambda item: (float(item[1]['sum_abs'] or 0), item[0][0]),
        reverse=True
    )
    lines = [f'FINANCE PROMOTIONAUDIT ({period_name})', '']
    if sorted_groups:
        lines.append('Операции, содержащие продвижение / promotion / advert / реклама:')
        lines.append('')
        for (report_date, doc_value, descriptor, sign), bucket in sorted_groups[:50]:
            lines.append(f'дата: {report_date or "-"}')
            lines.append(f'документ: {doc_value or "-"}')
            lines.append(f'descriptor: {descriptor}')
            lines.append(f'сумма: {money(bucket["sum_abs"])}')
            lines.append(f'знак: {sign}')
            lines.append(f'количество строк: {int(bucket["rows"] or 0)}')
            lines.append('')
    else:
        lines.append('Локальных promotion-операций в finance_raw_audit за период не найдено.')
        lines.append('')

    lines.extend([
        'Итоги:',
        f'сумма рекламы из Advertising API: {money(advertising_sum)}',
        f'сумма WB Продвижение из finance audit: {money(matched_sum_abs)}',
        f'сумма остальных deduction: {money(remaining_deduction_abs)}',
        '',
        'Проверка пересечения:',
    ])
    if overlap_rows:
        lines.append('Найдены совпадения по дате и сумме с локальной рекламой:')
        for report_date, promo_sum, ad_sum in overlap_rows[:10]:
            lines.append(f'{report_date}: WB Продвижение {money(promo_sum)} | Advertising API {money(ad_sum)}')
        lines.extend([
            '',
            'Вариант Б:',
            'WB Продвижение уже учтено в Advertising API и возникает двойной учёт.',
            'Это вывод по best-effort сопоставлению локальных дат и сумм, не по прямому document id.',
        ])
    else:
        lines.extend([
            'Прямого пересечения по document id локальная схема не хранит.',
            'Точных совпадений по дате и сумме с Advertising API не найдено.',
            '',
            'Вариант А:',
            'WB Продвижение не входит в Advertising API.',
        ])
    await send_long(update, '\n'.join(lines))


async def finance_promotiondetail_command(update, context, period_name, days, user):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    period_sql, params = _finance_period_clause(days)
    base_params = [user] + params
    cur.execute(
        "SELECT report_date, rrd_id, deduction, raw_json, doc_type_name, operation_type, payment_type, bonus_type_name "
        "FROM finance_raw_audit WHERE telegram_id=?" + period_sql + " "
        "ORDER BY report_date DESC, id DESC",
        base_params
    )
    db_rows = [dict(row) for row in cur.fetchall()]
    conn.close()

    matched = []
    raw_sum = 0.0
    positive_count = 0
    negative_count = 0
    for row in db_rows:
        try:
            raw_row = json.loads(row.get('raw_json') or '{}')
        except Exception:
            raw_row = {}
        if not isinstance(raw_row, dict):
            raw_row = {}
        if not _finance_promotion_row_from_raw(raw_row, row):
            continue

        raw_value = float(row.get('deduction') or 0)
        raw_sum += raw_value
        if raw_value > 0:
            positive_count += 1
            sign = '+'
        elif raw_value < 0:
            negative_count += 1
            sign = '-'
        else:
            sign = '0'

        if raw_value != 0:
            classification = 'expense'
            reason = 'Текущий код finance считает поле deduction частью блока other и добавляет его в расход через abs(deduction).'
        else:
            classification = 'ignored'
            reason = 'Поле deduction равно 0, поэтому текущая формула other эту строку не учитывает через deduction.'

        descriptor_parts = []
        descriptor_field_names = (
            'supplier_oper_name', 'supplierOperName', 'operation', 'operation_name', 'operationName',
            'operation_type', 'operationType', 'doc_type_name', 'docTypeName', 'docType',
            'payment_type', 'paymentType', 'bonus_type_name', 'bonusTypeName', 'category', 'category_name', 'categoryName',
            'subject_name', 'brand_name'
        )
        fallback_values = {
            'operation_type': row.get('operation_type'),
            'doc_type_name': row.get('doc_type_name'),
            'payment_type': row.get('payment_type'),
            'bonus_type_name': row.get('bonus_type_name'),
        }
        for field_name in descriptor_field_names:
            value = raw_row.get(field_name)
            if value in (None, ''):
                value = fallback_values.get(field_name)
            if value not in (None, ''):
                descriptor_parts.append((field_name, str(value)))

        money_fields = []
        seen_money_fields = set()
        preferred_money_fields = (
            'income', 'deduction', 'amount', 'payout', 'delivery_rub', 'bonus', 'penalty', 'supplier_reward'
        )

        def _append_money_field(field_name, raw_field_value):
            if field_name in seen_money_fields or raw_field_value in (None, ''):
                return
            if isinstance(raw_field_value, bool):
                return
            try:
                field_value = float(raw_field_value)
            except Exception:
                return
            money_fields.append((field_name, field_value))
            seen_money_fields.add(field_name)

        for field_name in preferred_money_fields:
            _append_money_field(field_name, raw_row.get(field_name))

        for field_name, raw_field_value in raw_row.items():
            _append_money_field(field_name, raw_field_value)

        matched.append({
            'date': str(raw_row.get('date') or raw_row.get('rr_dt') or raw_row.get('sale_dt') or row.get('report_date') or '')[:10],
            'document': _finance_text_value(
                raw_row.get('doc_type_name')
                or raw_row.get('docTypeName')
                or raw_row.get('docType')
                or raw_row.get('doc_type')
                or row.get('doc_type_name')
            ),
            'descriptor': ' | '.join(f'{field_name}: {field_value}' for field_name, field_value in descriptor_parts) or '-',
            'descriptor_parts': descriptor_parts,
            'money_fields': money_fields,
            'raw_value': raw_value,
            'sign': sign,
            'classification': classification,
            'reason': reason,
        })
        if len(matched) >= 20:
            break

    lines = [f'FINANCE PROMOTIONDETAIL ({period_name})', '']
    if not matched:
        lines.append('Строки promotion / advert / реклама в finance_raw_audit не найдены.')
        await send_long(update, '\n'.join(lines))
        return

    for index, item in enumerate(matched, start=1):
        lines.append(f'{index}. date: {item["date"] or "-"}')
        lines.append(f'document: {item["document"]}')
        lines.append(f'descriptor: {item["descriptor"]}')
        if item['money_fields']:
            lines.append('money fields:')
            for field_name, field_value in item['money_fields']:
                lines.append(f'{field_name}: {money(field_value)}')
        else:
            lines.append('money fields: нет')
        lines.append(f'raw value: {money(item["raw_value"])}')
        lines.append(f'знак: {item["sign"]}')
        lines.append(f'как сейчас классифицируется системой: {item["classification"]}')
        lines.append(f'почему: {item["reason"]}')
        lines.append('')

    if raw_sum > 0:
        source_text = 'По знаку raw_sum это больше похоже на начисление WB.'
    elif raw_sum < 0:
        source_text = 'По знаку raw_sum это больше похоже на удержание WB.'
    else:
        source_text = 'По знаку raw_sum определить источник нельзя: сумма близка к нулю.'
    lines.extend([
        f'Итоговый raw_sum: {money(raw_sum)}',
        f'Положительных строк: {positive_count}',
        f'Отрицательных строк: {negative_count}',
        source_text,
        'Это диагностический вывод. Расчёты прибыли и расходов не изменялись.',
    ])
    await send_long(update, '\n'.join(lines))


async def finance_promotionraw_command(update, context, period_name, days, user):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    period_sql, params = _finance_period_clause(days)
    base_params = [user] + params
    cur.execute(
        "SELECT report_date, deduction, raw_json, doc_type_name, operation_type, payment_type, bonus_type_name, subject_name, brand_name "
        "FROM finance_raw_audit WHERE telegram_id=?" + period_sql + " "
        "ORDER BY report_date DESC, id DESC",
        base_params
    )
    db_rows = [dict(row) for row in cur.fetchall()]
    conn.close()

    totals = {'deduction': 0.0, 'income': 0.0, 'amount': 0.0, 'bonus': 0.0}
    matched = []
    detail_fields = (
        'descriptor', 'type', 'category', 'operation', 'operationType', 'operation_type',
        'bonus_type_name', 'bonusTypeName', 'docType', 'docTypeName', 'doc_type_name',
        'supplier_oper_name', 'supplierOperName', 'payment_type', 'paymentType'
    )
    important_fields = (
        'deduction', 'income', 'amount', 'payout', 'supplier_reward', 'bonus', 'penalty', 'delivery_rub'
    )

    for row in db_rows:
        try:
            raw_row = json.loads(row.get('raw_json') or '{}')
        except Exception:
            raw_row = {}
        if not isinstance(raw_row, dict):
            raw_row = {}
        if not _finance_promotion_row_from_raw(raw_row, row):
            continue

        numeric_fields = []
        for field_name, raw_value in raw_row.items():
            if isinstance(raw_value, bool) or raw_value in (None, ''):
                continue
            try:
                numeric_value = float(raw_value)
            except Exception:
                continue
            numeric_fields.append((field_name, numeric_value))

        string_fields = []
        for field_name in detail_fields:
            raw_value = raw_row.get(field_name)
            if raw_value in (None, ''):
                raw_value = row.get(field_name)
            if raw_value not in (None, ''):
                string_fields.append((field_name, str(raw_value)))

        for total_field in totals:
            raw_value = raw_row.get(total_field)
            if raw_value in (None, '') and total_field == 'deduction':
                raw_value = row.get('deduction')
            try:
                totals[total_field] += float(raw_value or 0)
            except Exception:
                pass

        pretty_json = json.dumps(raw_row, ensure_ascii=False, indent=2, sort_keys=True)
        matched.append({
            'date': str(raw_row.get('date') or raw_row.get('rr_dt') or raw_row.get('sale_dt') or row.get('report_date') or '')[:10],
            'document': _finance_text_value(
                raw_row.get('doc_type_name')
                or raw_row.get('docTypeName')
                or raw_row.get('docType')
                or raw_row.get('doc_type')
                or row.get('doc_type_name')
            ),
            'keys': sorted(str(key) for key in raw_row.keys()),
            'numeric_fields': numeric_fields,
            'string_fields': string_fields,
            'important_values': [(field_name, raw_row.get(field_name) if raw_row.get(field_name) not in (None, '') else row.get(field_name)) for field_name in important_fields if (raw_row.get(field_name) not in (None, '') or row.get(field_name) not in (None, ''))],
            'pretty_json': pretty_json[:3000],
        })
        if len(matched) >= 20:
            break

    lines = [f'FINANCE PROMOTIONRAW ({period_name})', '']
    if not matched:
        lines.append('Строки promotion / advert / реклама в finance_raw_audit не найдены.')
        await send_long(update, '\n'.join(lines))
        return

    for index, item in enumerate(matched, start=1):
        lines.append(f'{index}. date: {item["date"] or "-"}')
        lines.append(f'document: {item["document"]}')
        lines.append(f'raw_json keys: {", ".join(item["keys"]) if item["keys"] else "-"}')
        lines.append('string fields:')
        if item['string_fields']:
            for field_name, field_value in item['string_fields']:
                lines.append(f'{field_name}: {field_value}')
        else:
            lines.append('нет')
        lines.append('numeric fields:')
        if item['numeric_fields']:
            for field_name, field_value in item['numeric_fields']:
                lines.append(f'{field_name}: {money(field_value)}')
        else:
            lines.append('нет')
        lines.append('selected fields:')
        if item['important_values']:
            for field_name, field_value in item['important_values']:
                try:
                    lines.append(f'{field_name}: {money(float(field_value or 0))}')
                except Exception:
                    lines.append(f'{field_name}: {field_value}')
        else:
            lines.append('нет')
        lines.append('pretty json:')
        lines.append(item['pretty_json'] or '{}')
        lines.append('')

    lines.extend([
        f'количество строк: {len(matched)}',
        f'сумма deduction: {money(totals["deduction"])}',
        f'сумма income: {money(totals["income"])}',
        f'сумма amount: {money(totals["amount"])}',
        f'сумма bonus: {money(totals["bonus"])}',
    ])
    await send_long(update, '\n'.join(lines))


