async def finance_breakdown_command(update, context, period_name, days, user):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    analysis = _finance_local_expenses_analysis(user, days)
    st = analysis.get('st') or get_profit_stats(days, user)
    revenue = float(st[0] or 0)
    payout = float(st[2] or 0)
    difference_wb = float(st[1] or 0)

    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    period_sql, params = _finance_period_clause(days)
    base_params = [user] + params
    cur.execute(
        "SELECT report_date, deduction, raw_json, doc_type_name, bonus_type_name, operation_type, payment_type "
        "FROM finance_raw_audit WHERE telegram_id=?" + period_sql + " "
        "ORDER BY report_date DESC, id DESC",
        base_params
    )
    db_rows = [dict(row) for row in cur.fetchall()]
    conn.close()

    promotion_total = 0.0
    ppvz_sales_commission_abs = 0.0
    ppvz_reward_abs = 0.0
    supplier_reward_abs = 0.0
    raw_commission_candidates_abs = 0.0

    for row in db_rows:
        try:
            raw_row = json.loads(row.get('raw_json') or '{}')
        except Exception:
            raw_row = {}
        if not isinstance(raw_row, dict):
            raw_row = {}

        if _finance_promotion_row_from_raw(raw_row, row):
            promotion_total += abs(float(row.get('deduction') or raw_row.get('deduction') or 0))

        commission_value, has_commission_fields = _finance_commission_value_from_raw(raw_row)
        if has_commission_fields:
            raw_commission_candidates_abs += abs(float(commission_value or 0))

        for field_name, bucket_name in (
            ('ppvz_sales_commission', 'ppvz_sales_commission_abs'),
            ('ppvz_reward', 'ppvz_reward_abs'),
            ('supplier_reward', 'supplier_reward_abs'),
        ):
            raw_value = raw_row.get(field_name)
            if raw_value in (None, ''):
                continue
            try:
                numeric_value = abs(float(raw_value or 0))
            except Exception:
                continue
            if bucket_name == 'ppvz_sales_commission_abs':
                ppvz_sales_commission_abs += numeric_value
            elif bucket_name == 'ppvz_reward_abs':
                ppvz_reward_abs += numeric_value
            elif bucket_name == 'supplier_reward_abs':
                supplier_reward_abs += numeric_value

    ppvz_total = round(ppvz_sales_commission_abs + ppvz_reward_abs + supplier_reward_abs, 2)
    logistics = float(analysis.get('logistics') or 0)
    storage = float(analysis.get('storage') or 0)
    acquiring = float(analysis.get('acquiring') or 0)
    advertising = float(analysis.get('advertising') or 0)
    other_local = float(analysis.get('other_local') or 0)
    promotion_total = round(float(promotion_total or 0), 2)
    raw_commission_candidates_abs = round(float(raw_commission_candidates_abs or 0), 2)

    explained_total = round(
        logistics +
        storage +
        acquiring +
        promotion_total +
        advertising +
        ppvz_total +
        other_local,
        2
    )
    unexplained_difference = round(difference_wb - explained_total, 2)

    components = [
        ('Логистика', logistics),
        ('Хранение', storage),
        ('Эквайринг', acquiring),
        ('WB Продвижение', promotion_total),
        ('PPVZ', ppvz_total),
        ('Реклама', advertising),
        ('Прочее', other_local),
    ]

    def _pct(value, total):
        return (float(value or 0) / float(total) * 100) if total else 0.0

    lines = [
        f'FINANCE BREAKDOWN ({period_name})',
        '',
        'РАСЧЁТНАЯ РАЗНИЦА WB',
        '',
        f'Выручка: {money(revenue)}',
        f'К выплате: {money(payout)}',
        f'Разница WB: {money(difference_wb)}',
        '',
        'Состав:',
    ]

    for name, amount in components:
        lines.append(f'{name} .......... {money(amount)} ({_pct(amount, difference_wb):.1f}%)')

    lines.extend([
        '',
        f'Raw commission candidates: {money(raw_commission_candidates_abs)} ({_pct(raw_commission_candidates_abs, difference_wb):.1f}%)',
        f'Необъяснённый остаток: {money(unexplained_difference)}',
        '',
        'ТОП ПОТЕРЬ',
        '',
    ])

    top_losses = sorted(components, key=lambda item: item[1], reverse=True)
    for index, (name, amount) in enumerate(top_losses[:5], start=1):
        lines.append(f'{index}. {name} ....... {money(amount)}')

    lines.extend([
        '',
        'Доля расходов от выручки:',
        f'Логистика .... {_pct(logistics, revenue):.1f}%',
        f'Продвижение .. {_pct(promotion_total, revenue):.1f}%',
        f'Реклама ...... {_pct(advertising, revenue):.1f}%',
        f'Эквайринг .... {_pct(acquiring, revenue):.1f}%',
        f'Хранение ..... {_pct(storage, revenue):.1f}%',
        '',
        'Отдельные raw суммы за период:',
        f'ppvz_sales_commission: {money(ppvz_sales_commission_abs)}',
        f'ppvz_reward: {money(ppvz_reward_abs)}',
        f'supplier_reward: {money(supplier_reward_abs)}',
        f'raw commission candidates: {money(raw_commission_candidates_abs)}',
        '',
        'Это аналитическая команда. БД, прибыль, налог, реклама, отчёты и формулы не изменялись.',
    ])
    await send_long(update, '\n'.join(lines))


async def finance_sku_losses_command(update, context, period_name, days, user):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    worst_rows = get_top_profit_skus(user, days, limit=20, order='ASC')
    best_rows = get_top_profit_skus(user, days, limit=20, order='DESC')

    if not worst_rows and not best_rows:
        await update.message.reply_text(f'Нет данных по SKU за период {period_name}.')
        return

    def _flags(row):
        flags = []
        revenue = float(row.get('revenue') or 0)
        logistics = float(row.get('logistics') or 0)
        profit = float(row.get('profit_before_tax') or 0)
        margin = float(row.get('margin') or 0)
        logistics_share = (logistics / revenue * 100) if revenue else 0.0
        if logistics_share > 20:
            flags.append('логистика > 20%')
        if margin < 10:
            flags.append('маржа < 10%')
        if profit < 0:
            flags.append('убыток < 0')
        return logistics_share, flags

    lines = [f'FINANCE SKU LOSSES ({period_name})', '']
    lines.append('ТОП-20 самых убыточных SKU')
    lines.append('')
    for index, row in enumerate(worst_rows, start=1):
        logistics_share, flags = _flags(row)
        lines.append(f'{index}. {row["article"]}')
        lines.append(f'продажи: {int(row.get("sales_count") or 0)}')
        lines.append(f'выручка: {money(row["revenue"])}')
        lines.append(f'себестоимость: {money(row["cost"])}')
        lines.append(f'логистика: {money(row["logistics"])}')
        lines.append(f'доля логистики от выручки: {logistics_share:.1f}%')
        lines.append(f'реклама: {money(row["advertising"])}')
        lines.append(f'прибыль: {money(row["profit_before_tax"])}')
        lines.append(f'маржа %: {row["margin"]:.1f}%')
        if flags:
            lines.append('подсветка: ' + ', '.join(flags))
        lines.append('')

    lines.append('ТОП-20 самых прибыльных SKU')
    lines.append('')
    for index, row in enumerate(best_rows, start=1):
        logistics_share, flags = _flags(row)
        lines.append(f'{index}. {row["article"]}')
        lines.append(f'продажи: {int(row.get("sales_count") or 0)}')
        lines.append(f'выручка: {money(row["revenue"])}')
        lines.append(f'себестоимость: {money(row["cost"])}')
        lines.append(f'логистика: {money(row["logistics"])}')
        lines.append(f'доля логистики от выручки: {logistics_share:.1f}%')
        lines.append(f'реклама: {money(row["advertising"])}')
        lines.append(f'прибыль: {money(row["profit_before_tax"])}')
        lines.append(f'маржа %: {row["margin"]:.1f}%')
        if flags:
            lines.append('подсветка: ' + ', '.join(flags))
        lines.append('')

    lines.append('Это аналитическая команда. БД и расчёты не изменялись.')
    await send_long(update, '\n'.join(lines))


async def _legacy_finance_trace_command_v1(update, context, user, trace_date):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return
    try:
        datetime.strptime(str(trace_date), '%Y-%m-%d')
    except Exception:
        await update.message.reply_text('РСЃРїРѕР»СЊР·СѓР№С‚Рµ С„РѕСЂРјР°С‚: /finance trace YYYY-MM-DD')
        return

    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    cur.execute(
        "SELECT id, expense_date, amount, telegram_id, source, comment, created_at, "
        "COALESCE(supplier_article,'-'), unique_key "
        "FROM expenses "
        "WHERE telegram_id=? AND expense_type='other' AND substr(expense_date,1,10)=? "
        "ORDER BY amount DESC, id DESC",
        (user, trace_date)
    )
    rows = cur.fetchall()

    parser_fields = [
        'penalty',
        'deduction',
        'acceptance',
        'acceptance_fee',
        'acceptanceFee',
        'additional_payment',
        'additionalPayment',
        'acquiring_fee',
        'acquiringFee',
    ]
    lines = [f'FINANCE TRACE {trace_date}', '']
    if not rows:
        conn.close()
        lines.append('Локальных записей other за эту дату не найдено.')
        await send_long(update, '\n'.join(lines))
        return

    if len(rows) > 20:
        lines.append('Показано много строк. Для чтения удобнее использовать /finance topother month.')
        lines.append('')

    lines.append('Найденные записи other в локальной БД:')
    lines.append('')
    for row_id, expense_date, amount, telegram_id, source, comment, created_at, article, unique_key in rows:
        rrd_id = str(unique_key or '').split(':')[-2] if unique_key and ':' in unique_key else '-'
        lines.append(f'id: {row_id}')
        lines.append(f'expense_date: {expense_date}')
        lines.append(f'amount: {money(amount)}')
        lines.append(f'user_id: {telegram_id}')
        lines.append(f'source: {source}')
        lines.append(f'comment: {comment}')
        lines.append(f'created_at: {created_at}')
        lines.append(f'supplier_article: {article}')
        lines.append(f'unique_key: {unique_key}')
        lines.append(f'rrd_id: {rrd_id}')
        lines.append('')

        cur.execute(
            "SELECT id, expense_type, amount, COALESCE(supplier_article,'-'), COALESCE(comment,'-'), unique_key "
            "FROM expenses "
            "WHERE telegram_id=? AND substr(expense_date,1,10)=? AND unique_key LIKE ? "
            "ORDER BY expense_type, id",
            (user, trace_date, f'finance:{user}:{rrd_id}:%')
        )
        related_rows = cur.fetchall()
        lines.append(f'Расходы по rrd_id {rrd_id}:')
        lines.append(f'Количество строк: {len(related_rows)}')
        if related_rows:
            totals = {'logistics': 0.0, 'storage': 0.0, 'advertising': 0.0, 'other': 0.0}
            for rel_id, expense_type, rel_amount, rel_article, rel_comment, rel_key in related_rows:
                lines.append(
                    f'id: {rel_id} | expense_type: {expense_type} | amount: {money(rel_amount)} | '
                    f'supplier_article: {rel_article} | comment: {rel_comment} | unique_key: {rel_key}'
                )
                if expense_type in totals:
                    totals[expense_type] += float(rel_amount or 0)
            total_sum = sum(totals.values())
            lines.append('')
            lines.append(f'Логистика: {money(totals["logistics"])}')
            lines.append(f'Хранение: {money(totals["storage"])}')
            lines.append(f'Реклама: {money(totals["advertising"])}')
            lines.append(f'Прочее: {money(totals["other"])}')
            lines.append(f'Всего: {money(total_sum)}')
        else:
            lines.append('Связанные строки expenses с этим rrd_id не найдены.')
        lines.append('')

    lines.append('Что можно установить локально:')
    lines.append('Запись сформирована загрузчиком load_finance_expenses() из WB Finance API.')
    lines.append('Для блока other parser суммирует через abs() следующие поля:')
    for field_name in parser_fields:
        lines.append(f'- {field_name}')
    lines.append('')
    lines.append('Ограничение локального аудита:')
    lines.append('БД хранит уже агрегированную сумму other по строке WB Finance и не хранит разложение по отдельным полям WB.')
    lines.append('Поэтому без raw-ответа WB API или отдельного журнала payload нельзя точно доказать, какое из полей дало эту сумму.')
    conn.close()
    await send_long(update, '\n'.join(lines))


async def adsfullstatsprobe_command(update, context):
    from vooglii_telegram.handlers.legacy import adsfullstatsprobe_command as _impl
    return await _impl(update, context)


async def _adsfullstatsprobe_command_entry(update, context):
    if not admin(update):
        await update.message.reply_text('Команда доступна только ADMIN_IDS.')
        return

    user = uid(update)
    token = get_user_token(user)
    if not token:
        await update.message.reply_text('WB API РЅРµ РїРѕРґРєР»СЋС‡РµРЅ. РСЃРїРѕР»СЊР·СѓР№С‚Рµ /connect')
        return

    campaign_id = context.args[0].strip() if context.args else None
    if not campaign_id:
        campaign_id = _latest_local_campaign_id(user)
    if not campaign_id:
        await update.message.reply_text('Локальный campaign_id не найден. Используйте /adsfullstatsprobe ID')
        return

    today = datetime.now().strftime('%Y-%m-%d')
    url = 'https://advert-api.wildberries.ru/adv/v3/fullstats'
    params = {'ids': str(campaign_id), 'begin': today, 'end': today}

    try:
        _log_ads_token_debug(token, 'db.users.wb_token')
        response = httpx.get(url, headers={'Authorization': token}, params=params, timeout=20)
        body = (response.text or '')[:3000]
        lines = [
            'ADS FULLSTATS PROBE',
            f'url: {response.request.url}',
            f'params: {params}',
            f'status_code: {response.status_code}',
            f'x-ratelimit-retry: {response.headers.get("x-ratelimit-retry", "-")}',
            f'x-ratelimit-limit: {response.headers.get("x-ratelimit-limit", "-")}',
            f'x-ratelimit-reset: {response.headers.get("x-ratelimit-reset", "-")}',
            '',
            body or '<empty>',
        ]
        await send_long(update, '\n'.join(lines))
    except httpx.TimeoutException:
        await update.message.reply_text('ADS FULLSTATS PROBE\nОшибка: timeout')
    except Exception:
        logger.exception('adsfullstatsprobe failed')
        await update.message.reply_text('ADS FULLSTATS PROBE\nОшибка выполнения. Подробности записаны в лог сервера.')


async def adsinspect_command(update, context):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    token = get_user_token(uid(update))
    if not token:
        await update.message.reply_text('WB API не подключен. Используйте /connect')
        return

    campaign_id = context.args[1].strip() if len(context.args) > 1 else None
    if not campaign_id:
        campaign_id = _latest_local_campaign_id(uid(update))
    if not campaign_id:
        await update.message.reply_text('Локальный campaign_id не найден. Используйте /ads inspect ID')
        return
    try:
        campaign_id = int(campaign_id)
    except Exception:
        await update.message.reply_text('campaign_id должен быть числом. Используйте /ads inspect ID')
        return

    today = datetime.now().strftime('%Y-%m-%d')
    contract = inspect_fullstats_contract([campaign_id], today, today)
    current = contract['current_contract']
    alternative = contract['alternative_contract']
    post_payload = alternative['payload_sample']

    try:
        _log_ads_token_debug(token, 'db.users.wb_token')
        response = httpx.post(
            alternative['endpoint'],
            headers={'Authorization': token},
            json=post_payload,
            timeout=20,
        )
        body = response.text or ''
        sample = body[:500] or '<empty>'
        has_invalid_begin = 'Invalid begin date' in body
        lines = [
            'ADS INSPECT',
            '',
            'Текущая реализация _fetch_fullstats_batch()',
            f'HTTP method: {current["method"]}',
            f'endpoint: {current["endpoint"]}',
            'параметры запроса:',
        ]
        for index, params in enumerate(current.get('query_variants') or [], start=1):
            lines.append(f'{index}. {params}')
        lines.extend([
            'структура payload:',
            str(current.get('payload_structure')),
            '',
            'Альтернативная диагностика',
            f'HTTP method: {alternative["method"]}',
            f'endpoint: {alternative["endpoint"]}',
            f'payload structure: {alternative["payload_structure"]}',
            f'payload sample: {post_payload}',
            f'HTTP status: {response.status_code}',
            f'response first 500 chars: {sample}',
        ])
        if not has_invalid_begin:
            lines.extend([
                '',
                'POTENTIALLY WORKING CONTRACT',
                'Ответ отличается от Invalid begin date.',
            ])
        await send_long(update, '\n'.join(lines))
    except httpx.TimeoutException:
        await update.message.reply_text('ADS INSPECT\nОшибка: timeout')
    except Exception:
        logger.exception('adsinspect_command failed')
        await update.message.reply_text('ADS INSPECT\nОшибка выполнения. Подробности записаны в лог сервера.')


async def adsinspect2_command(update, context):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    variant = (context.args[1].strip().upper() if len(context.args) > 1 else '')
    variants = {
        'A': lambda campaign_id, today: {'ids': str(campaign_id), 'dateFrom': today, 'dateTo': today},
        'B': lambda campaign_id, today: {'id': str(campaign_id), 'dateFrom': today, 'dateTo': today},
        'C': lambda campaign_id, today: {'ids': str(campaign_id), 'dates': today},
        'D': lambda campaign_id, today: {'id': str(campaign_id), 'dates': today},
        'E': lambda campaign_id, today: {
            'ids': str(campaign_id),
            'begin': f'{today}T00:00:00+03:00',
            'end': f'{today}T23:59:59+03:00',
        },
        'F': lambda campaign_id, today: {
            'ids': str(campaign_id),
            'begin': f'{today} 00:00:00',
            'end': f'{today} 23:59:59',
        },
    }
    if variant not in variants:
        await update.message.reply_text('Используйте: /ads inspect2 A|B|C|D|E|F')
        return

    token = get_user_token(uid(update))
    if not token:
        await update.message.reply_text('WB API не подключен. Используйте /connect')
        return

    cooldown_row = get_api_cooldown(uid(update), 'advertising') or {}
    if parse_dt(cooldown_row.get('retry_after')) and parse_dt(cooldown_row.get('retry_after')) > datetime.now():
        minutes = _cooldown_minutes_text(cooldown_row)
        await update.message.reply_text(
            'Рекламный API WB находится на cooldown.\n'
            f'Повтор через {minutes} мин.\n'
            'Диагностический запрос не выполнялся.'
        )
        return

    campaign_id = context.args[2].strip() if len(context.args) > 2 else None
    if not campaign_id:
        campaign_id = _latest_local_campaign_id(uid(update))
    if not campaign_id:
        await update.message.reply_text('Локальный campaign_id не найден. Используйте /ads inspect2 A ID')
        return
    try:
        campaign_id = int(campaign_id)
    except Exception:
        await update.message.reply_text('campaign_id должен быть числом. Используйте /ads inspect2 A ID')
        return

    today = datetime.now().strftime('%Y-%m-%d')
    endpoint = 'https://advert-api.wildberries.ru/adv/v3/fullstats'
    params = variants[variant](campaign_id, today)

    try:
        _log_ads_token_debug(token, 'db.users.wb_token')
        response = httpx.get(endpoint, headers={'Authorization': token}, params=params, timeout=20)
        body = response.text or ''
        sample = body[:300] or '<empty>'
        lines = [
            'ADS INSPECT2',
            f'variant: {variant}',
            f'campaign_id: {campaign_id}',
            f'endpoint: {endpoint}',
            f'params: {params}',
            f'HTTP status: {response.status_code}',
            f'response first 300 chars: {sample}',
        ]
        if body.strip() != 'Invalid begin date':
            lines.extend([
                '',
                'POTENTIAL CONTRACT MATCH',
            ])
        await send_long(update, '\n'.join(lines))
    except httpx.TimeoutException:
        await update.message.reply_text('ADS INSPECT2\nОшибка: timeout')
    except Exception:
        logger.exception('adsinspect2_command failed')
        await update.message.reply_text('ADS INSPECT2\nОшибка выполнения. Подробности записаны в лог сервера.')


async def adsinspect3_command(update, context):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    token = get_user_token(uid(update))
    if not token:
        await update.message.reply_text('WB API не подключен. Используйте /connect')
        return

    campaign_id = context.args[1].strip() if len(context.args) > 1 else ''
    if not campaign_id:
        await update.message.reply_text('Используйте: /ads inspect3 <campaign_id>')
        return
    try:
        campaign_id = int(campaign_id)
    except Exception:
        await update.message.reply_text('campaign_id должен быть числом. Используйте /ads inspect3 <campaign_id>')
        return

    today = datetime.now().strftime('%Y-%m-%d')
    endpoint = 'https://advert-api.wildberries.ru/adv/v3/fullstats'
    variants = [
        ('A', {'ids': str(campaign_id), 'begin': today, 'end': today}),
        ('B', {'ids': str(campaign_id), 'begin': f'{today}T00:00:00', 'end': f'{today}T23:59:59'}),
        ('C', {'ids': str(campaign_id), 'begin': f'{today}T00:00:00+03:00', 'end': f'{today}T23:59:59+03:00'}),
        ('D', {'ids': str(campaign_id), 'begin': f'{today}T00:00:00Z', 'end': f'{today}T23:59:59Z'}),
        ('E', {'ids': str(campaign_id), 'dateFrom': today, 'dateTo': today}),
        ('F', [('ids[]', str(campaign_id)), ('begin', today), ('end', today)]),
    ]

    lines = [
        'ADS INSPECT3',
        f'campaign_id: {campaign_id}',
        f'date: {today}',
        '',
    ]
    try:
        for index, (variant, params) in enumerate(variants):
            _log_ads_token_debug(token, 'db.users.wb_token')
            response = httpx.get(endpoint, headers={'Authorization': token}, params=params, timeout=20)
            body = response.text or ''
            sample = body[:300] or '<empty>'
            lines.extend([
                f'variant: {variant}',
                f'endpoint: {endpoint}',
                f'params: {params}',
                f'HTTP status: {response.status_code}',
                f'response first 300 chars: {sample}',
            ])
            if body.strip() != 'Invalid begin date':
                lines.append('POSSIBLE MATCH')
            if response.status_code == 200:
                lines.append('CONTRACT CONFIRMED')
                break
            if index < len(variants) - 1:
                lines.extend(['', 'pause: 3 seconds', ''])
                await asyncio.sleep(3)
            else:
                lines.append('')
        await send_long(update, '\n'.join(lines))
    except httpx.TimeoutException:
        await update.message.reply_text('ADS INSPECT3\nОшибка: timeout')
    except Exception:
        logger.exception('adsinspect3_command failed')
        await update.message.reply_text('ADS INSPECT3\nОшибка выполнения. Подробности записаны в лог сервера.')


async def adslimittest_command(update, context):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    cooldown_row = get_api_cooldown(uid(update), 'advertising') or {}
    if _ads_cooldown_is_active(cooldown_row):
        remaining_seconds = max(0, int(_ads_remaining_seconds(cooldown_row) or 0))
        await update.message.reply_text(
            'Рекламный API сейчас на cooldown.\n'
            f'Следующая безопасная попытка через {rate_text(f"ADS_STEP_COOLDOWN:{remaining_seconds}")}.\n'
            'Limittest не выполнен.'
        )
        return

    token = get_user_token(uid(update))
    if not token:
        await update.message.reply_text('WB API не подключен. Используйте /connect')
        return

    try:
        result = ads_limit_test(token, max_requests=10, token_source='db.users.wb_token')
        count_call = result.get('count_call') or {}
        lines = [
            'ADS LIMITTEST',
            f'date: {result.get("date")}',
            f'max_requests: {result.get("max_requests")}',
            '',
            'promotion/count',
            f'HTTP status: {count_call.get("http_status")}',
            f'sample: {str(count_call.get("sample") or "<empty>")[:300]}',
            '',
        ]
        if count_call.get('status') != 'SUCCESS':
            lines.append('Не удалось получить список campaign_id. Лимит fullstats не проверялся.')
            await send_long(update, '\n'.join(lines))
            return

        for call in result.get('calls') or []:
            lines.extend([
                f'Запрос #{call.get("request_number")} campaign_id={call.get("campaign_id")}',
                f'endpoint: {call.get("endpoint")}',
                f'params: {call.get("params")}',
                f'HTTP status: {call.get("http_status")}',
                f'x-ratelimit-limit: {call.get("x_ratelimit_limit") or "-"}',
                f'x-ratelimit-retry: {call.get("x_ratelimit_retry") or "-"}',
                f'x-ratelimit-reset: {call.get("x_ratelimit_reset") or "-"}',
                f'response first 300 chars: {call.get("sample") or "<empty>"}',
                '',
            ])

        lines.extend([
            'Итог',
            f'Сделано запросов: {result.get("requests_done")}',
            f'HTTP 200: {result.get("status_200")}',
            f'HTTP 400: {result.get("status_400")}',
            f'Первый 429: {result.get("first_429_request") or "не было"}',
            f'Вывод: {result.get("recommendation")}',
        ])
        await send_long(update, '\n'.join(lines))
    except Exception:
        logger.exception('adslimittest_command failed')
        await update.message.reply_text('ADS LIMITTEST\nОшибка выполнения. Подробности записаны в лог сервера.')


