async def _ads_command_entry(update, context):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return

    subcommand = (context.args[0].strip().lower() if context.args else '')
    if subcommand not in ('probe', 'contract', 'inspect', 'inspect2', 'inspect3', 'limittest', 'batchtest', 'periodtest', 'backfill', 'historical', 'historicalaudit', 'applyhistorical', 'duplicateaudit', 'cleanupaudit', 'cleanuphistorical', 'ratelimit', 'resetcooldown', 'levelaudit', 'normalizeaudit', 'compare', 'optimize', 'recommendations', 'summary', 'linkaudit', 'rawaudit', 'nmfixaudit'):
        await update.message.reply_text('Используйте: /ads probe\nили: /ads contract A|B|C|D|E\nили: /ads inspect [ID]\nили: /ads inspect2 A|B|C|D|E|F [ID]\nили: /ads inspect3 <campaign_id>\nили: /ads limittest\nили: /ads batchtest\nили: /ads periodtest\nили: /ads ratelimit\nили: /ads resetcooldown\nили: /ads backfill YYYY-MM-DD YYYY-MM-DD\nили: /ads historical YYYY-MM-DD YYYY-MM-DD\nили: /ads historicalaudit YYYY-MM-DD YYYY-MM-DD\nили: /ads applyhistorical YYYY-MM-DD YYYY-MM-DD\nили: /ads duplicateaudit YYYY-MM-DD YYYY-MM-DD\nили: /ads cleanupaudit YYYY-MM-DD YYYY-MM-DD\nили: /ads cleanuphistorical YYYY-MM-DD YYYY-MM-DD\nили: /ads levelaudit YYYY-MM-DD YYYY-MM-DD\nили: /ads normalizeaudit YYYY-MM-DD YYYY-MM-DD\nили: /ads compare YYYY-MM-DD YYYY-MM-DD\nили: /ads optimize YYYY-MM-DD YYYY-MM-DD\nили: /ads recommendations YYYY-MM-DD YYYY-MM-DD\nили: /ads summary YYYY-MM-DD YYYY-MM-DD\nили: /ads linkaudit YYYY-MM-DD YYYY-MM-DD\nили: /ads rawaudit YYYY-MM-DD YYYY-MM-DD\nили: /ads rawaudit CAMPAIGN_ID YYYY-MM-DD YYYY-MM-DD\nили: /ads nmfixaudit YYYY-MM-DD YYYY-MM-DD')
        return

    if subcommand == 'inspect':
        await adsinspect_command(update, context)
        return

    if subcommand == 'inspect2':
        await adsinspect2_command(update, context)
        return

    if subcommand == 'inspect3':
        await adsinspect3_command(update, context)
        return

    if subcommand == 'limittest':
        await adslimittest_command(update, context)
        return

    if subcommand == 'batchtest':
        await adsbatchtest_command(update, context)
        return

    if subcommand == 'periodtest':
        await adsperiodtest_command(update, context)
        return

    if subcommand == 'ratelimit':
        await adsratelimit_command(update, context)
        return

