    lines.append('')

    lines.append('ALLOCATION METHOD BREAKDOWN')
    for item in snapshot.get('allocation_method_breakdown') or []:
        lines.append(
            f'{item.get("method")}: rows {int(item.get("rows_count") or 0)} | spend {money(item.get("spend_sum") or 0)} | share {float(item.get("share_of_total_spend_percent") or 0):.1f}%'
        )
