def _status_kind(status):
    s = str(status or '')
    if s == 'SUCCESS':
        return 'success'
    if s.startswith('SKIPPED_COOLDOWN') or s.startswith('RATE_LIMIT') or s.startswith('ADS_COOLDOWN') or s.startswith('ADS_STEP_COOLDOWN') or s.startswith('FULLSTATS_429') or s.startswith('ADS_BACKGROUND_THROTTLED'):
        return 'cooldown'
    if s in ('PENDING', 'SKIPPED', ''):
        return 'pending'
    return 'error'


def format_block_status(status, row=None):
    s = str(status or '')
    kind = _status_kind(s)
    if kind == 'success':
        return '✅ актуально'
    if kind == 'cooldown':
        if s.startswith('ADS_COOLDOWN') or s.startswith('ADS_STEP_COOLDOWN') or s.startswith('FULLSTATS_429_SAFE_COOLDOWN'):
            return f'⏳ Реклама WB: лимит. Следующая безопасная попытка через {_ads_retry_text(s, row)}'
        return f'⏳ лимит WB, повтор через {rate_text(s)}'
    if kind == 'pending':
        return '⏳ ожидает обновления'
    if s.startswith('ADVERTISING_UNSUPPORTED'):
        return '⚠ не загружена'
    if s.startswith('ERROR_'):
        return f'⚠ ошибка WB API {s}'
    if s.startswith('EXCEPTION:'):
        return '⚠ внутренняя ошибка обновления'
    if s in ('CONNECTION_ERROR', 'INVALID_RESPONSE', 'INVALID_JSON'):
        return f'⚠ ошибка загрузки: {s}'
    return f'⚠ {s}'


def _user_reason_text(status, row=None):
    s = str(status or '')
    normalized_status = normalize_advertising_status(s)
    if normalized_status == 'ADS_PARTIAL':
        return '⚠ Рекламные данные обновлены частично.\nЧасть кампаний пока не удалось связать с товарами WB.'
    if normalized_status == 'ADS_NO_CAMPAIGNS':
        return 'активные рекламные кампании не найдены'
    if s.startswith('ADS_COOLDOWN') or s.startswith('ADS_STEP_COOLDOWN') or s.startswith('FULLSTATS_429_SAFE_COOLDOWN'):
        return f'лимит WB API, следующая безопасная попытка через {_ads_retry_text(s, row)}'
    if s.startswith('ADS_BACKGROUND_THROTTLED'):
        return f'фоновая рекламная загрузка отложена, повтор через {rate_text(s)}'
    if s.startswith('FULLSTATS_429'):
        return f'лимит WB API, повтор через {rate_text(s)}'
    if s.startswith('SKIPPED_COOLDOWN') or s.startswith('RATE_LIMIT'):
        return f'лимит WB API, повтор через {rate_text(s)}'
    if s.startswith('ADS_BATCH_TOO_LARGE'):
        return 'список campaign_id слишком большой для одного fullstats-запроса'
    if s.startswith('ADVERTISING_UNSUPPORTED'):
        return f'ошибка рекламного API {s}'
    if s.startswith('ERROR_'):
        return f'ошибка WB API {s}'
    if s.startswith('EXCEPTION:'):
        return 'внутренняя ошибка обновления'
    if s in ('CONNECTION_ERROR', 'INVALID_RESPONSE', 'INVALID_JSON'):
        return f'ошибка загрузки {s}'
    if s == 'UNKNOWN':
        return 'данные обновляются'
    if s == 'NOT_ACTIVE':
        return 'нет активных рекламных кампаний'
    return s or '-'


def _status_summary_line(name, status, row=None):
    s = str(status or '')
    kind = _status_kind(s)
    prefix = '✅' if kind == 'success' else '⏳' if kind == 'cooldown' else '⚠'
    if kind == 'success':
        text = 'актуально'
    elif kind == 'cooldown':
        if name == 'advertising':
            if s.startswith('ADS_COOLDOWN') or s.startswith('ADS_STEP_COOLDOWN') or s.startswith('FULLSTATS_429_SAFE_COOLDOWN'):
                text = f'лимит. Следующая безопасная попытка через {_ads_retry_text(s, row)}'
            else:
                text = 'обновление отложено из-за лимита WB'
        else:
            text = 'обновление отложено из-за лимита WB'
    elif kind == 'pending':
        text = 'ожидает первого обновления'
    else:
        text = 'не загружена'
    return f'{prefix} {block_label(name)}: {text}'


