def _report_period_local_stats(user, start_date, end_date, table_name, date_column, sum_expr):
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    cur.execute(
        f"SELECT COUNT(*), MIN(substr({date_column},1,10)), MAX(substr({date_column},1,10)), COALESCE(SUM({sum_expr}),0) "
        f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ?",
        (user, str(start_date), str(end_date)),
    )
    row = cur.fetchone() or (0, None, None, 0)
    conn.close()
    return {
        'rows': int(row[0] or 0),
        'min_date': row[1],
        'max_date': row[2],
        'sum': round(float(row[3] or 0), 2),
    }


def _date_range_days(start_date, end_date):
    start_dt = datetime.strptime(str(start_date), '%Y-%m-%d')
    end_dt = datetime.strptime(str(end_date), '%Y-%m-%d')
    total_days = max(0, int((end_dt - start_dt).days)) + 1
    return [
        (start_dt + timedelta(days=offset)).strftime('%Y-%m-%d')
        for offset in range(total_days)
    ]


def _coverage_grade(percent):
    value = float(percent or 0)
    if value >= 90:
        return 'HIGH'
    if value >= 70:
        return 'MEDIUM'
    return 'LOW'


def _safe_share(part, total):
    total_value = float(total or 0)
    if abs(total_value) < 0.000001:
        return 0.0
    return round(float(part or 0) / total_value * 100, 1)


def _period_label_from_days(days, fallback='month'):
    start_date, end_date = _period_dates(days)
    if start_date and end_date:
        return f'{start_date} - {end_date}'
    return str(fallback)


def _quality_period_snapshot(user, table_name, date_column, start_date, end_date, sum_expr='0', where_sql='', extra_params=None):
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    where_tail = f' AND {where_sql}' if where_sql else ''
    params = [user, str(start_date), str(end_date)] + list(extra_params or [])
    cur.execute(
        f"SELECT COUNT(*), MIN(substr({date_column},1,10)), MAX(substr({date_column},1,10)), COALESCE(SUM({sum_expr}),0) "
        f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ?{where_tail}",
        params,
    )
    row = cur.fetchone() or (0, None, None, 0)
    cur.execute(
        f"SELECT DISTINCT substr({date_column},1,10) "
        f"FROM {table_name} WHERE telegram_id=? AND substr({date_column},1,10) BETWEEN ? AND ?{where_tail} "
        f"ORDER BY 1",
        params,
    )
    covered_days = [str(item[0]) for item in cur.fetchall() if item and item[0]]
    conn.close()
    requested_days = _date_range_days(start_date, end_date)
    covered_set = set(covered_days)
    missing_days = [day for day in requested_days if day not in covered_set]
    coverage_percent = round((len(covered_set) / len(requested_days) * 100) if requested_days else 0, 1)
    return {
        'rows': int(row[0] or 0),
        'min_date': row[1],
        'max_date': row[2],
        'sum': round(float(row[3] or 0), 2),
        'days_covered': len(covered_set),
        'requested_days': len(requested_days),
        'missing_days': missing_days,
        'coverage': coverage_percent,
        'coverage_percent': coverage_percent,
        'status': _coverage_grade(coverage_percent) if int(row[0] or 0) > 0 else 'LOW',
    }


def _finance_quality_snapshot(user, start_date, end_date):
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    params = (user, str(start_date), str(end_date))
    cur.execute(
        "SELECT COUNT(*) FROM finance_raw_audit WHERE telegram_id=? AND substr(report_date,1,10) BETWEEN ? AND ?",
        params,
    )
    raw_rows = int((cur.fetchone() or [0])[0] or 0)
    cur.execute(
        "SELECT COUNT(*) FROM expenses WHERE telegram_id=? AND substr(expense_date,1,10) BETWEEN ? AND ?",
        params,
    )
    expense_rows = int((cur.fetchone() or [0])[0] or 0)
    if raw_rows > 0:
        cur.execute(
            "SELECT COUNT(*), MIN(day_value), MAX(day_value) FROM ("
            "SELECT substr(report_date,1,10) AS day_value FROM finance_raw_audit WHERE telegram_id=? AND substr(report_date,1,10) BETWEEN ? AND ? "
            "UNION "
            "SELECT substr(expense_date,1,10) AS day_value FROM expenses WHERE telegram_id=? AND substr(expense_date,1,10) BETWEEN ? AND ?"
            ")",
            params + params,
        )
        base_row = cur.fetchone() or (0, None, None)
        cur.execute(
            "SELECT DISTINCT day_value FROM ("
            "SELECT substr(report_date,1,10) AS day_value FROM finance_raw_audit WHERE telegram_id=? AND substr(report_date,1,10) BETWEEN ? AND ? "
            "UNION "
            "SELECT substr(expense_date,1,10) AS day_value FROM expenses WHERE telegram_id=? AND substr(expense_date,1,10) BETWEEN ? AND ?"
            ") ORDER BY day_value",
            params + params,
        )
        covered_days = [str(item[0]) for item in cur.fetchall() if item and item[0]]
        source_name = 'finance_raw_audit+expenses'
    else:
        cur.execute(
            "SELECT COUNT(*), MIN(substr(expense_date,1,10)), MAX(substr(expense_date,1,10)) "
            "FROM expenses WHERE telegram_id=? AND substr(expense_date,1,10) BETWEEN ? AND ?",
            params,
        )
        base_row = cur.fetchone() or (0, None, None)
        cur.execute(
            "SELECT DISTINCT substr(expense_date,1,10) "
            "FROM expenses WHERE telegram_id=? AND substr(expense_date,1,10) BETWEEN ? AND ? ORDER BY 1",
            params,
        )
        covered_days = [str(item[0]) for item in cur.fetchall() if item and item[0]]
        source_name = 'expenses'
    conn.close()
    requested_days = _date_range_days(start_date, end_date)
    covered_set = set(covered_days)
    missing_days = [day for day in requested_days if day not in covered_set]
    coverage_percent = round((len(covered_set) / len(requested_days) * 100) if requested_days else 0, 1)
    return {
        'finance_raw_rows': raw_rows,
        'expenses_rows': expense_rows,
        'source': source_name,
        'rows': int(base_row[0] or 0),
        'min_date': base_row[1],
        'max_date': base_row[2],
        'days_covered': len(covered_set),
        'requested_days': len(requested_days),
        'missing_days': missing_days,
        'coverage': coverage_percent,
        'coverage_percent': coverage_percent,
        'status': _coverage_grade(coverage_percent) if (raw_rows > 0 or expense_rows > 0) else 'LOW',
    }


def get_data_quality_snapshot(user, start_date, end_date):
    sales = _quality_period_snapshot(user, 'sales', 'sale_date', start_date, end_date, 'price_with_disc')
    orders = _quality_period_snapshot(user, 'orders', 'order_date', start_date, end_date, 'price_with_disc')
    advertising = _quality_period_snapshot(user, 'advertising', 'advert_date', start_date, end_date, 'spend')
    finance = _finance_quality_snapshot(user, start_date, end_date)
    sync_map = get_sync_status_map(user)
    ads_sync = sync_map.get('advertising') or {}
    advertising['last_success'] = ads_sync.get('last_success')
    overall_score = round((
        float(sales.get('coverage_percent') or 0) +
        float(orders.get('coverage_percent') or 0) +
        float(advertising.get('coverage_percent') or 0) +
        float(finance.get('coverage_percent') or 0)
    ) / 4, 1)
    overall_status = _coverage_grade(overall_score)
    if overall_status == 'LOW':
        recommendation = 'Не использовать отчёт для управленческих решений без ручной сверки.'
    elif overall_status == 'MEDIUM':
        recommendation = 'Можно использовать осторожно, с учетом предупреждений.'
    else:
        recommendation = 'Данные пригодны для управленческого отчёта.'
    return {
        'period_start': start_date,
        'period_end': end_date,
        'sales': sales,
        'orders': orders,
        'advertising': advertising,
        'finance': finance,
        'overall_score': overall_score,
        'overall_status': overall_status,
        'recommendation': recommendation,
    }


def _data_quality_snapshot(user, days, context=None):
    start_date, end_date = _period_dates(days)
    context = _snapshot_context(context)
    cache_key = _context_key('data_quality_snapshot', user, start_date, end_date)
    cached = _context_snapshot_get(context, cache_key)
    if cached is not None:
        return cached
    snapshot = get_data_quality_snapshot(user, start_date, end_date)
    _context_count(context, 'data_quality_snapshot')
    return _context_snapshot_put(context, cache_key, snapshot)


def get_advertising_health_snapshot(user, start_date, end_date):
    quality_snapshot = get_data_quality_snapshot(user, start_date, end_date)
    advertising_quality = quality_snapshot.get('advertising') or {}
    duplicate_audit = advertising_duplicate_audit(user, start_date, end_date)
    cleanup_audit = advertising_cleanup_audit(user, start_date, end_date)
    sku_ads = _sku_ads_snapshot(user, (start_date, end_date))
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    try:
        cur.execute(
            """
            SELECT
                COUNT(*),
                SUM(CASE WHEN nm_id > 0 THEN 1 ELSE 0 END),
                SUM(CASE WHEN nm_id < 0 THEN 1 ELSE 0 END),
                SUM(CASE WHEN nm_id IS NULL OR nm_id = 0 THEN 1 ELSE 0 END),
                SUM(CASE WHEN TRIM(COALESCE(supplier_article, ''))!='' THEN 1 ELSE 0 END),
                ROUND(COALESCE(SUM(spend), 0), 2)
            FROM advertising
            WHERE telegram_id=? AND substr(advert_date,1,10) BETWEEN ? AND ?
            """,
            (user, str(start_date), str(end_date)),
        )
        ad_row = cur.fetchone() or (0, 0, 0, 0, 0, 0)
        cur.execute(
            """
            SELECT ROUND(COALESCE(SUM(amount), 0), 2)
            FROM expenses
            WHERE telegram_id=? AND expense_type='advertising' AND substr(expense_date,1,10) BETWEEN ? AND ?
            """,
            (user, str(start_date), str(end_date)),
        )
        expenses_advertising_total = round(float((cur.fetchone() or [0])[0] or 0), 2)
        cur.execute(
            """
            SELECT
                COUNT(DISTINCT campaign_id),
                COUNT(DISTINCT CASE
                    WHEN (nm_id IS NOT NULL AND nm_id > 0) OR TRIM(COALESCE(supplier_article, ''))!=''
                    THEN campaign_id
                    ELSE NULL
                END)
            FROM advertising
            WHERE telegram_id=? AND substr(advert_date,1,10) BETWEEN ? AND ?
            """,
            (user, str(start_date), str(end_date)),
        )
        campaign_row = cur.fetchone() or (0, 0)
    finally:
        conn.close()

    total_spend = round(float(ad_row[5] or 0), 2)
    linked_spend = round(float(sku_ads.get('linked_ads_spend') or 0), 2)
    unlinked_spend = round(float(sku_ads.get('unlinked_ads_spend') or 0), 2)
    coverage_percent = round(float(advertising_quality.get('coverage_percent') or 0), 1)
    coverage_status = str(advertising_quality.get('status') or _coverage_grade(coverage_percent))
    if total_spend > 0:
        linkability_percent = round((linked_spend / total_spend) * 100, 1)
    else:
        linkability_percent = 0.0
    negative_nm_id_rows = int(ad_row[2] or 0)
    duplicate_negative_rows = int(cleanup_audit.get('safe_to_delete_rows') or 0)
    duplicate_negative_spend = round(float(cleanup_audit.get('safe_to_delete_spend') or 0), 2)
    campaigns_total = int(campaign_row[0] or 0)
    campaigns_linked = int(campaign_row[1] or 0)
    campaigns_unlinked = max(0, campaigns_total - campaigns_linked)
    last_success = advertising_quality.get('last_success')
    stale = _freshness_label(last_success) == 'stale'
    local_period_complete = not list(advertising_quality.get('missing_days') or []) and int(ad_row[0] or 0) > 0
    spend_delta_vs_expenses = round(abs(total_spend - expenses_advertising_total), 2)
    api_total = total_spend
    local_total = expenses_advertising_total
    delta = round(local_total - api_total, 2)
    stale_critical = bool(
        stale and not (
            local_period_complete and
            linkability_percent >= 95 and
            spend_delta_vs_expenses <= 1.0
        )
    )

    if linkability_percent >= 95 and negative_nm_id_rows == 0 and duplicate_negative_spend == 0 and total_spend > 0:
        status = 'HIGH'
    elif linkability_percent < 70 or (total_spend <= 0 and expenses_advertising_total > 0):
        status = 'LOW'
    else:
        status = 'MEDIUM'

    return {
        'period_start': str(start_date),
        'period_end': str(end_date),
        'total_spend': total_spend,
        'positive_nm_id_rows': int(ad_row[1] or 0),
        'negative_nm_id_rows': negative_nm_id_rows,
        'null_nm_id_rows': int(ad_row[3] or 0),
        'supplier_article_rows': int(ad_row[4] or 0),
        'linked_spend': linked_spend,
        'unlinked_spend': unlinked_spend,
        'linkability_percent': round(linkability_percent, 1),
        'campaigns_total': campaigns_total,
        'campaigns_linked': campaigns_linked,
        'campaigns_unlinked': campaigns_unlinked,
        'coverage_percent': coverage_percent,
        'coverage_status': coverage_status,
        'api_total': api_total,
        'local_total': local_total,
        'delta': delta,
        'duplicate_negative_spend': duplicate_negative_spend,
        'duplicate_negative_rows': duplicate_negative_rows,
        'last_success': last_success,
        'stale': stale,
        'stale_critical': stale_critical,
        'local_period_complete': local_period_complete,
        'expenses_advertising_total': expenses_advertising_total,
        'spend_delta_vs_expenses': spend_delta_vs_expenses,
        'status': status,
    }


def _advertising_health_snapshot(user, days, context=None):
    start_date, end_date = _period_dates(days)
    context = _snapshot_context(context)
