def _freshness_label(last_success_text):
    dt = parse_dt(last_success_text)
    if not dt:
        return 'unknown'
    age_seconds = (datetime.now() - dt).total_seconds()
    return 'fresh' if age_seconds < 24 * 3600 else 'stale'


def _health_snapshot(user):
    ensure_sync_status_rows(user)
    sync_map = get_sync_status_map(user)
    quality_start = (datetime.now() - timedelta(days=29)).strftime('%Y-%m-%d')
    quality_end = datetime.now().strftime('%Y-%m-%d')
    quality = get_data_quality_snapshot(user, quality_start, quality_end)
    db_exists = os.path.exists(DB_NAME)
    db_status = 'OK' if db_exists else 'ERROR'
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    totals = {}
    for table_name in ('sales', 'orders', 'advertising', 'expenses', 'finance_raw_audit'):
        try:
            cur.execute(f'SELECT COUNT(*) FROM {table_name}')
            totals[table_name] = int((cur.fetchone() or [0])[0] or 0)
        except Exception:
            totals[table_name] = 0
    conn.close()
    last_updates = {}
    freshness = {}
    for block in ('sales', 'orders', 'advertising', 'finance'):
        row = sync_map.get(block) or {}
        last_updates[block] = row.get('last_success') or 'unknown'
        freshness[block] = _freshness_label(row.get('last_success'))
    cooldowns = {
        'statistics': get_api_cooldown(user, 'sales') or {},
        'advertising': get_api_cooldown(user, 'advertising') or {},
        'finance': get_api_cooldown(user, 'finance') or {},
    }
    stale_present = any(value == 'stale' for value in freshness.values())
    unknown_present = any(value == 'unknown' for value in freshness.values())
    if db_status != 'OK':
        verdict = 'needs_attention'
    elif stale_present:
        verdict = 'data_stale'
    elif unknown_present:
        verdict = 'needs_attention'
    else:
        verdict = 'system_ok'
    return {
        'bot_status': 'OK',
        'database_status': db_status,
        'database_exists': 'yes' if db_exists else 'no',
        'totals': totals,
        'last_updates': last_updates,
        'freshness': freshness,
        'cooldowns': cooldowns,
        'quality': quality,
        'verdict': verdict,
    }


def _health_text(user):
    snapshot = _health_snapshot(user)
    return '\n'.join(health_lines(snapshot))


