def _system_audit_snapshot(user):
    health = _health_snapshot(user)
    quality = health.get('quality') or {}
    quality_end = datetime.now().strftime('%Y-%m-%d')
    quality_start = (datetime.now() - timedelta(days=29)).strftime('%Y-%m-%d')
    system_migration_snapshot = _system_audit_data_source_snapshot(quality_start, quality_end, user=user)
    udl_snapshot = dict(system_migration_snapshot.get('udl_snapshot') or {})
    business_metrics_snapshot = dict(system_migration_snapshot.get('business_metrics_snapshot') or {})
    financial_engine_snapshot = dict(system_migration_snapshot.get('financial_engine_snapshot') or {})
    period_snapshot = dict(system_migration_snapshot.get('period_snapshot') or {})
    sku_registry_snapshot = dict(system_migration_snapshot.get('sku_registry_snapshot') or {})
    core_v2_status = _core_v2_status_snapshot(user=user)
    ads_health = get_advertising_health_snapshot(user, quality_start, quality_end)
    finance_health = get_finance_difference_snapshot(user, quality_start, quality_end)
    cache = _cache_capability_snapshot()
    write_safety = _write_safety_snapshot()
    udl_quality = dict((udl_snapshot.get('quality') or {}))
    udl_trust = dict((udl_snapshot.get('trust') or {}))
    udl_finance = dict((udl_snapshot.get('finance') or {}))
    udl_sources = dict((udl_snapshot.get('sources') or {}))
    quality = dict(quality or {})
    quality['overall_score'] = udl_quality.get('overall_score', quality.get('overall_score'))
    quality['overall_status'] = udl_quality.get('overall_status') or quality.get('overall_status')
    ads_health = dict(ads_health or {})
    ads_health['status'] = business_metrics_snapshot.get('advertising_health') or ads_health.get('status')
    finance_health = dict(finance_health or {})
    finance_runtime_status = udl_finance.get('status') or business_metrics_snapshot.get('official_status') or financial_engine_snapshot.get('status') or 'UNKNOWN'
    return {
        'health': health,
        'quality': quality,
        'ads_health': ads_health,
        'finance_health': finance_health,
        'cache': cache,
        'write_safety': write_safety,
        'cooldowns': health.get('cooldowns') or {},
        'last_updates': health.get('last_updates') or {},
        'udl_snapshot': udl_snapshot,
        'business_metrics_snapshot': business_metrics_snapshot,
        'financial_engine_snapshot': financial_engine_snapshot,
        'period_snapshot': period_snapshot,
        'sku_registry_snapshot': sku_registry_snapshot,
        'system_audit_data_source_snapshot': system_migration_snapshot,
        'core_v2_status': core_v2_status,
        'trust_score': udl_trust.get('overall_trust'),
        'udl_status': ((udl_sources.get('finance') or {}).get('status') or 'UNKNOWN'),
        'finance_runtime_status': finance_runtime_status,
        'verdict': health.get('verdict') or 'needs_attention',
    }


