def _director_lightweight_context(start_date, end_date, user=None, context=None):
    user = user if user is not None else 658486226
    context = _snapshot_context(context)
    period = (str(start_date), str(end_date))
    cache_key = _context_key('director_lightweight_context', user, period[0], period[1])
    cached = _context_snapshot_get(context, cache_key)
    if cached is not None:
        context['profile_mode'] = 'director_light'
        context['light_path_used'] = True
        return cached

    context['profile_mode'] = 'director_light'
    context['light_path_used'] = True
    context['full_fallback_fields'] = []
    context['saved_db_opens_estimate'] = max(int(context.get('saved_db_opens_estimate') or 0), 250)
    context['saved_queries_estimate'] = max(int(context.get('saved_queries_estimate') or 0), 9000)

    period_snapshot = _period_snapshot_for_range(start_date, end_date, context=context)
    financial_engine_snapshot = _financial_engine_snapshot(start_date, end_date, user=user, context=context)
    business_metrics_snapshot = _business_metrics_snapshot_mode(user, start_date, end_date, context=context, mode='director_light')
    unified_snapshot = _unified_data_snapshot_mode(user, start_date, end_date, context=context, mode='director_light')
    sku_registry_snapshot = _sku_registry_snapshot(user, period, context=context)
    ads_snapshot = _advertising_health_snapshot(user, period, context=context)
    sales_snapshot = _payment_reconciliation_snapshot(user, start_date, end_date, context=context)
    kpi_snapshot = build_kpi_snapshot(
        period_snapshot=period_snapshot,
        unified_data_snapshot=unified_snapshot,
        business_metrics_snapshot=business_metrics_snapshot,
        financial_engine_snapshot=financial_engine_snapshot,
        ads_snapshot=ads_snapshot,
        sales_snapshot=sales_snapshot,
        sku_registry_snapshot=sku_registry_snapshot,
    )
    cfo_snapshot = build_cfo_insights_snapshot(
        period_snapshot=period_snapshot,
        unified_data_snapshot=unified_snapshot,
        business_metrics_snapshot=business_metrics_snapshot,
        financial_engine_snapshot=financial_engine_snapshot,
        ads_snapshot=ads_snapshot,
        sku_registry_snapshot=sku_registry_snapshot,
    )
    decision_snapshot = build_decision_snapshot(
        period_snapshot=period_snapshot,
        unified_data_snapshot=unified_snapshot,
        business_metrics_snapshot=business_metrics_snapshot,
        kpi_snapshot=kpi_snapshot,
        cfo_insights_snapshot=cfo_snapshot,
        sku_registry_snapshot=sku_registry_snapshot,
    )
    advisor_snapshot = build_advisor_v2_snapshot(
        period_snapshot=period_snapshot,
        unified_data_snapshot=unified_snapshot,
        business_metrics_snapshot=business_metrics_snapshot,
        financial_engine_snapshot=financial_engine_snapshot,
        kpi_snapshot=kpi_snapshot,
        cfo_insights_snapshot=cfo_snapshot,
        decision_snapshot=decision_snapshot,
        sku_registry_snapshot=sku_registry_snapshot,
    )
    payload = {
        'period_snapshot': period_snapshot,
        'financial_engine_snapshot': financial_engine_snapshot,
        'business_metrics_snapshot': business_metrics_snapshot,
        'unified_data_snapshot': unified_snapshot,
        'sku_registry_snapshot': sku_registry_snapshot,
        'ads_snapshot': ads_snapshot,
        'sales_snapshot': sales_snapshot,
        'kpi_snapshot': kpi_snapshot,
        'cfo_snapshot': cfo_snapshot,
        'decision_snapshot': decision_snapshot,
        'advisor_snapshot': advisor_snapshot,
        'mode': 'director_light',
        'light_path_used': True,
        'full_fallback_fields': [],
    }
    return _context_snapshot_put(context, cache_key, payload)


