    start_date, end_date = _period_dates(days)
    cache_key = _context_key('director_snapshot', user, start_date, end_date)
    cached = _context_snapshot_get(context, cache_key)
    if cached is not None:
        if build_counts is not None:
            build_counts.update(_context_copy_build_counts(context))
