def _product_readiness_snapshot(user=658486226):
    audit_snapshot = _command_source_audit_snapshot()
    commands = {
        str(item.get('command') or ''): dict(item or {})
        for item in list(audit_snapshot.get('commands') or [])
    }
    director_row = commands.get('/director') or {}
    advisor_row = commands.get('/advisor v2') or {}
    financial_row = commands.get('/financial engine') or {}
    control_center_row = commands.get('/control center') or {}
    structure_row = commands.get('/structure readiness') or {}
    finance_api_status = str(
        financial_row.get('migration_readiness_status')
        or director_row.get('migration_readiness_status')
        or 'UNKNOWN'
    )
    remaining_blockers = []
    if str(financial_row.get('migration_readiness_status') or '') != 'READY':
        remaining_blockers.append('Official Financial Engine live validation waits for Finance API')
    if str(control_center_row.get('migration_readiness_status') or '') != 'READY':
        remaining_blockers.append('Control Center release surface is not fully validated yet')
    if str(structure_row.get('migration_readiness_status') or '') not in ('READY', 'ALMOST_READY'):
        remaining_blockers.append('Project structure readiness still requires release-candidate cleanup')
    return build_product_readiness_snapshot(
        finance_api_status=finance_api_status,
        director_ready=str(director_row.get('migration_readiness_status') or '') == 'READY',
        advisor_v2_ready=str(advisor_row.get('migration_readiness_status') or '') == 'READY',
        financial_engine_ready=str(financial_row.get('migration_readiness_status') or '') == 'READY',
        control_center_ready=str(control_center_row.get('migration_readiness_status') or '') == 'READY',
        structure_readiness_status=str(structure_row.get('migration_readiness_status') or 'UNKNOWN'),
        remaining_blockers=remaining_blockers,
        recommended_next_step='After Finance API is available, validate May 2026 against Gold Standard and migrate Profit Audit / Money Flow.',
    )


