def _performance_snapshot(user=658486226, days=('2026-05-01', '2026-05-31')):
    director_counts = _director_build_count_snapshot(user, days)
    snapshot = build_performance_snapshot(
        Path(__file__).resolve().parent,
        director_build_counts=director_counts,
    )
    director_perf = _command_performance_snapshot('director', user=user, days=days)
    snapshot['layer_timings'] = dict(director_perf.get('layer_timings') or {})
    snapshot['api_call_count'] = dict(director_perf.get('api_call_count') or {})
    snapshot['db_open_count'] = int(director_perf.get('db_open_count') or 0)
    snapshot['db_query_count'] = int(director_perf.get('db_query_count') or 0)
    snapshot['total_ms'] = round(float(director_perf.get('total_ms') or 0.0), 1)
    snapshot['warnings'] = list(director_perf.get('warnings') or [])
    snapshot['slowest_layers'] = list(director_perf.get('slowest_layers') or [])
    return snapshot


