def _telegram_identity_snapshot():
    return _telegram_config_identity_snapshot()


def _telegram_identity_text():
    snapshot = _telegram_identity_snapshot()
    active_refs = list(snapshot.get('active_references') or [])
    ignored_refs = list(snapshot.get('ignored_archive_references') or [])
    lines = [
        'TELEGRAM IDENTITY',
        '',
        f'Brand: {snapshot.get("brand") or "VOOGLII"}',
        '',
        'Configured bot token:',
        'present' if snapshot.get("token_present") else 'missing',
        '',
        f'Token source: {snapshot.get("config_source") or "unknown"}',
        '',
        f'Token masked: {snapshot.get("token_masked") or "not configured"}',
        '',
        f'Bot username: {snapshot.get("bot_username") or "unknown"}',
        f'Username source: {snapshot.get("bot_username_source") or "default unknown"}',
        f'Old bot references: {"found" if active_refs else "none"}',
        f'Ignored archive references: {len(ignored_refs)}',
        f'Runtime: {snapshot.get("runtime_status") or "UNKNOWN"}',
    ]
    if active_refs:
        lines.extend(['', 'Active references:'])
        for item in active_refs[:10]:
            lines.append(f'- {item.get("file")}:{item.get("line")} [{item.get("type")}]')
    if ignored_refs:
        lines.extend(['', 'Ignored archive references:'])
        for item in ignored_refs[:10]:
            lines.append(f'- {item.get("file")}:{item.get("line")} [{item.get("type")}]')
    return '\n'.join(lines)


