def _business_center_text(user=658486226, days=('2026-05-01', '2026-05-31')):
    days = _center_days(days)
    snapshot = _business_center_snapshot(user=user, days=days)
    state = dict(snapshot.get('business_state') or {})
    advertising_snapshot = dict(snapshot.get('advertising') or {})
    products_snapshot = dict(snapshot.get('products') or {})
    unified_snapshot = dict(snapshot.get('unified_finance') or {})
    finance_snapshot = snapshot.get('customer_financial_snapshot') or snapshot.get('unified_finance') or {}
    finance_confidence = str(unified_snapshot.get('finance_confidence') or 'UNKNOWN')
    recommendation = _customer_business_copy(snapshot.get('main_recommendation') or '')
    recommendation_action = _customer_business_copy(snapshot.get('main_recommendation_action') or '')
    today_actions = [_customer_business_copy(item) for item in list(snapshot.get('today_actions') or []) if str(item).strip()]
    risk_lines = [_customer_business_copy(item) for item in list(snapshot.get('risks') or []) if str(item).strip() and str(item).strip() != '-']
    advertising_line = _advertising_business_summary_line(advertising_snapshot) if advertising_snapshot else f"- Реклама: {_customer_business_status_text(state.get('ads') or 'UNKNOWN')}"
    cost_label = _customer_cost_status_label(
        unified_snapshot.get('cost_status'),
        cost_value=unified_snapshot.get('cost_price'),
        coverage_percent=products_snapshot.get('cost_coverage_percent'),
    )
    highlights = [
        f"- Продажи: {_customer_sales_status_label(state.get('sales') or 'UNKNOWN')}",
        f"- Финансы: {_customer_finance_status_label((getattr(finance_snapshot, 'finance_status', None) or (finance_snapshot.get('finance_status') if isinstance(finance_snapshot, dict) else None) or 'FINANCE_WAITING_WB'))}",
        f"- Достоверность финансов: {_customer_finance_confidence_label(finance_confidence)}",
        advertising_line,
        f"- Себестоимость: {cost_label}",
    ]
    if recommendation and recommendation != '-':
        highlights.append(f"- Главная рекомендация: {recommendation}")
    if risk_lines:
        highlights.append(f"- Главное сейчас: {risk_lines[0]}")
    if finance_confidence == 'LOW':
        highlights.append("- Не принимать решения по прибыли, пока достоверность финансового отчёта низкая.")
    actions = _customer_actions(
        recommendation_action,
        today_actions[0] if len(today_actions) > 0 else "",
        today_actions[1] if len(today_actions) > 1 else "",
        "Открыть /advisor для следующего шага.",
    )
    next_sections = ["🤖 /advisor", "💰 /finance", "📦 /products"]
    return business_screen(
        period_label=_customer_period_label(user, days),
        status_text=f"{_ux_status_icon(snapshot.get('business_health'))} Нужно проверить" if _ux_status_icon(snapshot.get('business_health')) != '🟢' else "🟢 Ситуация стабильна",
        highlights=highlights,
        actions=actions,
        next_sections=next_sections,
        validation_summary=str(snapshot.get('wb_data_status_text') or 'Данные WB: 🟡 данные обновляются'),
    )


