def _command_performance_snapshot(command='director', user=658486226, days=('2026-05-01', '2026-05-31')):
    command = str(command or 'director').strip().lower()
    context = _snapshot_context()
    start_date, end_date = _period_dates(days)
    period_label = f'{start_date}..{end_date}' if start_date and end_date else str(days)
    started = time.perf_counter()
    original_finance_list = fetch_wb_finance_reports_list
    original_finance_detail = fetch_wb_finance_report_detail
    original_wb_api_get = wb_api_get

    def _counted_finance_list(*args, **kwargs):
        _context_api_call(context, 'finance_api_calls', caller='fetch_wb_finance_reports_list')
        return original_finance_list(*args, **kwargs)

    def _counted_finance_detail(*args, **kwargs):
        _context_api_call(context, 'finance_api_calls', caller='fetch_wb_finance_report_detail')
        return original_finance_detail(*args, **kwargs)

    def _counted_wb_api_get(*args, **kwargs):
        _context_api_call(context, 'sales_api_calls', caller='wb_api_get')
        return original_wb_api_get(*args, **kwargs)

    globals()['fetch_wb_finance_reports_list'] = _counted_finance_list
    globals()['fetch_wb_finance_report_detail'] = _counted_finance_detail
    globals()['wb_api_get'] = _counted_wb_api_get
    try:
        with api_call_counter(context):
            with db_open_counter(sqlite3, context):
                with perf_timer(context['timings'], 'access_check_ms'):
                    pass
                if command in ('director', 'home'):
                    _director_text(user, days, context=context)
                elif command == 'advisor_v2':
                    _advisor_v2_text(user, days, context=context)
                elif command == 'decision':
                    _decision_text(user, days, context=context)
                elif command == 'cfo_insights':
                    _cfo_insights_text(user, days, context=context)
                elif command == 'kpi':
                    _kpi_text(user, days, context=context)
                elif command == 'udl':
                    _unified_data_text(start_date, end_date, user, context=context)
                elif command == 'business_metrics':
                    _business_metrics_text(start_date, end_date, user, context=context)
                elif command == 'dashboard':
                    _dashboard_text('performance', days, user)
                elif command == 'report_ceo':
                    _report_ceo_text('performance', days, user)
                elif command == 'system_audit':
                    _system_audit_text(user)
                else:
                    _context_warning(context, f'Unknown command for profiler: {command}')
    finally:
        globals()['fetch_wb_finance_reports_list'] = original_finance_list
        globals()['fetch_wb_finance_report_detail'] = original_finance_detail
        globals()['wb_api_get'] = original_wb_api_get
    context['timings']['total_ms'] = round((time.perf_counter() - started) * 1000.0, 1)
    return build_command_performance_snapshot(
        command=command,
        period_label=period_label,
        mode=context.get('profile_mode') or 'full',
        light_path_used=bool(context.get('light_path_used')),
        full_fallback_fields=context.get('full_fallback_fields'),
        saved_db_opens_estimate=context.get('saved_db_opens_estimate') or 0,
        saved_queries_estimate=context.get('saved_queries_estimate') or 0,
        timings=context.get('timings'),
        db_open_count=context.get('db_open_count') or 0,
        db_query_count=context.get('db_query_count') or 0,
        db_opens_by_layer=context.get('db_opens_by_layer'),
        db_queries_by_layer=context.get('db_queries_by_layer'),
        api_call_count=context.get('api_call_count'),
        api_calls_by_layer=context.get('api_calls_by_layer'),
        snapshot_build_counts=context.get('build_counts'),
        layer_timings=(context.get('timings', {}).get('layer_timings') or context.get('layer_timings')),
        warnings=context.get('warnings'),
    )


