def _percentile_ms(values, percentile=95):
    numbers = sorted(float(item or 0.0) for item in list(values or []))
    if not numbers:
        return 0.0
    if len(numbers) == 1:
        return round(numbers[0], 1)
    rank = max(0, min(len(numbers) - 1, int(round(((float(percentile) / 100.0) * len(numbers)) + 0.4999)) - 1))
    return round(numbers[rank], 1)


def run_readonly_command_stress_test(commands, iterations=10, user='test', days=('2026-05-01', '2026-05-31')):
    normalized_commands = []
    alias_map = {
        '/director current_month': 'director',
        'director': 'director',
        '/home': 'home',
        'home': 'home',
        '/advisor v2 current_month': 'advisor_v2',
        'advisor_v2': 'advisor_v2',
        'advisor': 'advisor_v2',
        '/decision current_month': 'decision',
        'decision': 'decision',
        '/cfo insights current_month': 'cfo_insights',
        'cfo_insights': 'cfo_insights',
        'cfo': 'cfo_insights',
        '/kpi current_month': 'kpi',
        'kpi': 'kpi',
        '/udl current_month': 'udl',
        'udl': 'udl',
        '/business metrics current_month': 'business_metrics',
        'business_metrics': 'business_metrics',
        'business': 'business_metrics',
    }
    for item in list(commands or []):
        key = str(item or '').strip().lower()
        if key in alias_map:
            normalized_commands.append(alias_map[key])
    normalized_commands = [item for idx, item in enumerate(normalized_commands) if item and item not in normalized_commands[:idx]]
    iterations = max(1, int(iterations or 1))
    user_id = int(user) if str(user).strip().isdigit() else 658486226

    command_latency = {}
    aggregate_duplicates = []
    aggregate_db_opens = 0
    aggregate_api_calls = {
        'finance_api_calls': 0,
        'ads_api_calls': 0,
        'sales_api_calls': 0,
    }
    warnings = []
    severe_exceptions = []

    for command_name in normalized_commands:
        durations = []
        min_ms = None
        max_ms = None
        failed_count = 0
        timeout_count = 0
        item_warnings = []
        mode = 'unknown'
        light_path_used = False
        for _ in range(iterations):
            try:
                snapshot = _command_performance_snapshot(command_name, user=user_id, days=days)
                total_ms = round(float(snapshot.get('total_ms') or 0.0), 1)
                durations.append(total_ms)
                min_ms = total_ms if min_ms is None else min(min_ms, total_ms)
                max_ms = total_ms if max_ms is None else max(max_ms, total_ms)
                mode = str(snapshot.get('mode') or mode)
                light_path_used = bool(snapshot.get('light_path_used'))
                aggregate_db_opens += int(snapshot.get('db_open_count') or 0)
                api_counts = dict(snapshot.get('api_call_count') or {})
                for api_name in aggregate_api_calls:
                    aggregate_api_calls[api_name] += int(api_counts.get(api_name) or 0)
                for dup in list(snapshot.get('duplicate_snapshot_builds') or []):
                    aggregate_duplicates.append(dict(dup or {}))
                for warning in list(snapshot.get('warnings') or []):
                    text = str(warning or '').strip()
                    if text and text not in item_warnings:
                        item_warnings.append(text)
                if total_ms > 10000.0:
                    timeout_count += 1
            except Exception as exc:
                failed_count += 1
                severe_exceptions.append(f'{command_name}: {exc}')
        avg_ms = round(sum(durations) / len(durations), 1) if durations else 0.0
        command_latency[command_name] = {
            'avg_ms': avg_ms,
            'min_ms': round(float(min_ms or 0.0), 1),
            'max_ms': round(float(max_ms or 0.0), 1),
            'p95_ms': _percentile_ms(durations, 95),
            'failed_count': failed_count,
            'timeout_count': timeout_count,
            'iterations': iterations,
            'mode': mode,
            'light_path_used': light_path_used,
            'warnings': item_warnings,
        }
    for text in severe_exceptions:
        if text not in warnings:
            warnings.append(text)
    return {
        'tested_commands': normalized_commands,
        'command_latency': command_latency,
        'db_open_count': aggregate_db_opens,
        'api_call_count': aggregate_api_calls,
        'duplicate_snapshot_builds': aggregate_duplicates,
        'warnings': warnings,
        'severe_exceptions': severe_exceptions,
    }


def assert_snapshot_context_isolation(days=('2026-05-01', '2026-05-31'), user_a=658486226, user_b=658486227):
    context_a = _snapshot_context()
    context_b = _snapshot_context()
    counts_a = {}
    counts_b = {}
    warnings = []
    try:
        _director_snapshot(user_a, days, build_counts=counts_a, context=context_a)
        _director_snapshot(user_b, days, build_counts=counts_b, context=context_b)
    except Exception as exc:
        return {
            'isolated': False,
            'context_ids': [id(context_a), id(context_b)],
            'build_counts_a': counts_a,
            'build_counts_b': counts_b,
            'warnings': [str(exc)],
        }

    isolated = True
    if id(context_a) == id(context_b):
        isolated = False
        warnings.append('request contexts share the same object id')
    if id(context_a.get('snapshots')) == id(context_b.get('snapshots')):
        isolated = False
        warnings.append('snapshot stores are shared between requests')
    if counts_a == counts_b and user_a != user_b:
        warnings.append('build count shapes are identical; verify this is expected for readonly reuse')
    if any(str(key[2] if isinstance(key, tuple) and len(key) > 2 else '') == str(user_b) for key in (context_a.get('snapshots') or {})):
        isolated = False
        warnings.append('user B cache key leaked into user A context')
    if any(str(key[2] if isinstance(key, tuple) and len(key) > 2 else '') == str(user_a) for key in (context_b.get('snapshots') or {})):
        isolated = False
        warnings.append('user A cache key leaked into user B context')
    return {
        'isolated': isolated,
        'context_ids': [id(context_a), id(context_b)],
        'build_counts_a': counts_a,
        'build_counts_b': counts_b,
        'warnings': warnings,
    }


def _memory_smoke_snapshot(user=658486226, days=('2026-05-01', '2026-05-31'), iterations=20):
    start_date, end_date = _period_dates(days)
    iterations = max(1, int(iterations or 1))
    tracemalloc.start()
    baseline_current, _ = tracemalloc.get_traced_memory()
    warnings = []
    try:
        for _ in range(iterations):
            request_context = _snapshot_context()
            _director_lightweight_context(start_date, end_date, user=user, context=request_context)
        after_current, _ = tracemalloc.get_traced_memory()
    finally:
        tracemalloc.stop()
    baseline_mb = round(float(baseline_current) / (1024.0 * 1024.0), 2)
    after_mb = round(float(after_current) / (1024.0 * 1024.0), 2)
    delta_mb = round(after_mb - baseline_mb, 2)
    if delta_mb > 25.0:
        warnings.append(f'memory delta warning: {delta_mb:.2f} MB')
    return {
        'memory_baseline_mb': baseline_mb,
        'memory_after_mb': after_mb,
        'memory_delta_mb': delta_mb,
        'warnings': warnings,
        'iterations': iterations,
    }


def _concurrency_smoke_snapshot(user=658486226, days=('2026-05-01', '2026-05-31')):
    commands = [
        ('director', lambda: _director_snapshot(user, days, context=_snapshot_context())),
        ('advisor_v2', lambda: _advisor_v2_snapshot(user, days, context=_snapshot_context())),
        ('decision', lambda: _decision_snapshot(user, days, context=_snapshot_context())),
        ('cfo_insights', lambda: _cfo_insights_snapshot(user, days, context=_snapshot_context())),
        ('kpi', lambda: _kpi_snapshot(user, days, context=_snapshot_context())),
    ]
    warnings = []
    results = []
    exceptions = []
    with ThreadPoolExecutor(max_workers=len(commands)) as executor:
        futures = [(name, executor.submit(builder)) for name, builder in commands]
        for name, future in futures:
            try:
                value = future.result(timeout=60)
                results.append({
                    'command': name,
                    'ok': isinstance(value, dict),
                })
            except Exception as exc:
                exceptions.append(f'{name}: {exc}')
    if exceptions:
        warnings.extend(exceptions)
    return {
        'status': 'OK' if not exceptions else 'ERROR',
        'results': results,
        'warnings': warnings,
        'exceptions': exceptions,
    }


def _scheduler_health_snapshot(application=None):
    runtime_app = application or _TELEGRAM_RUNTIME.get('application')
    if runtime_app is None or not getattr(runtime_app, 'job_queue', None):
        return {
            'jobs_count': 0,
            'missed_jobs_count': None,
            'last_missed_job': None,
            'long_running_jobs': [],
            'next_run_times': [],
            'scheduler_status': 'UNKNOWN',
            'recommendations': ['Attach the live Telegram application to inspect scheduler state.'],
        }
    job_queue = runtime_app.job_queue
    jobs_accessor = getattr(job_queue, 'jobs', None)
    try:
        jobs = list(jobs_accessor()) if callable(jobs_accessor) else list(jobs_accessor or [])
    except Exception:
        jobs = []
    next_run_times = []
    long_running_jobs = []
    for job in jobs:
        name = str(getattr(job, 'name', None) or 'unnamed')
        next_t = getattr(job, 'next_t', None)
        if next_t is not None:
            next_run_times.append({'name': name, 'next_run': str(next_t)})
        interval = getattr(job, 'interval', None)
        if interval is not None:
            try:
                interval_seconds = float(getattr(interval, 'total_seconds', lambda: interval)())
            except Exception:
                interval_seconds = 0.0
            if interval_seconds >= 3600.0:
                long_running_jobs.append(name)
    scheduler_status = 'OK' if jobs else 'WARNING'
    recommendations = []
    if not jobs:
        recommendations.append('Scheduler job list is empty; confirm background jobs were registered.')
    if long_running_jobs:
        recommendations.append('Review long-interval scheduler jobs if runtime timeouts continue.')
    return {
        'jobs_count': len(jobs),
        'missed_jobs_count': None,
        'last_missed_job': None,
        'long_running_jobs': long_running_jobs,
        'next_run_times': next_run_times[:10],
        'scheduler_status': scheduler_status,
        'recommendations': recommendations,
    }


def _telegram_runtime_status_snapshot(application=None):
    runtime_app = application or _TELEGRAM_RUNTIME.get('application')
    if runtime_app is None:
        return {
            'status': 'UNKNOWN',
            'job_queue_available': False,
            'recommendations': ['Run RC diagnostics inside the Telegram runtime for full scheduler visibility.'],
        }
    return {
        'status': 'OK',
        'job_queue_available': bool(getattr(runtime_app, 'job_queue', None)),
        'recommendations': [],
    }


def _rc_stability_snapshot(user=658486226, days=('2026-05-01', '2026-05-31'), application=None):
    stress = run_readonly_command_stress_test(
        [
            'director',
            'home',
            'advisor_v2',
            'decision',
            'cfo_insights',
            'kpi',
            'udl',
            'business_metrics',
        ],
        iterations=2,
        user=user,
        days=days,
    )
    isolation = assert_snapshot_context_isolation(days=days, user_a=user, user_b=user + 1)
    memory = _memory_smoke_snapshot(user=user, days=days, iterations=20)
    concurrency = _concurrency_smoke_snapshot(user=user, days=days)
    scheduler = _scheduler_health_snapshot(application=application)
    telegram_runtime = _telegram_runtime_status_snapshot(application=application)
    finance_status = _finance_api_status_snapshot(user)

    warnings = []
    warnings.extend(stress.get('warnings') or [])
    warnings.extend(memory.get('warnings') or [])
    warnings.extend(isolation.get('warnings') or [])
    warnings.extend(concurrency.get('warnings') or [])
    if str(finance_status.get('status') or '') in ('RATE_LIMIT', 'FORBIDDEN', 'UNAUTHORIZED', 'UNKNOWN'):
        warnings.append(f"finance status: {finance_status.get('status') or 'UNKNOWN'}")

    recommendations = []
    recommendations.extend(scheduler.get('recommendations') or [])
    recommendations.extend(telegram_runtime.get('recommendations') or [])
    if str(finance_status.get('status') or '') == 'RATE_LIMIT':
        recommendations.append('Finance API is cooling down; keep RC validation focused on readonly local snapshots.')

    snapshot = build_rc_stability_snapshot(
        tested_commands=stress.get('tested_commands'),
        command_latency=stress.get('command_latency'),
        memory_baseline_mb=memory.get('memory_baseline_mb'),
        memory_after_mb=memory.get('memory_after_mb'),
        memory_delta_mb=memory.get('memory_delta_mb'),
        request_context_isolated=isolation.get('isolated'),
        duplicate_snapshot_builds=stress.get('duplicate_snapshot_builds'),
        db_open_count=stress.get('db_open_count'),
        api_call_count=stress.get('api_call_count'),
        scheduler_status=scheduler,
        telegram_runtime_status=telegram_runtime,
        warnings=warnings,
        recommendations=recommendations,
        write_attempt_detected=False,
        severe_exceptions=stress.get('severe_exceptions') or concurrency.get('exceptions'),
    )
    snapshot['finance_status'] = str(finance_status.get('status') or 'UNKNOWN')
    snapshot['finance_recommended_next_check'] = str(finance_status.get('recommended_next_check') or '-')
    snapshot['context_isolation_details'] = isolation
    snapshot['memory_details'] = memory
    snapshot['concurrency_details'] = concurrency
    return snapshot


def _rc_status_text(user=658486226, days=('2026-05-01', '2026-05-31'), application=None):
    snapshot = _rc_stability_snapshot(user=user, days=days, application=application)
    lines = [rc_stability_text(snapshot), "", "Finance:", f"- status: {snapshot.get('finance_status') or 'UNKNOWN'}", f"- next check: {snapshot.get('finance_recommended_next_check') or '-'}"]
    return '\n'.join(lines)


def _advisor_cfo_readiness_snapshot(start_date, end_date, user=None):
    business_metrics_snapshot = _business_metrics_snapshot(user, start_date, end_date)
    udl_snapshot = _unified_data_snapshot(user, start_date, end_date)
    financial_engine_snapshot = _financial_engine_snapshot(start_date, end_date, user=user)
    cfo_snapshot = _cfo_insights_snapshot(user, (start_date, end_date))

    cfo_insights_available = bool(cfo_snapshot)
    business_metrics_available = bool(business_metrics_snapshot)
    udl_available = bool(udl_snapshot)
    financial_engine_status = str(
        financial_engine_snapshot.get('status')
        or business_metrics_snapshot.get('official_status')
        or ((udl_snapshot.get('finance') or {}).get('status'))
        or 'UNAVAILABLE'
    )
    official_profit_available = bool(cfo_snapshot.get('official_profit_available'))
    operational_estimate_available = bool(cfo_snapshot.get('operational_estimate_available'))
    cfo_status = str(cfo_snapshot.get('status') or 'INSUFFICIENT_DATA')
    cfo_confidence = str(cfo_snapshot.get('data_confidence') or 'LOW')

    readiness_percent = 70
    if cfo_confidence == 'MEDIUM':
        readiness_percent = 65
    elif cfo_confidence == 'LOW':
        readiness_percent = 55
    if official_profit_available:
        readiness_percent = 85
    if financial_engine_status in ('RATE_LIMIT', 'UNAVAILABLE', 'DETAIL_REQUIRED', 'API_ENDPOINT_ERROR', 'ERROR'):
        readiness_percent -= 5
    readiness_percent = max(0, min(100, readiness_percent))

    blockers = []
    if financial_engine_status in ('RATE_LIMIT', 'UNAVAILABLE', 'DETAIL_REQUIRED', 'API_ENDPOINT_ERROR', 'ERROR'):
        blockers.append('official financial profit unavailable until Finance API is restored')
    blockers.append('Advisor recommendations must not use operational profit as official profit')
    if not official_profit_available and cfo_confidence == 'LOW':
        blockers.append('CFO Insights confidence is still too low for recommendation-layer integration')

    dedup_blockers = []
    seen = set()
    for item in blockers:
        key = str(item or '').strip().lower()
        if not key or key in seen:
            continue
        seen.add(key)
        dedup_blockers.append(str(item))

    return {
        'advisor_current_sources': 'legacy operational snapshots',
        'cfo_insights_available': cfo_insights_available,
        'cfo_insights_status': cfo_status,
        'cfo_data_confidence': cfo_confidence,
        'business_metrics_available': business_metrics_available,
        'udl_available': udl_available,
        'financial_engine_status': financial_engine_status,
        'official_profit_available': official_profit_available,
        'operational_estimate_available': operational_estimate_available,
        'readiness_percent': readiness_percent,
        'blockers': dedup_blockers,
        'migration_target': 'CFO Insights explanatory layer only',
        'suggested_next_step': 'After Finance API is restored, connect CFO Insights as explanatory layer only.',
    }


