def _gold_standard_period_from_args(args, command_name='gold'):
    normalized = [str(x).strip().lower() for x in (args or []) if str(x).strip()]
    if command_name == 'gold':
        if not normalized or normalized[0] != 'standard':
            raise ValueError('invalid gold command')
        payload = normalized[1:]
    else:
        if not normalized or normalized[0] not in ('validation', 'engine'):
            raise ValueError('invalid financial command')
        payload = normalized[1:]
        if normalized[0] == 'validation' and (not payload or payload == ['may']):
            return 'may', _GOLD_STANDARD_MAY_RANGE
    if not payload or payload == ['may']:
        return 'may', _GOLD_STANDARD_MAY_RANGE
    if len(payload) == 2:
        start_date, end_date = payload
        datetime.strptime(start_date, '%Y-%m-%d')
        datetime.strptime(end_date, '%Y-%m-%d')
        if start_date > end_date:
            raise ValueError('invalid date range')
        return f'{start_date} - {end_date}', (start_date, end_date)
    raise ValueError('unsupported args')


