def _forecast_risk_label(row):
    risk = str((row or {}).get('risk_level') or 'ok')
    if risk == 'no_stock':
        return '⛔ Нет остатка'
    if risk == 'critical':
        return '🔴 Критично'
    if risk == 'high':
        return '🟠 Высокий риск'
    if risk == 'no_sales':
        return '⚪ Нет продаж'
    return '✅ Норма'


