async def _forecast_command_entry(update, context):
    args = [str(x).strip() for x in (context.args or []) if str(x).strip()]
    if len(args) >= 2:
        if not await access(update, 'report'):
            return
        try:
            period_name, days = period(args, 'month', 0)
        except ValueError:
            await update.message.reply_text(
                "Используйте:\n"
                "/forecast 2026-05-01 2026-05-31\n\n"
                "Для прогноза остатков по SKU остаются:\n"
                "/forecast week\n"
                "/forecast month\n"
                "/forecast settings"
            )
            return
        await send_long(update, _forecast_management_text(period_name, days, uid(update)))
        return
    if not await access(update, 'stocks'):
        return
    user = uid(update)
    arg = str(args[0]).lower() if args else 'week'
    if arg == 'settings':
        await update.message.reply_text(_replenishment_settings_text(user))
        return
    horizon = 30 if arg == 'month' else 7
    settings = get_replenishment_settings(user)
    rows = get_stock_forecast(user, horizon, settings['sales_window_days'])
    if not rows:
        await update.message.reply_text(
            "Прогноз остатков пока недоступен.\n"
            "Нужны загруженные остатки WB и продажи за выбранный период."
        )
        return
    snapshot = rows[0].get('snapshot_date') or '-'
    lines = [
        f"📦 Прогноз остатков ({'30 дней' if horizon == 30 else '7 дней'})",
        "",
        f"Дата snapshot: {snapshot}",
        f"Окно продаж для прогноза: {settings['sales_window_days']} дн.",
        "",
    ]
    shown = 0
    for row in rows:
        if shown >= 20:
            break
        if (row['avg_sales_per_day'] or 0) <= 0 and (row['current_stock'] or 0) > 0:
            continue
        lines.append(
            f"{_forecast_risk_label(row)} {row['article']}\n"
            f"Остаток: {row['current_stock']} | В пути: {(row['in_way_to_client'] or 0) + (row['in_way_from_client'] or 0)}\n"
            f"Продажи/день: {row['avg_sales_per_day']:.2f}\n"
            f"Хватит на: {row['days_left'] if row['days_left'] is not None else '-'} дн.\n"
            f"OOS: {row['oos_date'] or '-'}"
        )
        shown += 1
    if shown == 0:
        lines.append("Недостаточно продаж за период, чтобы построить прогноз по SKU.")
    lines.append("")
    lines.append("Прогноз основан на продажах за последние дни из настроек закупки.")
    await send_long(update, '\n\n'.join(lines))


