async def finance_audit_command(update, context, period_name, days, user):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return
    token = get_user_token(user)
    if not token:
        await update.message.reply_text('WB API РЅРµ РїРѕРґРєР»СЋС‡РµРЅ. РСЃРїРѕР»СЊР·СѓР№С‚Рµ /connect')
        return
    audit = get_finance_audit(token, days, 20)
    if audit.get('status') != 'SUCCESS':
        await update.message.reply_text(
            f'FINANCE AUDIT ({period_name})\n\n'
            f'Не удалось получить детализацию из WB API: {audit.get("status")}'
        )
        return

    lines = [f'FINANCE AUDIT ({period_name})', '']
    operations = audit.get('operations') or []
    if operations:
        lines.append('Операции WB из raw/audit:')
        lines.append('')
        for item in operations:
            lines.append(str(item.get('name') or '-'))
            lines.append(f'сумма: {money(item.get("sum_abs", 0))}')
            lines.append(f'строк: {int(item.get("rows_count") or 0)}')
            lines.append(f'знак: {item.get("sign") or "-"}')
            lines.append(f'raw_sum: {money(item.get("sum_raw", 0))}')
            if float(item.get('sum_raw') or 0) > 0 and float(item.get('sum_abs') or 0) > 0:
                lines.append('Проверьте знак: положительное значение учтено как расход через abs()')
            lines.append('')
    else:
        lines.append('Нет ненулевых полей WB Finance для блока other.')
        lines.append('')
    lines.append(f'other: {money(audit.get("total_other_abs", 0))}')
    positive_entries = audit.get('positive_as_expense') or []
    if positive_entries:
        lines.append('')
        lines.append('Положительные значения WB, попавшие в расход через abs():')
        for item in positive_entries[:10]:
            lines.append(
                f'{item["date"]} | {item["wb_field"]} | raw {money(item["raw_value"])} -> expense {money(item["stored_value"])}'
            )
    await send_long(update, '\n'.join(lines))


async def finance_rawdeduction_command(update, context, period_name, days, user):
    if not admin(update):
        await update.message.reply_text('Команда доступна только владельцу бота.')
        return
    blocked, cooldown_row = _finance_is_blocked(user)
    if blocked:
        status = str((cooldown_row or {}).get('last_status') or '')
        wait_text = rate_text(status) if status.startswith('RATE_LIMIT:') else f'{_cooldown_minutes_text(cooldown_row)} мин.'
        await update.message.reply_text(
            "Finance API сейчас на cooldown.\n"
            f"Следующая безопасная попытка через {wait_text}\n"
            "Rawdeduction не выполнен."
        )
        return
    token = get_user_token(user)
    if not token:
        await update.message.reply_text('WB API не подключен. Используйте /connect')
        return
    result = get_finance_rawdeduction(token, days, 10)
    if result.get('status') != 'SUCCESS':
        await update.message.reply_text(
            f'FINANCE RAWDEDUCTION ({period_name})\n\n'
            f'Не удалось получить raw/audit из WB API: {result.get("status")}'
        )
        return

    lines = [f'FINANCE RAWDEDUCTION ({period_name})', '']
    items = result.get('items') or []
    if not items:
        lines.append('Строки с descriptor, содержащим deduction, не найдены.')
        lines.append('')
    else:
        lines.append('Первые 10 строк raw/audit, где descriptor содержит deduction:')
        lines.append('')
        for index, item in enumerate(items, start=1):
            lines.append(f'{index}. date: {item.get("date") or "-"}')
            descriptor_pairs = item.get('descriptors') or []
            for field_name, field_value in descriptor_pairs:
                lines.append(f'{field_name}: {field_value}')
            money_fields = item.get('money_fields') or []
            if money_fields:
                lines.append('money fields:')
                for field_name, field_value in money_fields:
                    lines.append(f'{field_name}: {money(field_value)}')
            else:
                lines.append('money fields: нет')
            lines.append(f'raw value в текущем расчёте: {money(item.get("raw_value") or 0)}')
            lines.append(f'знак значения: {item.get("sign") or "0"}')
            lines.append(f'классификация текущим кодом: {item.get("classification") or "-"}')
            lines.append(f'почему: {item.get("reason") or "-"}')
            lines.append('')
    lines.extend([
        f'raw_sum по deduction: {money(result.get("raw_sum") or 0)}',
        f'expense_sum по deduction после текущей логики: {money(result.get("expense_sum") or 0)}',
        f'income_sum по deduction после текущей логики: {money(result.get("income_sum") or 0)}',
        f'количество строк: {int(result.get("rows_count") or 0)}',
    ])
    await send_long(update, '\n'.join(lines))


