async def finance_topother_command(update, context, period_name, days, user):
    if not await access(update, 'report'):
        return
    date_from, date_to = _period_dates(days or 30)
    conn = sqlite3.connect(DB_NAME)
    cur = conn.cursor()
    cur.execute(
        "SELECT expense_date, amount, COALESCE(supplier_article,'-'), COALESCE(comment,'-') "
        "FROM expenses WHERE telegram_id=? AND expense_type='other' AND substr(expense_date,1,10) BETWEEN ? AND ? "
        "ORDER BY amount DESC LIMIT 20",
        (user, date_from, date_to)
    )
    top_rows = cur.fetchall()
    cur.execute(
        "SELECT COALESCE(SUM(amount),0) FROM expenses "
        "WHERE telegram_id=? AND expense_type='other' AND substr(expense_date,1,10) BETWEEN ? AND ?",
        (user, date_from, date_to)
    )
    total_other = float(cur.fetchone()[0] or 0)
    cur.execute(
        "SELECT COALESCE(supplier_article,'-') AS article, COALESCE(SUM(amount),0) AS total_amount, COUNT(*) "
        "FROM expenses WHERE telegram_id=? AND expense_type='other' AND substr(expense_date,1,10) BETWEEN ? AND ? "
        "GROUP BY COALESCE(supplier_article,'-') ORDER BY total_amount DESC LIMIT 10",
        (user, date_from, date_to)
    )
    top_articles = cur.fetchall()
    conn.close()

    top20_sum = round(sum(float(row[1] or 0) for row in top_rows), 2)
    share = round((top20_sum / total_other * 100) if total_other else 0, 1)
    lines = [f'ТОП-20 прочих расходов ({period_name})', '']
    if top_rows:
        lines.append('Дата | Сумма | Артикул | Комментарий')
        for idx, (expense_date, amount, article, comment) in enumerate(top_rows, 1):
            lines.append(f'{idx}. {expense_date} | {money(amount)} | {article} | {comment}')
    else:
        lines.append('За выбранный период прочих расходов не найдено.')
    lines.append('')
    lines.append(f'Сумма ТОП-20: {money(top20_sum)}')
    lines.append(f'Сумма всех other: {money(total_other)}')
    lines.append(f'Доля ТОП-20: {share}%')
    lines.append('')
    lines.append('ТОП-10 артикулов по прочим расходам')
    if top_articles:
        for article, amount, count_rows in top_articles:
            lines.append(f'{article}: {money(amount)} | строк: {count_rows}')
    else:
        lines.append('Нет данных по артикулам.')
    lines.append('')
    lines.append('Основная доля прочих расходов сосредоточена в строках без артикула.')
    lines.append('Для точного источника нужен /finance raw после новой загрузки finance.')
    await send_long(update, '\n'.join(lines))


async def finance_expenses_command(update, context, period_name, days, user):
    if not await access(update, 'report'):
        return
    analysis = _finance_local_expenses_analysis(user, days)
    st = analysis['st']
    after = analysis['after']
    lines = [
        f'FINANCE EXPENSES ({period_name})',
        '',
        f'К выплате: {money(st[2])}',
        f'Прибыль до налога: {money(after["profit_before_tax"])}',
        f'Налог: {money(after["tax"])}',
        f'Чистая прибыль: {money(after["profit_after_tax"])}',
        '',
        'Расходы по категориям:',
        f'Себестоимость: {money(analysis["cost"])}',
        f'Расчётная разница WB: {money(analysis["commission"])}',
        f'Логистика: {money(analysis["logistics"])}',
        f'Хранение: {money(analysis["storage"])}',
        f'Реклама: {money(analysis["advertising"])}',
        f'Эквайринг: {money(analysis["acquiring"])}',
        f'deduction / удержания WB: {money(analysis["deduction"])}',
        f'other / прочее: {money(analysis["other_local"])}',
        'Расчётная разница WB = сумма заказов/продаж минус к выплате. Может включать комиссии, скидки, корректировки и особенности выплат WB.',
        '',
        'Финансовая сверка:',
        f'Видимые расходы: {money(analysis["visible_expenses"])}',
        f'Расчётная прибыль по видимым расходам: {money(analysis["calculated_profit_before_tax"])}',
        f'Фактическая прибыль до налога: {money(after["profit_before_tax"])}',
        f'Нерасшифрованные расходы WB: {money(analysis["hidden_difference"])}',
        '',
        'ТОП-5 самых крупных удержаний WB:',
    ]
    if analysis['top_deductions']:
        for item in analysis['top_deductions']:
            lines.append(
                f'{item["name"]}: {money(item["sum"])} | строк: {item["rows"]} | доля от всех расходов: {item["share"]}%'
            )
    else:
        lines.append('Нет локальных raw-данных по deduction для выбранного периода.')

    warnings = []
    if float(analysis['deduction'] or 0) > 0:
        warnings.append('Проверьте deduction: крупное удержание WB')
    if abs(float(analysis['hidden_difference'] or 0)) > 5000:
        warnings.append('Есть существенная нерасшифрованная разница')
    payout = float(st[2] or 0)
    advertising = float(analysis['advertising'] or 0)
    if payout > 0 and advertising / payout > 0.10:
        warnings.append('Реклама выше 10% от выплаты')
    if warnings:
        lines.extend(['', 'Предупреждения:'])
        lines.extend(warnings)

    blocked, _ = _finance_is_blocked(user)
    if not analysis['detailed_available'] and blocked:
        lines.extend([
            '',
            'Детальная raw-расшифровка WB временно недоступна из-за лимита Finance API.',
        ])
    elif not analysis['detailed_available']:
        lines.extend([
            '',
            'Детальная raw-расшифровка WB локально недоступна. Она появится после следующей успешной загрузки Finance.',
        ])
    await send_long(update, '\n'.join(lines))


