async def sales_audit_command(update, context, start_date, end_date, user, targets):
    token = get_user_token(user)
    if not token:
        await update.message.reply_text('WB API не подключен. Используйте /connect')
        return

    sales_api = inspect_sales_api(token, start_date, end_date, user)
    orders_api = inspect_orders_api(token, start_date, end_date, user)
    dry_run = estimate_sales_orders_backfill_impact(
        user,
        sales_api.get('filtered_rows') or [],
        orders_api.get('filtered_rows') or [],
    )
    sales_local = _sales_local_source_snapshot(user, start_date, end_date, 'sales', 'sale_id', 'sale_date')
    orders_local = _sales_local_source_snapshot(user, start_date, end_date, 'orders', 'order_id', 'order_date')
    verdicts = _sales_verdict_lines(
        {
            'sales_api': sales_api,
            'orders_api': orders_api,
            'sales_local': sales_local,
            'orders_local': orders_local,
        },
        targets,
    )

    def _append_source(lines, title, api_data, local_data, db_mode_label):
        params = api_data.get('params') or {}
        lines.extend([
            title,
            f'API endpoint: {api_data.get("api") or "-"}',
            'используемые параметры:',
            f'dateFrom: {params.get("dateFrom")}',
            f'flag: {params.get("flag")}',
            f'lastChangeDate: {params.get("lastChangeDate")}',
            f'limit: {params.get("limit")}',
            f'next: {params.get("next")}',
            f'используется ли пагинация: {api_data.get("pagination_used")}',
            f'pages_loaded: {api_data.get("pages_loaded")}',
            f'WB rows before DB write: {api_data.get("received_rows")}',
            f'WB rows in requested range: {api_data.get("rows_in_range")}',
            f'computed unique key strategy: {api_data.get("identity_strategy")}',
            f'sample primary key: {api_data.get("sample_primary_key") or "-"}',
            f'computed key collisions: {api_data.get("duplicate_computed_keys")}',
            f'тип сохранения: {db_mode_label}',
            '',
            'локальная статистика:',
            f'rows: {local_data.get("rows")}',
            f'unique ids: {local_data.get("unique_ids")}',
            f'unique srid: {local_data.get("unique_srid") if local_data.get("unique_srid") is not None else "column missing"}',
            f'sum: {money(local_data.get("sum") or 0)}',
            f'min/max date: {local_data.get("min_date") or "-"} / {local_data.get("max_date") or "-"}',
            f'min/max lastChangeDate: {(local_data.get("last_change") or {}).get("min") or "-"} / {(local_data.get("last_change") or {}).get("max") or "-"}',
            'группировка по дням:',
        ])
        if local_data.get('day_groups'):
            for item in local_data['day_groups'][:40]:
                lines.append(f'{item["date"]}: rows {item["count"]} | sum {money(item["sum"])}')
        else:
            lines.append('нет данных')
        lines.append('группировка по supplierArticle:')
        if local_data.get('article_groups'):
            for item in local_data['article_groups'][:20]:
                lines.append(f'{item["supplier_article"]}: rows {item["count"]} | sum {money(item["sum"])}')
        else:
            lines.append('нет данных')
        lines.append('')

    lines = [
        f'SALES AUDIT {start_date} - {end_date}',
        '',
        '=== API STATUS ===',
        f'sales status: {sales_api.get("status")}',
        f'orders status: {orders_api.get("status")}',
        '',
        '=== DRY RUN SAVE STATS ===',
        f'sales inserted: {int((dry_run.get("sales") or {}).get("inserted") or 0)}',
        f'sales updated: {int((dry_run.get("sales") or {}).get("updated") or 0)}',
        f'sales skipped: {int((dry_run.get("sales") or {}).get("skipped") or 0)}',
        '',
        f'orders inserted: {int((dry_run.get("orders") or {}).get("inserted") or 0)}',
        f'orders updated: {int((dry_run.get("orders") or {}).get("updated") or 0)}',
        f'orders skipped: {int((dry_run.get("orders") or {}).get("skipped") or 0)}',
        '',
        '=== SALES SOURCE ===',
    ]
    _append_source(lines, '', sales_api, sales_local, 'safe upsert')
    lines.append('=== ORDERS SOURCE ===')
    _append_source(lines, '', orders_api, orders_local, 'safe upsert')

    lines.append('=== MANUAL TARGET ===')
    if targets:
        lines.append(f'target_orders_count: {targets.get("target_orders_count", "-")}')
        lines.append(f'target_orders_sum: {money(targets.get("target_orders_sum") or 0)}' if 'target_orders_sum' in targets else 'target_orders_sum: -')
        lines.append(f'target_sales_count: {targets.get("target_sales_count", "-")}')
        lines.append(f'target_sales_sum: {money(targets.get("target_sales_sum") or 0)}' if 'target_sales_sum' in targets else 'target_sales_sum: -')
    else:
        lines.append('manual target не передан')
    lines.append('')

    lines.append('=== COMPARE LOCAL VS TARGET ===')
    if targets:
        if 'target_orders_count' in targets:
            lines.append(f'orders delta count: {int(orders_local.get("rows") or 0) - int(targets["target_orders_count"])}')
        if 'target_orders_sum' in targets:
            lines.append(f'orders delta amount: {money(float(orders_local.get("sum") or 0) - float(targets["target_orders_sum"] or 0))}')
        if 'target_sales_count' in targets:
            lines.append(f'sales delta count: {int(sales_local.get("rows") or 0) - int(targets["target_sales_count"])}')
        if 'target_sales_sum' in targets:
            lines.append(f'sales delta amount: {money(float(sales_local.get("sum") or 0) - float(targets["target_sales_sum"] or 0))}')
    else:
        lines.append('нет manual target для сравнения')
    lines.append('')

    lines.append('=== VERDICT ===')
    for item in verdicts:
        lines.append(f'- {item}')
    await send_long(update, '\n'.join(lines).strip())


