    rows, _ = _sku_analytics_rows(user, days)
    if not rows:
        await update.message.reply_text(f'Нет данных по SKU за период {period_name}.')
        return
    worst = sorted(rows, key=lambda item: (float(item.get('profit_per_unit') or 0), float(item.get('contribution_profit') or 0)))[:20]
    best = sorted(rows, key=lambda item: (float(item.get('profit_per_unit') or 0), float(item.get('contribution_profit') or 0)), reverse=True)[:20]
    lines = [f'SKU OPTIMIZE ({period_name})', '', '20 самых убыточных', '']
    for index, row in enumerate(worst, start=1):
        verdict = ', '.join(row.get('verdicts') or []) or '-'
        lines.extend([
            f'{index}. {row["article"]}',
            f'продажи: {row["sales"]} | выручка: {money(row["revenue"])} | средняя цена: {money(row["avg_price"])}',
            f'себестоимость/шт: {money(row["cost_u"])} | логистика/шт: {money(row["logistics_u"])} | реклама/шт: {money(row["advertising_u"])} | хранение/шт: {money(row["storage_u"])}',
            f'WB difference/шт: {money(row["wb_diff_u"])} | прибыль/шт: {money(row["profit_per_unit"])} | маржа: {row["margin_percent"]:.1f}%',
            f'безубыточная цена: {money(row["break_even_price"])} | цена 10%: {money(row["target_price_10"])} | цена 20%: {money(row["target_price_20"])} | запас цены: {money(row["price_buffer"])}',
            f'вердикт: {verdict}',
            '',
        ])
    lines.extend(['20 самых прибыльных', ''])
    for index, row in enumerate(best, start=1):
        verdict = ', '.join(row.get('verdicts') or []) or '-'
        lines.extend([
            f'{index}. {row["article"]}',
            f'продажи: {row["sales"]} | выручка: {money(row["revenue"])} | средняя цена: {money(row["avg_price"])}',
            f'себестоимость/шт: {money(row["cost_u"])} | логистика/шт: {money(row["logistics_u"])} | реклама/шт: {money(row["advertising_u"])} | хранение/шт: {money(row["storage_u"])}',
            f'WB difference/шт: {money(row["wb_diff_u"])} | прибыль/шт: {money(row["profit_per_unit"])} | маржа: {row["margin_percent"]:.1f}%',
            f'безубыточная цена: {money(row["break_even_price"])} | цена 10%: {money(row["target_price_10"])} | цена 20%: {money(row["target_price_20"])} | запас цены: {money(row["price_buffer"])}',
            f'вердикт: {verdict}',
            '',
        ])
    await send_long(update, '\n'.join(lines).strip())


