async def _finance_command_entry(update, context):
    if _raw_command_name(update) not in ('finance',):
        return
    started = time.monotonic()
    user = uid(update)
    raw_text = ''
    if getattr(update, 'message', None):
        raw_text = getattr(update.message, 'text', '') or ''
    args = [str(x).strip().lower() for x in (context.args or []) if str(x).strip()]
    mode = args[0] if args else 'help'
    subcommand = mode
    logger.info('FINANCE COMMAND START user=%s text=%s', user, sanitize_log_value(raw_text))
    logger.info('FINANCE PROMOTIONAUDIT DEBUG args=%s subcommand=%s', args, mode)

    try:
        center_period = _customer_command_period(user, args, 'current_month')
        if not args or center_period is not None:
            _, days = center_period or _customer_command_period(user, ['current_month'], 'current_month')
            await send_long(update, _finance_center_text(user, days))
            return

        if mode == 'validate':
            validate_started = time.monotonic()
            logger.info('FINANCE VALIDATE START user=%s text=%s', user, sanitize_log_value(raw_text))
            if not await access(update, 'report'):
                return
            try:
                period_name, days = period(args, 'month', 1)
            except ValueError:
                await update.message.reply_text(_period_help('finance'))
                return
            st = get_profit_stats(days, user)
            after = get_profit_stats_after_tax(days, user)
            roi = get_roi(days, user)
            lines = [
                f'FINANCE VALIDATE ({period_name})',
                '',
                f'К выплате: {money(st[2])}',
                f'- Себестоимость: {money(st[3])}',
                f'- Логистика: {money(st[4])}',
                f'- Хранение: {money(st[6])}',
                f'- Реклама: {money(st[5])}',
                f'- Прочие расходы: {money(st[7])}',
                f'= Прибыль до налога: {money(after["profit_before_tax"])}',
                f'- Налог: {money(after["tax"])}',
                f'= Чистая прибыль после налога: {money(after["profit_after_tax"])}',
                '',
                f'Маржа до налога: {st[11]:.1f}%',
                f'Маржа после налога: {after["margin_after_tax"]:.1f}%',
                f'ROI: {roi:.1f}%' if roi is not None else 'ROI: не рассчитан',
                f'Налоговый режим: {format_tax_settings_label(user)}',
            ]
            if after.get('tax_warning'):
                lines.extend(['', str(after['tax_warning'])])
            tax_notes = after.get('tax_notes') or []
            if tax_notes:
                lines.extend([''] + [str(x) for x in tax_notes])
            await send_long(update, '\n'.join(lines))
            logger.info('FINANCE VALIDATE END user=%s duration=%s', user, round(time.monotonic() - validate_started, 2))
            return

        if mode == 'explain':
            try:
                period_name, days = period(args, 'month', 1)
            except ValueError:
                await update.message.reply_text(_period_help('finance'))
                return
            await finance_explain_command(update, context, period_name, days, user)
            return

        if mode == 'mgmt':
            if len(args) > 1 and str(args[1]).strip().lower() == 'explain':
                try:
                    period_name, days = period(args, 'month', 2)
                except ValueError:
                    await update.message.reply_text(_period_help('finance'))
                    return
                await finance_mgmt_explain_command(update, context, period_name, days, user)
                return
            try:
                period_name, days = period(args, 'month', 1)
            except ValueError:
                await update.message.reply_text(_period_help('finance'))
                return
            await finance_mgmt_command(update, context, period_name, days, user)
            return

        if mode == 'wbdelta':
            try:
                period_name, days = period(args, 'month', 1)
            except ValueError:
                await update.message.reply_text(_period_help('finance wbdelta'))
                return
            await send_long(update, _finance_wbdelta_text(period_name, days, user))
            return

        if mode == 'reconcile':
            try:
                period_name, days = period(args, 'month', 1)
            except ValueError:
                await update.message.reply_text(_period_help('finance'))
                return
            await finance_reconcile_command(update, context, period_name, days, user)
            return

        if mode == 'api':
            api_mode = str(args[1]).strip().lower() if len(args) > 1 else ''
            if api_mode == 'diagnose':
                if len(args) > 2:
                    await update.message.reply_text('Используйте:\n/finance api diagnose')
                    return
                await send_long(update, _finance_api_diagnose_text(user))
                return
            if api_mode != 'status':
                await update.message.reply_text('Используйте:\n/finance api status\nили:\n/finance api diagnose')
                return
            force = len(args) > 2 and str(args[2]).strip().lower() == 'force'
            if len(args) > 2 and not force:
                await update.message.reply_text('Используйте:\n/finance api status\nили:\n/finance api status force')
                return
            await send_long(update, _finance_api_status_text(user, force=force))
            return

        if mode == 'doublecount':
            try:
                period_name, days = period(args, 'month', 1)
            except ValueError:
                await update.message.reply_text(_period_help('finance'))
                return
            await finance_doublecount_command(update, context, period_name, days, user)
            return

        if mode == 'raw':
            raw_rrd_id = args[1] if len(args) > 1 else ''
            await finance_raw_command(update, context, user, raw_rrd_id)
            return

        if mode == 'trace':
            trace_date = args[1] if len(args) > 1 else ''
            await finance_trace_command(update, context, user, trace_date)
            return

        if mode == 'readiness':
            await finance_readiness_command(update, context, user)
            return

        if mode == 'auditcheck':
            await finance_auditcheck_command(update, context, user)
            return

        if mode == 'ratelimit':
            await finance_ratelimit_command(update, context, user)
            return

        try:
            period_name, days = period(args, 'month', 1)
        except ValueError:
            await update.message.reply_text(_period_help('finance'))
            return
        raw_audit_days = days
        local_days = days or 30

        if mode == 'deduction':
            await finance_deduction_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'deductionstats':
            await finance_deductionstats_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'biggestdeductions':
            await finance_biggestdeductions_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'rawdeduction':
            await finance_rawdeduction_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'promotionaudit':
            await update.message.reply_text(
                f'FINANCE PROMOTIONAUDIT DEBUG\nargs={args}\nsubcommand={mode}'
            )
            await finance_promotionaudit_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'promotiondetail':
            await finance_promotiondetail_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'promotionraw':
            await finance_promotionraw_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'commissionaudit':
            await update.message.reply_text(
                f'FINANCE COMMISSIONAUDIT DEBUG\nargs={args}\nsubcommand={subcommand}'
            )
            await finance_commissionaudit_command(update, context, period_name, raw_audit_days, user)
            await update.message.reply_text('FINANCE COMMISSIONAUDIT ROUTE OK')
            return

        if mode == 'differenceaudit':
            await finance_differenceaudit_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'catalog':
            await send_long(update, _finance_operation_catalog_text(period_name, raw_audit_days, user))
            return

        if mode == 'breakdown':
            await finance_breakdown_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'sku_losses':
            await finance_sku_losses_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'expenses':
            await finance_expenses_command(update, context, period_name, raw_audit_days, user)
            return

        if mode == 'debug':
            if not admin(update):
                await update.message.reply_text('Команда доступна только владельцу бота.')
                return
            st = get_profit_stats(local_days, user)
            after = get_profit_stats_after_tax(local_days, user)
            lines = [
                f'FINANCE DEBUG ({period_name})',
                f'payout: {money(st[2])}',
                f'commission: {money(st[1])}',
                f'cost: {money(st[3])}',
                f'logistics: {money(st[4])}',
                f'storage: {money(st[6])}',
                f'advertising: {money(st[5])}',
                f'other: {money(st[7])}',
                f'profit_before_tax: {money(after["profit_before_tax"])}',
            ]
            await update.message.reply_text('\n'.join(lines))
            return

        if mode == 'topother':
            await finance_topother_command(update, context, period_name, days, user)
            return

        known_modes = {
            'validate', 'explain', 'mgmt', 'wbdelta', 'reconcile', 'doublecount', 'raw', 'trace', 'readiness', 'auditcheck', 'ratelimit',
            'deduction', 'deductionstats', 'biggestdeductions', 'rawdeduction',
            'promotionaudit', 'promotiondetail', 'promotionraw', 'commissionaudit', 'differenceaudit', 'catalog', 'breakdown', 'sku_losses', 'expenses', 'debug', 'topother', 'other', 'audit',
        }
        if mode not in known_modes:
            await update.message.reply_text(_finance_help_text())
            return

        if mode == 'other' and not await access(update, 'report'):
            return

        blocked, cooldown_row = _finance_is_blocked(user)
        if blocked:
            await update.message.reply_text(_finance_rate_limited_message(cooldown_row))
            return

        token = get_user_token(user)
        if not token:
            await update.message.reply_text('WB API РЅРµ РїРѕРґРєР»СЋС‡РµРЅ. РСЃРїРѕР»СЊР·СѓР№С‚Рµ /connect')
            return

        if mode == 'audit':
            if not admin(update):
                await update.message.reply_text('Команда доступна только владельцу бота.')
                return
            if not acquire_sync_lock(user, 'finance_audit', 30):
                await update.message.reply_text('Аудит финансов уже выполняется. Подождите завершения.')
                return
            try:
                await finance_audit_command(update, context, period_name, days, user)
            finally:
                release_sync_lock(user, 'finance_audit')
            return

        breakdown = get_finance_breakdown(token, days)
        st = get_profit_stats(days, user)
        if breakdown.get('status') != 'SUCCESS':
            await update.message.reply_text(
                f'Прочие расходы WB ({period_name})\n\n'
                f'Не удалось получить детализацию из WB API: {breakdown.get("status")}\n'
                f'По текущим данным в БД: {money(st[7])}'
            )
            return
        categories = breakdown.get('categories') or {}
        lines = [f'Прочие расходы WB ({period_name})', '']
        if categories:
            for name, amount in sorted(categories.items(), key=lambda x: x[1], reverse=True):
                lines.append(f'{name}: {money(amount)}')
            lines.append('')
            lines.append(f'РС‚РѕРіРѕ: {money(sum(categories.values()))}')
        else:
            lines.append('В WB API нет ненулевых полей для блока other.')
            lines.append(f'По текущим данным в БД: {money(st[7])}')
        await send_long(update, '\n'.join(lines))
    except Exception:
        logger.exception('finance_command failed')
        await update.message.reply_text(
            'Ошибка выполнения команды.\n'
            'Подробности записаны в лог сервера.'
        )
    finally:
        duration = round(time.monotonic() - started, 2)
        logger.info('FINANCE COMMAND END mode=%s duration=%s', mode, duration)


